 for <var>hide</var> and/or <var>show</var>.\";'),('en','messages:apierror-revisions-badid','s:53:\"en:No revision was found for parameter <var>$1</var>.\";'),('en','messages:apierror-revisions-norevids','s:247:\"en:The <var>revids</var> parameter may not be used with the list options (<var>$1limit</var>, <var>$1startid</var>, <var>$1endid</var>, <kbd>$1dir=newer</kbd>, <var>$1user</var>, <var>$1excludeuser</var>, <var>$1start</var>, and <var>$1end</var>).\";'),('en','messages:apierror-revisions-singlepage','s:316:\"en:<var>titles</var>, <var>pageids</var> or a generator was used to supply multiple pages, but the <var>$1limit</var>, <var>$1startid</var>, <var>$1endid</var>, <kbd>$1dir=newer</kbd>, <var>$1user</var>, <var>$1excludeuser</var>, <var>$1start</var>, and <var>$1end</var> parameters may only be used on a single page.\";'),('en','messages:apierror-revwrongpage','s:31:\"en:r$1 is not a revision of $2.\";'),('en','messages:apierror-searchdisabled','s:36:\"en:<var>$1</var> search is disabled.\";'),('en','messages:apierror-sectionreplacefailed','s:35:\"en:Could not merge updated section.\";'),('en','messages:apierror-sectionsnotsupported','s:51:\"en:Sections are not supported for content model $1.\";'),('en','messages:apierror-sectionsnotsupported-what','s:36:\"en:Sections are not supported by $1.\";'),('en','messages:apierror-show','s:71:\"en:Incorrect parameter - mutually exclusive values may not be supplied.\";'),('en','messages:apierror-siteinfo-includealldenied','s:76:\"en:Cannot view all servers\' info unless <var>$wgShowHostnames</var> is true.\";'),('en','messages:apierror-sizediffdisabled','s:45:\"en:Size difference is disabled in Miser Mode.\";'),('en','messages:apierror-spamdetected','s:79:\"en:Your edit was refused because it contained a spam fragment: <code>$1</code>.\";'),('en','messages:apierror-specialpage-cantexecute','s:70:\"en:You don\'t have permission to view the results of this special page.\";'),('en','messages:apierror-stashedfilenotfound','s:44:\"en:Could not find the file in the stash: $1.\";'),('en','messages:apierror-stashedit-missingtext','s:45:\"en:No stashed text found with the given hash.\";'),('en','messages:apierror-stashexception','s:5:\"en:$1\";'),('en','messages:apierror-stashfailed-complete','s:65:\"en:Chunked upload is already completed, check status for details.\";'),('en','messages:apierror-stashfailed-nosession','s:43:\"en:No chunked upload session with this key.\";'),('en','messages:apierror-stashfilestorage','s:42:\"en:Could not store upload in the stash: $1\";'),('en','messages:apierror-stashinvalidfile','s:24:\"en:Invalid stashed file.\";'),('en','messages:apierror-stashnosuchfilekey','s:23:\"en:No such filekey: $1.\";'),('en','messages:apierror-stashpathinvalid','s:56:\"en:File key of improper format or otherwise invalid: $1.\";'),('en','messages:apierror-stashwrongowner','s:18:\"en:Wrong owner: $1\";'),('en','messages:apierror-stashzerolength','s:68:\"en:File is of zero length, and could not be stored in the stash: $1.\";'),('en','messages:apierror-systemblocked','s:52:\"en:You have been blocked automatically by MediaWiki.\";'),('en','messages:apierror-templateexpansion-notwikitext','s:87:\"en:Template expansion is only supported for wikitext content. $1 uses content model $2.\";'),('en','messages:apierror-tempuseracquirefailed','s:50:\"en:Unable to acquire a temporary account username.\";'),('en','messages:apierror-tempuserdisabled','s:47:\"en:Temporary user account creation is disabled.\";'),('en','messages:apierror-toofewexpiries','s:105:\"en:$1 expiry {{PLURAL:$1|timestamp was|timestamps were}} provided where $2 {{PLURAL:$2|was|were}} needed.\";'),('en','messages:apierror-toomanyvalues','s:73:\"en:Too many values supplied for parameter <var>$1</var>. The limit is $2.\";'),('en','messages:apierror-unknownaction','s:58:\"en:The action specified, <kbd>$1</kbd>, is not recognized.\";'),('en','messages:apierror-unknownerror','s:23:\"en:Unknown error: \"$1\".\";'),('en','messages:apierror-unknownerror-editpage','s:30:\"en:Unknown EditPage error: $1.\";'),('en','messages:apierror-unknownerror-nocode','s:17:\"en:Unknown error.\";'),('en','messages:apierror-unknownformat','s:28:\"en:Unrecognized format \"$1\".\";'),('en','messages:apierror-unrecognizedparams','s:55:\"en:Unrecognized {{PLURAL:$2|parameter|parameters}}: $1.\";'),('en','messages:apierror-unrecognizedvalue','s:54:\"en:Unrecognized value for parameter <var>$1</var>: $2.\";'),('en','messages:apierror-unsupportedrepo','s:62:\"en:Local file repository does not support querying all images.\";'),('en','messages:apierror-upload-filekeyneeded','s:71:\"en:Must supply a <var>filekey</var> when <var>offset</var> is non-zero.\";'),('en','messages:apierror-upload-filekeynotallowed','s:66:\"en:Cannot supply a <var>filekey</var> when <var>offset</var> is 0.\";'),('en','messages:apierror-upload-inprogress','s:41:\"en:Upload from stash already in progress.\";'),('en','messages:apierror-upload-missingresult','s:28:\"en:No result in status data.\";'),('en','messages:apierror-urlparamnormal','s:47:\"en:Could not normalize image parameters for $1.\";'),('en','messages:apierror-writeapidenied','s:56:\"en:You\'re not allowed to edit this wiki through the API.\";'),('en','messages:apihelp','s:11:\"en:API help\";'),('en','messages:apihelp-acquiretempusername-extended-description','s:249:\"en:If the user later performs an action that results in temp account creation, the stashed username will be used for their account. It may also be used in previews. However, the account is not created yet, and the name is not visible to other users.\";'),('en','messages:apihelp-acquiretempusername-summary','s:204:\"en:Acquire a temporary user username and stash it in the current session, if temp account creation is enabled and the current user is logged out. If a name has already been stashed, returns the same name.\";'),('en','messages:apihelp-block-example-ip-simple','s:70:\"en:Block IP address <kbd>192.0.2.5</kbd> for three days with a reason.\";'),('en','messages:apihelp-block-example-user-complex','s:111:\"en:Block user <kbd>Vandal</kbd> indefinitely with a reason, and prevent new account creation and email sending.\";'),('en','messages:apihelp-block-param-actionrestrictions','s:106:\"en:List of actions to block the user from performing. Only applies when <var>partial</var> is set to true.\";'),('en','messages:apihelp-block-param-allowusertalk','s:145:\"en:Allow the user to edit their own talk page (depends on <var>[[mw:Special:MyLanguage/Manual:$wgBlockAllowsUTEdit|$wgBlockAllowsUTEdit]]</var>).\";'),('en','messages:apihelp-block-param-anononly','s:116:\"en:Block anonymous users only (i.e. disable anonymous edits for this IP address, including temporary account edits).\";'),('en','messages:apihelp-block-param-autoblock','s:104:\"en:Automatically block the last used IP address, and any subsequent IP addresses they try to login from.\";'),('en','messages:apihelp-block-param-expiry','s:236:\"en:Expiry time. May be relative (e.g. <kbd>5 months</kbd> or <kbd>2 weeks</kbd>) or absolute (e.g. <kbd>2014-09-18T12:34:56Z</kbd>). If set to <kbd>infinite</kbd>, <kbd>indefinite</kbd>, or <kbd>never</kbd>, the block will never expire.\";'),('en','messages:apihelp-block-param-hidename','s:84:\"en:Hide the username from the block log. (Requires the <code>hideuser</code> right).\";'),('en','messages:apihelp-block-param-id','s:161:\"en:ID of the block to modify (obtained through <kbd>list=blocks</kbd>). Cannot be used together with <var>user</var>, <var>reblock</var>, or <var>newblock</var>.\";'),('en','messages:apihelp-block-param-namespacerestrictions','s:109:\"en:List of namespace IDs to block the user from editing. Only applies when <var>partial</var> is set to true.\";'),('en','messages:apihelp-block-param-newblock','s:123:\"en:Add another block even if the user is already blocked. Cannot be used together with <var>id</var> or <var>reblock</var>.\";'),('en','messages:apihelp-block-param-nocreate','s:28:\"en:Prevent account creation.\";'),('en','messages:apihelp-block-param-noemail','s:98:\"en:Prevent user from sending email through the wiki. (Requires the <code>blockemail</code> right).\";'),('en','messages:apihelp-block-param-pagerestrictions','s:102:\"en:List of titles to block the user from editing. Only applies when <var>partial</var> is set to true.\";'),('en','messages:apihelp-block-param-partial','s:76:\"en:Block user from specific pages or namespaces rather than the entire site.\";'),('en','messages:apihelp-block-param-reason','s:20:\"en:Reason for block.\";'),('en','messages:apihelp-block-param-reblock','s:282:\"en:If the user is already blocked by a single block, overwrite the existing block. If the user is blocked more than once, this will failâuse the <var>id</var> parameter instead to specify which block to overwrite. Cannot be used together with <var>id</var> or <var>newblock</var>.\";'),('en','messages:apihelp-block-param-tags','s:54:\"en:Change tags to apply to the entry in the block log.\";'),('en','messages:apihelp-block-param-user','s:63:\"en:User to block. Cannot be used together with <var>$1id</var>.\";'),('en','messages:apihelp-block-param-userid','s:52:\"en:Specify <kbd>$1user=#<var>ID</var></kbd> instead.\";'),('en','messages:apihelp-block-param-watchlistexpiry','s:98:\"en:Watchlist expiry timestamp. Omit this parameter entirely to leave the current expiry unchanged.\";'),('en','messages:apihelp-block-param-watchuser','s:56:\"en:Watch the user\'s or IP address\'s user and talk pages.\";'),('en','messages:apihelp-block-summary','s:16:\"en:Block a user.\";'),('en','messages:apihelp-changeauthenticationdata-example-password','s:79:\"en:Attempt to change the current user\'s password to <kbd>ExamplePassword</kbd>.\";'),('en','messages:apihelp-changeauthenticationdata-summary','s:51:\"en:Change authentication data for the current user.\";'),('en','messages:apihelp-changecontentmodel-example','s:67:\"en:Change the main page to have the <code>text</code> content model\";'),('en','messages:apihelp-changecontentmodel-param-bot','s:49:\"en:Mark the content model change with a bot flag.\";'),('en','messages:apihelp-changecontentmodel-param-model','s:36:\"en:Content model of the new content.\";'),('en','messages:apihelp-changecontentmodel-param-pageid','s:102:\"en:Page ID of the page to change the contentmodel of. Cannot be used together with <var>$1title</var>.\";'),('en','messages:apihelp-changecontentmodel-param-summary','s:36:\"en:Edit summary and log entry reason\";'),('en','messages:apihelp-changecontentmodel-param-tags','s:50:\"en:Change tags to apply to the log entry and edit.\";'),('en','messages:apihelp-changecontentmodel-param-title','s:101:\"en:Title of the page to change the contentmodel of. Cannot be used together with <var>$1pageid</var>.\";'),('en','messages:apihelp-changecontentmodel-summary','s:37:\"en:Change the content model of a page\";'),('en','messages:apihelp-checktoken-example-simple','s:48:\"en:Test the validity of a <kbd>csrf</kbd> token.\";'),('en','messages:apihelp-checktoken-param-maxtokenage','s:48:\"en:Maximum allowed age of the token, in seconds.\";'),('en','messages:apihelp-checktoken-param-token','s:17:\"en:Token to test.\";'),('en','messages:apihelp-checktoken-param-type','s:30:\"en:Type of token being tested.\";'),('en','messages:apihelp-checktoken-summary','s:107:\"en:Check the validity of a token from <kbd>[[Special:ApiHelp/query+tokens|action=query&meta=tokens]]</kbd>.\";'),('en','messages:apihelp-clearhasmsg-example-1','s:59:\"en:Clear the <code>hasmsg</code> flag for the current user.\";'),('en','messages:apihelp-clearhasmsg-summary','s:60:\"en:Clears the <code>hasmsg</code> flag for the current user.\";'),('en','messages:apihelp-clientlogin-example-login','s:115:\"en:Start the process of logging in to the wiki as user <kbd>Example</kbd> with password <kbd>ExamplePassword</kbd>.\";'),('en','messages:apihelp-clientlogin-example-login2','s:132:\"en:Continue logging in after a <samp>UI</samp> response for two-factor auth, supplying an <var>OATHToken</var> of <kbd>987654</kbd>.\";'),('en','messages:apihelp-clientlogin-summary','s:49:\"en:Log in to the wiki using the interactive flow.\";'),('en','messages:apihelp-compare-example-1','s:42:\"en:Create a diff between revision 1 and 2.\";'),('en','messages:apihelp-compare-extended-description','s:117:\"en:A revision number, a page title, a page ID, text, or a relative reference for both \"from\" and \"to\" must be passed.\";'),('en','messages:apihelp-compare-param-difftype','s:50:\"en:Return the comparison formatted as inline HTML.\";'),('en','messages:apihelp-compare-param-fromcontentformat','s:87:\"en:Specify <kbd>fromslots=main</kbd> and use <var>fromcontentformat-main</var> instead.\";'),('en','messages:apihelp-compare-param-fromcontentformat-{slot}','s:67:\"en:Content serialization format of <var>fromtext-&#x7B;slot}</var>.\";'),('en','messages:apihelp-compare-param-fromcontentmodel','s:86:\"en:Specify <kbd>fromslots=main</kbd> and use <var>fromcontentmodel-main</var> instead.\";'),('en','messages:apihelp-compare-param-fromcontentmodel-{slot}','s:119:\"en:Content model of <var>fromtext-&#x7B;slot}</var>. If not supplied, it will be guessed based on the other parameters.\";'),('en','messages:apihelp-compare-param-fromid','s:28:\"en:First page ID to compare.\";'),('en','messages:apihelp-compare-param-frompst','s:62:\"en:Do a pre-save transform on <var>fromtext-&#x7B;slot}</var>.\";'),('en','messages:apihelp-compare-param-fromrev','s:29:\"en:First revision to compare.\";'),('en','messages:apihelp-compare-param-fromsection','s:66:\"en:Only use the specified section of the specified \'from\' content.\";'),('en','messages:apihelp-compare-param-fromsection-{slot}','s:244:\"en:When <var>fromtext-&#x7B;slot}</var> is the content of a single section, this is the section identifier. It will be merged into the revision specified by <var>fromtitle</var>, <var>fromid</var> or <var>fromrev</var> as if for a section edit.\";'),('en','messages:apihelp-compare-param-fromslots','s:329:\"en:Override content of the revision specified by <var>fromtitle</var>, <var>fromid</var> or <var>fromrev</var>.\n\nThis parameter specifies the slots that are to be modified. Use <var>fromtext-&#x7B;slot}</var>, <var>fromcontentmodel-&#x7B;slot}</var>, and <var>fromcontentformat-&#x7B;slot}</var> to specify content for each slot.\";'),('en','messages:apihelp-compare-param-fromtext','s:78:\"en:Specify <kbd>fromslots=main</kbd> and use <var>fromtext-main</var> instead.\";'),('en','messages:apihelp-compare-param-fromtext-{slot}','s:81:\"en:Text of the specified slot. If omitted, the slot is removed from the revision.\";'),('en','messages:apihelp-compare-param-fromtitle','s:26:\"en:First title to compare.\";'),('en','messages:apihelp-compare-param-prop','s:38:\"en:Which pieces of information to get.\";'),('en','messages:apihelp-compare-param-slots','s:88:\"en:Return individual diffs for these slots, rather than one combined diff for all slots.\";'),('en','messages:apihelp-compare-param-tocontentformat','s:83:\"en:Specify <kbd>toslots=main</kbd> and use <var>tocontentformat-main</var> instead.\";'),('en','messages:apihelp-compare-param-tocontentformat-{slot}','s:65:\"en:Content serialization format of <var>totext-&#x7B;slot}</var>.\";'),('en','messages:apihelp-compare-param-tocontentmodel','s:82:\"en:Specify <kbd>toslots=main</kbd> and use <var>tocontentmodel-main</var> instead.\";'),('en','messages:apihelp-compare-param-tocontentmodel-{slot}','s:117:\"en:Content model of <var>totext-&#x7B;slot}</var>. If not supplied, it will be guessed based on the other parameters.\";'),('en','messages:apihelp-compare-param-toid','s:29:\"en:Second page ID to compare.\";'),('en','messages:apihelp-compare-param-topst','s:48:\"en:Do a pre-save transform on <var>totext</var>.\";'),('en','messages:apihelp-compare-param-torelative','s:168:\"en:Use a revision relative to the revision determined from <var>fromtitle</var>, <var>fromid</var> or <var>fromrev</var>. All of the other \'to\' options will be ignored.\";'),('en','messages:apihelp-compare-param-torev','s:30:\"en:Second revision to compare.\";'),('en','messages:apihelp-compare-param-tosection','s:64:\"en:Only use the specified section of the specified \'to\' content.\";'),('en','messages:apihelp-compare-param-tosection-{slot}','s:236:\"en:When <var>totext-&#x7B;slot}</var> is the content of a single section, this is the section identifier. It will be merged into the revision specified by <var>totitle</var>, <var>toid</var> or <var>torev</var> as if for a section edit.\";'),('en','messages:apihelp-compare-param-toslots','s:317:\"en:Override content of the revision specified by <var>totitle</var>, <var>toid</var> or <var>torev</var>.\n\nThis parameter specifies the slots that are to be modified. Use <var>totext-&#x7B;slot}</var>, <var>tocontentmodel-&#x7B;slot}</var>, and <var>tocontentformat-&#x7B;slot}</var> to specify content for each slot.\";'),('en','messages:apihelp-compare-param-totext','s:74:\"en:Specify <kbd>toslots=main</kbd> and use <var>totext-main</var> instead.\";'),('en','messages:apihelp-compare-param-totext-{slot}','s:81:\"en:Text of the specified slot. If omitted, the slot is removed from the revision.\";'),('en','messages:apihelp-compare-param-totitle','s:27:\"en:Second title to compare.\";'),('en','messages:apihelp-compare-paramvalue-prop-comment','s:182:\"en:The comment on the \'from\' and \'to\' revisions. If the comment has been revision deleted, a <samp>fromcommenthidden</samp> or <samp>tocommenthidden</samp> property will be returned.\";'),('en','messages:apihelp-compare-paramvalue-prop-diff','s:17:\"en:The diff HTML.\";'),('en','messages:apihelp-compare-paramvalue-prop-diffsize','s:39:\"en:The size of the diff HTML, in bytes.\";'),('en','messages:apihelp-compare-paramvalue-prop-ids','s:62:\"en:The page and revision IDs of the \'from\' and \'to\' revisions.\";'),('en','messages:apihelp-compare-paramvalue-prop-parsedcomment','s:189:\"en:The parsed comment on the \'from\' and \'to\' revisions. If the comment has been revision deleted, a <samp>fromcommenthidden</samp> or <samp>tocommenthidden</samp> property will be returned.\";'),('en','messages:apihelp-compare-paramvalue-prop-rel','s:78:\"en:The revision IDs of the revision previous to \'from\' and after \'to\', if any.\";'),('en','messages:apihelp-compare-paramvalue-prop-size','s:45:\"en:The size of the \'from\' and \'to\' revisions.\";'),('en','messages:apihelp-compare-paramvalue-prop-timestamp','s:50:\"en:The timestamp of the \'from\' and \'to\' revisions.\";'),('en','messages:apihelp-compare-paramvalue-prop-title','s:52:\"en:The page titles of the \'from\' and \'to\' revisions.\";'),('en','messages:apihelp-compare-paramvalue-prop-user','s:181:\"en:The username and ID of the \'from\' and \'to\' revisions. If the user has been revision deleted, a <samp>fromuserhidden</samp> or <samp>touserhidden</samp> property will be returned.\";'),('en','messages:apihelp-compare-summary','s:40:\"en:Get the difference between two pages.\";'),('en','messages:apihelp-createaccount-example-create','s:106:\"en:Start the process of creating the user <kbd>Example</kbd> with the password <kbd>ExamplePassword</kbd>.\";'),('en','messages:apihelp-createaccount-param-preservestate','s:352:\"en:If <kbd>[[Special:ApiHelp/query+authmanagerinfo|action=query&meta=authmanagerinfo]]</kbd> returned true for <samp>hasprimarypreservedstate</samp>, requests marked as <samp>primary-required</samp> should be omitted. If it returned a non-empty value for <samp>preservedusername</samp>, that username must be used for the <var>username</var> parameter.\";'),('en','messages:apihelp-createaccount-summary','s:29:\"en:Create a new user account.\";'),('en','messages:apihelp-cspreport-param-reportonly','s:74:\"en:Mark as being a report from a monitoring policy, not an enforced policy\";'),('en','messages:apihelp-cspreport-param-source','s:59:\"en:What generated the CSP header that triggered this report\";'),('en','messages:apihelp-cspreport-summary','s:169:\"en:Used by browsers to report violations of the Content Security Policy. This module should never be used, except when used automatically by a CSP compliant web browser.\";'),('en','messages:apihelp-delete-example-reason','s:83:\"en:Delete [[{{MediaWiki:Mainpage}}]] with the reason <kbd>Preparing for move</kbd>.\";'),('en','messages:apihelp-delete-example-simple','s:37:\"en:Delete [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-delete-param-deletetalk','s:38:\"en:Delete the talk page, if it exists.\";'),('en','messages:apihelp-delete-param-oldimage','s:137:\"en:The name of the old image to delete as provided by [[Special:ApiHelp/query+imageinfo|action=query&prop=imageinfo&iiprop=archivename]].\";'),('en','messages:apihelp-delete-param-pageid','s:82:\"en:Page ID of the page to delete. Cannot be used together with <var>$1title</var>.\";'),('en','messages:apihelp-delete-param-reason','s:87:\"en:Reason for the deletion. If not set, an automatically generated reason will be used.\";'),('en','messages:apihelp-delete-param-tags','s:57:\"en:Change tags to apply to the entry in the deletion log.\";'),('en','messages:apihelp-delete-param-title','s:81:\"en:Title of the page to delete. Cannot be used together with <var>$1pageid</var>.\";'),('en','messages:apihelp-delete-param-unwatch','s:53:\"en:Remove the page from the current user\'s watchlist.\";'),('en','messages:apihelp-delete-param-watch','s:48:\"en:Add the page to the current user\'s watchlist.\";'),('en','messages:apihelp-delete-param-watchlist','s:140:\"en:Unconditionally add or remove the page from the current user\'s watchlist, use preferences (ignored for bot users) or do not change watch.\";'),('en','messages:apihelp-delete-param-watchlistexpiry','s:98:\"en:Watchlist expiry timestamp. Omit this parameter entirely to leave the current expiry unchanged.\";'),('en','messages:apihelp-delete-summary','s:17:\"en:Delete a page.\";'),('en','messages:apihelp-disabled-summary','s:33:\"en:This module has been disabled.\";'),('en','messages:apihelp-edit-example-edit','s:15:\"en:Edit a page.\";'),('en','messages:apihelp-edit-example-prepend','s:50:\"en:Prepend <kbd>_&#95;NOTOC_&#95;</kbd> to a page.\";'),('en','messages:apihelp-edit-example-undo','s:55:\"en:Undo revisions 13579 through 13585 with autosummary.\";'),('en','messages:apihelp-edit-param-appendtext','s:141:\"en:Add this text to the end of the page or section. Overrides $1text.\n\nUse $1section=new to append a new section, rather than this parameter.\";'),('en','messages:apihelp-edit-param-baserevid','s:214:\"en:ID of the base revision, used to detect edit conflicts. May be obtained through [[Special:ApiHelp/query+revisions|action=query&prop=revisions]]. Self-conflicts cause the edit to fail unless basetimestamp is set.\";'),('en','messages:apihelp-edit-param-basetimestamp','s:199:\"en:Timestamp of the base revision, used to detect edit conflicts. May be obtained through [[Special:ApiHelp/query+revisions|action=query&prop=revisions&rvprop=timestamp]]. Self-conflicts are ignored.\";'),('en','messages:apihelp-edit-param-bot','s:32:\"en:Mark this edit as a bot edit.\";'),('en','messages:apihelp-edit-param-contentformat','s:56:\"en:Content serialization format used for the input text.\";'),('en','messages:apihelp-edit-param-contentmodel','s:36:\"en:Content model of the new content.\";'),('en','messages:apihelp-edit-param-createonly','s:44:\"en:Don\'t edit the page if it exists already.\";'),('en','messages:apihelp-edit-param-md5','s:162:\"en:The MD5 hash of the $1text parameter, or the $1prependtext and $1appendtext parameters concatenated. If set, the edit won\'t be done unless the hash is correct.\";'),('en','messages:apihelp-edit-param-minor','s:34:\"en:Mark this edit as a minor edit.\";'),('en','messages:apihelp-edit-param-nocreate','s:44:\"en:Throw an error if the page doesn\'t exist.\";'),('en','messages:apihelp-edit-param-notminor','s:103:\"en:Do not mark this edit as a minor edit even if the \"{{int:tog-minordefault}}\" user preference is set.\";'),('en','messages:apihelp-edit-param-pageid','s:80:\"en:Page ID of the page to edit. Cannot be used together with <var>$1title</var>.\";'),('en','messages:apihelp-edit-param-prependtext','s:75:\"en:Add this text to the beginning of the page or section. Overrides $1text.\";'),('en','messages:apihelp-edit-param-recreate','s:74:\"en:Override any errors about the page having been deleted in the meantime.\";'),('en','messages:apihelp-edit-param-redirect','s:35:\"en:Automatically resolve redirects.\";'),('en','messages:apihelp-edit-param-returnto','s:256:\"en:Page title. If saving the edit created a temporary account, the API may respond with an URL that the client should visit to complete logging in. If this parameter is provided, the URL will redirect to the given page, instead of the page that was edited.\";'),('en','messages:apihelp-edit-param-returntoanchor','s:265:\"en:URL fragment (with leading <kbd>#</kbd>). If saving the edit created a temporary account, the API may respond with an URL that the client should visit to complete logging in. If this parameter is provided, the URL will redirect to a page with the given fragment.\";'),('en','messages:apihelp-edit-param-returntoquery','s:281:\"en:URL query parameters (with leading <kbd>?</kbd>). If saving the edit created a temporary account, the API may respond with an URL that the client should visit to complete logging in. If this parameter is provided, the URL will redirect to a page with the given query parameters.\";'),('en','messages:apihelp-edit-param-section','s:145:\"en:Section identifier. <kbd>0</kbd> for the top section, <kbd>new</kbd> for a new section. Often a positive integer, but can also be non-numeric.\";'),('en','messages:apihelp-edit-param-sectiontitle','s:67:\"en:The title for a new section when using <var>$1section=new</var>.\";'),('en','messages:apihelp-edit-param-starttimestamp','s:245:\"en:Timestamp when the editing process began, used to detect edit conflicts. An appropriate value may be obtained using <var>[[Special:ApiHelp/main|curtimestamp]]</var> when beginning the edit process (e.g. when loading the page content to edit).\";'),('en','messages:apihelp-edit-param-summary','s:348:\"en:Edit summary.\n\nWhen this parameter is not provided or empty, [[mw:Special:MyLanguage/Autosummary|an edit summary may be generated automatically]].\n\nWhen using <var>$1section=new</var> and <var>$1sectiontitle</var> is not provided, the value of this parameter is used for the section title instead, and an edit summary is generated automatically.\";'),('en','messages:apihelp-edit-param-tags','s:40:\"en:Change tags to apply to the revision.\";'),('en','messages:apihelp-edit-param-text','s:16:\"en:Page content.\";'),('en','messages:apihelp-edit-param-title','s:79:\"en:Title of the page to edit. Cannot be used together with <var>$1pageid</var>.\";'),('en','messages:apihelp-edit-param-token','s:97:\"en:The token should always be sent as the last parameter, or at least after the $1text parameter.\";'),('en','messages:apihelp-edit-param-undo','s:72:\"en:Undo this revision. Overrides $1text, $1prependtext and $1appendtext.\";'),('en','messages:apihelp-edit-param-undoafter','s:82:\"en:Undo all revisions from $1undo to this one. If not set, just undo one revision.\";'),('en','messages:apihelp-edit-param-unwatch','s:53:\"en:Remove the page from the current user\'s watchlist.\";'),('en','messages:apihelp-edit-param-watch','s:48:\"en:Add the page to the current user\'s watchlist.\";'),('en','messages:apihelp-edit-param-watchlist','s:140:\"en:Unconditionally add or remove the page from the current user\'s watchlist, use preferences (ignored for bot users) or do not change watch.\";'),('en','messages:apihelp-edit-param-watchlistexpiry','s:98:\"en:Watchlist expiry timestamp. Omit this parameter entirely to leave the current expiry unchanged.\";'),('en','messages:apihelp-edit-summary','s:25:\"en:Create and edit pages.\";'),('en','messages:apihelp-emailuser-example-email','s:83:\"en:Send an email to the user <kbd>WikiSysop</kbd> with the text <kbd>Content</kbd>.\";'),('en','messages:apihelp-emailuser-param-ccme','s:34:\"en:Send a copy of this mail to me.\";'),('en','messages:apihelp-emailuser-param-subject','s:18:\"en:Subject header.\";'),('en','messages:apihelp-emailuser-param-target','s:29:\"en:User to send the email to.\";'),('en','messages:apihelp-emailuser-param-text','s:14:\"en:Email body.\";'),('en','messages:apihelp-emailuser-summary','s:16:\"en:Email a user.\";'),('en','messages:apihelp-expandtemplates-example-simple','s:71:\"en:Expand the wikitext <kbd><nowiki>{{Project:Sandbox}}</nowiki></kbd>.\";'),('en','messages:apihelp-expandtemplates-param-generatexml','s:58:\"en:Generate XML parse tree (replaced by $1prop=parsetree).\";'),('en','messages:apihelp-expandtemplates-param-includecomments','s:50:\"en:Whether to include HTML comments in the output.\";'),('en','messages:apihelp-expandtemplates-param-prop','s:161:\"en:Which pieces of information to get.\n\nNote that if no values are selected, the result will contain the wikitext, but the output will be in a deprecated format.\";'),('en','messages:apihelp-expandtemplates-param-revid','s:87:\"en:Revision ID, for <code><nowiki>{{REVISIONID}}</nowiki></code> and similar variables.\";'),('en','messages:apihelp-expandtemplates-param-showstrategykeys','s:74:\"en:Whether to include internal merge strategy information in jsconfigvars.\";'),('en','messages:apihelp-expandtemplates-param-text','s:23:\"en:Wikitext to convert.\";'),('en','messages:apihelp-expandtemplates-param-title','s:21:\"en:Title of the page.\";'),('en','messages:apihelp-expandtemplates-paramvalue-prop-categories','s:87:\"en:Any categories present in the input that are not represented in the wikitext output.\";'),('en','messages:apihelp-expandtemplates-paramvalue-prop-encodedjsconfigvars','s:86:\"en:Gives the JavaScript configuration variables specific to the page as a JSON string.\";'),('en','messages:apihelp-expandtemplates-paramvalue-prop-jsconfigvars','s:69:\"en:Gives the JavaScript configuration variables specific to the page.\";'),('en','messages:apihelp-expandtemplates-paramvalue-prop-modules','s:206:\"en:Any ResourceLoader modules that parser functions have requested be added to the output. Either <kbd>jsconfigvars</kbd> or <kbd>encodedjsconfigvars</kbd> must be requested jointly with <kbd>modules</kbd>.\";'),('en','messages:apihelp-expandtemplates-paramvalue-prop-parsetree','s:35:\"en:The XML parse tree of the input.\";'),('en','messages:apihelp-expandtemplates-paramvalue-prop-properties','s:67:\"en:Page properties defined by expanded magic words in the wikitext.\";'),('en','messages:apihelp-expandtemplates-paramvalue-prop-ttl','s:75:\"en:The maximum time after which caches of the result should be invalidated.\";'),('en','messages:apihelp-expandtemplates-paramvalue-prop-volatile','s:85:\"en:Whether the output is volatile and should not be reused elsewhere within the page.\";'),('en','messages:apihelp-expandtemplates-paramvalue-prop-wikitext','s:25:\"en:The expanded wikitext.\";'),('en','messages:apihelp-expandtemplates-summary','s:41:\"en:Expands all templates within wikitext.\";'),('en','messages:apihelp-feedcontributions-example-simple','s:52:\"en:Return contributions for user <kbd>Example</kbd>.\";'),('en','messages:apihelp-feedcontributions-param-deletedonly','s:35:\"en:Show only deleted contributions.\";'),('en','messages:apihelp-feedcontributions-param-feedformat','s:26:\"en:The format of the feed.\";'),('en','messages:apihelp-feedcontributions-param-hideminor','s:20:\"en:Hide minor edits.\";'),('en','messages:apihelp-feedcontributions-param-month','s:28:\"en:From month (and earlier).\";'),('en','messages:apihelp-feedcontributions-param-namespace','s:50:\"en:Which namespace to filter the contributions by.\";'),('en','messages:apihelp-feedcontributions-param-newonly','s:43:\"en:Only show edits that are page creations.\";'),('en','messages:apihelp-feedcontributions-param-showsizediff','s:46:\"en:Show the size difference between revisions.\";'),('en','messages:apihelp-feedcontributions-param-tagfilter','s:45:\"en:Filter contributions that have these tags.\";'),('en','messages:apihelp-feedcontributions-param-toponly','s:49:\"en:Only show edits that are the latest revisions.\";'),('en','messages:apihelp-feedcontributions-param-user','s:43:\"en:What users to get the contributions for.\";'),('en','messages:apihelp-feedcontributions-param-year','s:27:\"en:From year (and earlier).\";'),('en','messages:apihelp-feedcontributions-summary','s:39:\"en:Returns a user\'s contributions feed.\";'),('en','messages:apihelp-feedrecentchanges-example-30days','s:35:\"en:Show recent changes for 30 days.\";'),('en','messages:apihelp-feedrecentchanges-example-simple','s:23:\"en:Show recent changes.\";'),('en','messages:apihelp-feedrecentchanges-param-associated','s:47:\"en:Include associated (talk or main) namespace.\";'),('en','messages:apihelp-feedrecentchanges-param-days','s:32:\"en:Days to limit the results to.\";'),('en','messages:apihelp-feedrecentchanges-param-feedformat','s:26:\"en:The format of the feed.\";'),('en','messages:apihelp-feedrecentchanges-param-from','s:27:\"en:Show changes since then.\";'),('en','messages:apihelp-feedrecentchanges-param-hideanons','s:40:\"en:Hide changes made by anonymous users.\";'),('en','messages:apihelp-feedrecentchanges-param-hideanons-temp','s:63:\"en:Hide changes made by anonymous users and temporary accounts.\";'),('en','messages:apihelp-feedrecentchanges-param-hidebots','s:29:\"en:Hide changes made by bots.\";'),('en','messages:apihelp-feedrecentchanges-param-hidecategorization','s:36:\"en:Hide category membership changes.\";'),('en','messages:apihelp-feedrecentchanges-param-hideliu','s:41:\"en:Hide changes made by registered users.\";'),('en','messages:apihelp-feedrecentchanges-param-hideminor','s:22:\"en:Hide minor changes.\";'),('en','messages:apihelp-feedrecentchanges-param-hidemyself','s:41:\"en:Hide changes made by the current user.\";'),('en','messages:apihelp-feedrecentchanges-param-hidepatrolled','s:26:\"en:Hide patrolled changes.\";'),('en','messages:apihelp-feedrecentchanges-param-invert','s:39:\"en:All namespaces but the selected one.\";'),('en','messages:apihelp-feedrecentchanges-param-inverttags','s:55:\"en:All edits except ones tagged with the selected ones.\";'),('en','messages:apihelp-feedrecentchanges-param-limit','s:39:\"en:Maximum number of results to return.\";'),('en','messages:apihelp-feedrecentchanges-param-namespace','s:37:\"en:Namespace to limit the results to.\";'),('en','messages:apihelp-feedrecentchanges-param-showlinkedto','s:61:\"en:Show changes on pages linked to the selected page instead.\";'),('en','messages:apihelp-feedrecentchanges-param-tagfilter','s:17:\"en:Filter by tag.\";'),('en','messages:apihelp-feedrecentchanges-param-target','s:52:\"en:Show only changes on pages linked from this page.\";'),('en','messages:apihelp-feedrecentchanges-summary','s:33:\"en:Returns a recent changes feed.\";'),('en','messages:apihelp-feedwatchlist-example-all6hrs','s:57:\"en:Show all changes to watched pages in the past 6 hours.\";'),('en','messages:apihelp-feedwatchlist-example-default','s:27:\"en:Show the watchlist feed.\";'),('en','messages:apihelp-feedwatchlist-param-feedformat','s:26:\"en:The format of the feed.\";'),('en','messages:apihelp-feedwatchlist-param-hours','s:55:\"en:List pages modified within this many hours from now.\";'),('en','messages:apihelp-feedwatchlist-param-linktosections','s:49:\"en:Link directly to changed sections if possible.\";'),('en','messages:apihelp-feedwatchlist-summary','s:28:\"en:Returns a watchlist feed.\";'),('en','messages:apihelp-filerevert-example-revert','s:80:\"en:Revert <kbd>Wiki.png</kbd> to the version of <kbd>2011-03-05T15:27:40Z</kbd>.\";'),('en','messages:apihelp-filerevert-param-archivename','s:45:\"en:Archive name of the revision to revert to.\";'),('en','messages:apihelp-filerevert-param-comment','s:18:\"en:Upload comment.\";'),('en','messages:apihelp-filerevert-param-filename','s:45:\"en:Target filename, without the File: prefix.\";'),('en','messages:apihelp-filerevert-summary','s:35:\"en:Revert a file to an old version.\";'),('en','messages:apihelp-format-example-generic','s:44:\"en:Return the query result in the $1 format.\";'),('en','messages:apihelp-format-param-wrappedhtml','s:89:\"en:Return the pretty-printed HTML and associated ResourceLoader modules as a JSON object.\";'),('en','messages:apihelp-help-example-help','s:35:\"en:Help for the help module itself.\";'),('en','messages:apihelp-help-example-main','s:28:\"en:Help for the main module.\";'),('en','messages:apihelp-help-example-query','s:33:\"en:Help for two query submodules.\";'),('en','messages:apihelp-help-example-recursive','s:24:\"en:All help in one page.\";'),('en','messages:apihelp-help-example-submodules','s:59:\"en:Help for <kbd>action=query</kbd> and all its submodules.\";'),('en','messages:apihelp-help-param-helpformat','s:29:\"en:Format of the help output.\";'),('en','messages:apihelp-help-param-modules','s:162:\"en:Modules to display help for (values of the <var>action</var> and <var>format</var> parameters, or <kbd>main</kbd>). Can specify submodules with a <kbd>+</kbd>.\";'),('en','messages:apihelp-help-param-recursivesubmodules','s:43:\"en:Include help for submodules recursively.\";'),('en','messages:apihelp-help-param-submodules','s:51:\"en:Include help for submodules of the named module.\";'),('en','messages:apihelp-help-param-toc','s:50:\"en:Include a table of contents in the HTML output.\";'),('en','messages:apihelp-help-param-wrap','s:56:\"en:Wrap the output in a standard API response structure.\";'),('en','messages:apihelp-help-summary','s:42:\"en:Display help for the specified modules.\";'),('en','messages:apihelp-imagerotate-example-generator','s:75:\"en:Rotate all images in <kbd>Category:Flip</kbd> by <kbd>180</kbd> degrees.\";'),('en','messages:apihelp-imagerotate-example-simple','s:63:\"en:Rotate <kbd>File:Example.png</kbd> by <kbd>90</kbd> degrees.\";'),('en','messages:apihelp-imagerotate-param-rotation','s:37:\"en:Degrees to rotate image clockwise.\";'),('en','messages:apihelp-imagerotate-param-tags','s:48:\"en:Tags to apply to the entry in the upload log.\";'),('en','messages:apihelp-imagerotate-summary','s:29:\"en:Rotate one or more images.\";'),('en','messages:apihelp-import-example-import','s:75:\"en:Import [[meta:Help:ParserFunctions]] to namespace 100 with full history.\";'),('en','messages:apihelp-import-extended-description','s:143:\"en:Note that the HTTP POST must be done as a file upload (i.e. using multipart/form-data) when sending a file for the <var>xml</var> parameter.\";'),('en','messages:apihelp-import-param-assignknownusers','s:67:\"en:Assign edits to local users where the named user exists locally.\";'),('en','messages:apihelp-import-param-fullhistory','s:80:\"en:For interwiki imports: import the full history, not just the current version.\";'),('en','messages:apihelp-import-param-interwikipage','s:41:\"en:For interwiki imports: page to import.\";'),('en','messages:apihelp-import-param-interwikiprefix','s:130:\"en:For uploaded imports: interwiki prefix to apply to unknown usernames (and known users if <var>$1assignknownusers</var> is set).\";'),('en','messages:apihelp-import-param-interwikisource','s:46:\"en:For interwiki imports: wiki to import from.\";'),('en','messages:apihelp-import-param-namespace','s:80:\"en:Import to this namespace. Cannot be used together with <var>$1rootpage</var>.\";'),('en','messages:apihelp-import-param-rootpage','s:87:\"en:Import as subpage of this page. Cannot be used together with <var>$1namespace</var>.\";'),('en','messages:apihelp-import-param-summary','s:28:\"en:Log entry import summary.\";'),('en','messages:apihelp-import-param-tags','s:102:\"en:Change tags to apply to the entry in the import log and to the null revision on the imported pages.\";'),('en','messages:apihelp-import-param-templates','s:64:\"en:For interwiki imports: import all included templates as well.\";'),('en','messages:apihelp-import-param-xml','s:21:\"en:Uploaded XML file.\";'),('en','messages:apihelp-import-summary','s:56:\"en:Import a page from another wiki, or from an XML file.\";'),('en','messages:apihelp-json-param-ascii','s:129:\"en:If specified, encodes all non-ASCII using hexadecimal escape sequences. Default when <var>formatversion</var> is <kbd>1</kbd>.\";'),('en','messages:apihelp-json-param-callback','s:116:\"en:If specified, wraps the output into a given function call. For safety, all user-specific data will be restricted.\";'),('en','messages:apihelp-json-param-formatversion','s:20:\"en:Output formatting\";'),('en','messages:apihelp-json-param-utf8','s:193:\"en:If specified, encodes most (but not all) non-ASCII characters as UTF-8 instead of replacing them with hexadecimal escape sequences. Default when <var>formatversion</var> is not <kbd>1</kbd>.\";'),('en','messages:apihelp-json-paramvalue-formatversion-1','s:97:\"en:Backwards-compatible format (XML-style booleans, <samp>*</samp> keys for content nodes, etc.).\";'),('en','messages:apihelp-json-paramvalue-formatversion-2','s:17:\"en:Modern format.\";'),('en','messages:apihelp-json-paramvalue-formatversion-latest','s:78:\"en:Use the latest format (currently <kbd>2</kbd>), may change without warning.\";'),('en','messages:apihelp-json-summary','s:30:\"en:Output data in JSON format.\";'),('en','messages:apihelp-jsonfm-summary','s:53:\"en:Output data in JSON format (pretty-print in HTML).\";'),('en','messages:apihelp-link','s:28:\"en:[[Special:ApiHelp/$1|$2]]\";'),('en','messages:apihelp-linkaccount-example-link','s:70:\"en:Start the process of linking to an account from <kbd>Example</kbd>.\";'),('en','messages:apihelp-linkaccount-summary','s:67:\"en:Link an account from a third-party provider to the current user.\";'),('en','messages:apihelp-login-example-login','s:10:\"en:Log in.\";'),('en','messages:apihelp-login-extended-description','s:256:\"en:This action should only be used in combination with [[Special:BotPasswords]]; use for main-account login is deprecated and may fail without warning. To safely log in to the main account, use <kbd>[[Special:ApiHelp/clientlogin|action=clientlogin]]</kbd>.\";'),('en','messages:apihelp-login-extended-description-nobotpasswords','s:143:\"en:This action is deprecated and may fail without warning. To safely log in, use <kbd>[[Special:ApiHelp/clientlogin|action=clientlogin]]</kbd>.\";'),('en','messages:apihelp-login-param-domain','s:21:\"en:Domain (optional).\";'),('en','messages:apihelp-login-param-name','s:12:\"en:Username.\";'),('en','messages:apihelp-login-param-password','s:12:\"en:Password.\";'),('en','messages:apihelp-login-param-token','s:41:\"en:Login token obtained in first request.\";'),('en','messages:apihelp-login-summary','s:41:\"en:Log in and get authentication cookies.\";'),('en','messages:apihelp-logout-example-logout','s:28:\"en:Log the current user out.\";'),('en','messages:apihelp-logout-summary','s:34:\"en:Log out and clear session data.\";'),('en','messages:apihelp-main-extended-description','s:1342:\"en:<div class=\"hlist plainlinks api-main-links\">\n* [[mw:Special:MyLanguage/API:Main_page|Documentation]]\n* [[mw:Special:MyLanguage/API:Etiquette|Etiquette & usage guidelines]]\n* [[mw:Special:MyLanguage/API:FAQ|FAQ]]\n* [https://lists.wikimedia.org/postorius/lists/mediawiki-api.lists.wikimedia.org/ Mailing list]\n* [https://lists.wikimedia.org/postorius/lists/mediawiki-api-announce.lists.wikimedia.org/ API Announcements]\n* [https://phabricator.wikimedia.org/maniphest/query/GebfyV4uCaLd/#R Bugs & requests]\n</div>\n<strong>Status:</strong> The MediaWiki API is a mature and stable interface that is actively supported and improved. While we try to avoid it, we may occasionally need to make breaking changes; subscribe to [https://lists.wikimedia.org/hyperkitty/list/mediawiki-api-announce@lists.wikimedia.org/ the mediawiki-api-announce mailing list] for notice of updates.\n\n<strong>Erroneous requests:</strong> When erroneous requests are sent to the API, an HTTP header will be sent with the key \"MediaWiki-API-Error\" and then both the value of the header and the error code sent back will be set to the same value. For more information see [[mw:Special:MyLanguage/API:Errors_and_warnings|API: Errors and warnings]].\n\n<p class=\"mw-apisandbox-link\"><strong>Testing:</strong> For ease of testing API requests, see [[Special:ApiSandbox]].</p>\";'),('en','messages:apihelp-main-param-action','s:27:\"en:Which action to perform.\";'),('en','messages:apihelp-main-param-assert','s:199:\"en:Verify that the user is logged in (including possibly as a temporary user) if set to <kbd>user</kbd>, <em>not</em> logged in if set to <kbd>anon</kbd>, or has the bot user right if <kbd>bot</kbd>.\";'),('en','messages:apihelp-main-param-assertuser','s:45:\"en:Verify the current user is the named user.\";'),('en','messages:apihelp-main-param-crossorigin','s:542:\"en:When accessing the API using a cross-domain AJAX request (CORS) and using a session provider that is safe against cross-site request forgery (CSRF) attacks (such as OAuth), use this instead of <code>origin=*</code> to make the request authenticated (i.e., not logged out). This must be included in any pre-flight request, and therefore must be part of the request URI (not the POST body).\n\nNote that most session providers, including standard cookie-based sessions, do not support authenticated CORS and cannot be used with this parameter.\";'),('en','messages:apihelp-main-param-curtimestamp','s:47:\"en:Include the current timestamp in the result.\";'),('en','messages:apihelp-main-param-errorformat','s:50:\"en:Format to use for warning and error text output\";'),('en','messages:apihelp-main-param-errorlang','s:311:\"en:Language to use for warnings and errors. <kbd>[[Special:ApiHelp/query+siteinfo|action=query&meta=siteinfo&siprop=languages]]</kbd> returns a list of language codes. Specify <kbd>content</kbd> to use this wiki\'s content language or <kbd>uselang</kbd> to use the same value as the <var>uselang</var> parameter.\";'),('en','messages:apihelp-main-param-errorsuselocal','s:98:\"en:If given, error texts will use locally-customized messages from the {{ns:MediaWiki}} namespace.\";'),('en','messages:apihelp-main-param-format','s:28:\"en:The format of the output.\";'),('en','messages:apihelp-main-param-maxage','s:104:\"en:Set the <code>max-age</code> HTTP cache control header to this many seconds. Errors are never cached.\";'),('en','messages:apihelp-main-param-maxlag','s:491:\"en:Maximum lag can be used when MediaWiki is installed on a database replicated cluster. To save actions causing any more site replication lag, this parameter can make the client wait until the replication lag is less than the specified value. In case of excessive lag, error code <samp>maxlag</samp> is returned with a message like <samp>Waiting for $host: $lag seconds lagged</samp>.<br />See [[mw:Special:MyLanguage/Manual:Maxlag_parameter|Manual: Maxlag parameter]] for more information.\";'),('en','messages:apihelp-main-param-origin','s:1008:\"en:When accessing the API using a cross-domain AJAX request (CORS), set this to the originating domain. This must be included in any pre-flight request, and therefore must be part of the request URI (not the POST body).\n\nFor authenticated requests, this must match one of the origins in the <code>Origin</code> header exactly, so it has to be set to something like <kbd>https://en.wikipedia.org</kbd> or <kbd>https://meta.wikimedia.org</kbd>. If this parameter does not match the <code>Origin</code> header, a 403 response will be returned. If this parameter matches the <code>Origin</code> header and the origin is allowed, the <code>Access-Control-Allow-Origin</code> and <code>Access-Control-Allow-Credentials</code> headers will be set.\n\nFor non-authenticated requests, specify the value <kbd>*</kbd>. This will cause the <code>Access-Control-Allow-Origin</code> header to be set, but <code>Access-Control-Allow-Credentials</code> will be <code>false</code> and all user-specific data will be restricted.\";'),('en','messages:apihelp-main-param-requestid','s:94:\"en:Any value given here will be included in the response. May be used to distinguish requests.\";'),('en','messages:apihelp-main-param-responselanginfo','s:92:\"en:Include the languages used for <var>uselang</var> and <var>errorlang</var> in the result.\";'),('en','messages:apihelp-main-param-servedby','s:63:\"en:Include the hostname that served the request in the results.\";'),('en','messages:apihelp-main-param-smaxage','s:105:\"en:Set the <code>s-maxage</code> HTTP cache control header to this many seconds. Errors are never cached.\";'),('en','messages:apihelp-main-param-uselang','s:305:\"en:Language to use for message translations. <kbd>[[Special:ApiHelp/query+siteinfo|action=query&meta=siteinfo&siprop=languages]]</kbd> returns a list of language codes. You can specify <kbd>user</kbd> to use the current user\'s language preference or <kbd>content</kbd> to use this wiki\'s content language.\";'),('en','messages:apihelp-main-param-variant','s:88:\"en:Variant of the language. Only works if the base language supports variant conversion.\";'),('en','messages:apihelp-main-paramvalue-errorformat-bc','s:103:\"en:Format used prior to MediaWiki 1.29. <var>errorlang</var> and <var>errorsuselocal</var> are ignored.\";'),('en','messages:apihelp-main-paramvalue-errorformat-html','s:7:\"en:HTML\";'),('en','messages:apihelp-main-paramvalue-errorformat-none','s:40:\"en:No text output, only the error codes.\";'),('en','messages:apihelp-main-paramvalue-errorformat-plaintext','s:57:\"en:Wikitext with HTML tags removed and entities replaced.\";'),('en','messages:apihelp-main-paramvalue-errorformat-raw','s:30:\"en:Message key and parameters.\";'),('en','messages:apihelp-main-paramvalue-errorformat-wikitext','s:21:\"en:Unparsed wikitext.\";'),('en','messages:apihelp-main-summary','s:3:\"en:\";'),('en','messages:apihelp-managetags-example-activate','s:93:\"en:Activate a tag named <kbd>spam</kbd> with the reason <kbd>For use in edit patrolling</kbd>\";'),('en','messages:apihelp-managetags-example-create','s:91:\"en:Create a tag named <kbd>spam</kbd> with the reason <kbd>For use in edit patrolling</kbd>\";'),('en','messages:apihelp-managetags-example-deactivate','s:87:\"en:Deactivate a tag named <kbd>spam</kbd> with the reason <kbd>No longer required</kbd>\";'),('en','messages:apihelp-managetags-example-delete','s:74:\"en:Delete the <kbd>vandlaism</kbd> tag with the reason <kbd>Misspelt</kbd>\";'),('en','messages:apihelp-managetags-param-ignorewarnings','s:71:\"en:Whether to ignore any warnings that are issued during the operation.\";'),('en','messages:apihelp-managetags-param-operation','s:30:\"en:Which operation to perform:\";'),('en','messages:apihelp-managetags-param-reason','s:81:\"en:An optional reason for creating, deleting, activating or deactivating the tag.\";'),('en','messages:apihelp-managetags-param-tag','s:280:\"en:Tag to create, delete, activate or deactivate. For tag creation, the tag must not exist. For tag deletion, the tag must exist. For tag activation, the tag must exist and not be in use by an extension. For tag deactivation, the tag must be currently active and manually defined.\";'),('en','messages:apihelp-managetags-param-tags','s:63:\"en:Change tags to apply to the entry in the tag management log.\";'),('en','messages:apihelp-managetags-paramvalue-operation-activate','s:62:\"en:Activate a change tag, allowing users to apply it manually.\";'),('en','messages:apihelp-managetags-paramvalue-operation-create','s:42:\"en:Create a new change tag for manual use.\";'),('en','messages:apihelp-managetags-paramvalue-operation-deactivate','s:71:\"en:Deactivate a change tag, preventing users from applying it manually.\";'),('en','messages:apihelp-managetags-paramvalue-operation-delete','s:147:\"en:Remove a change tag from the database, including removing the tag from all revisions, recent change entries and log entries on which it is used.\";'),('en','messages:apihelp-managetags-summary','s:52:\"en:Perform management tasks relating to change tags.\";'),('en','messages:apihelp-mergehistory-example-merge','s:74:\"en:Merge the entire history of <kbd>Oldpage</kbd> into <kbd>Newpage</kbd>.\";'),('en','messages:apihelp-mergehistory-example-merge-timestamp','s:119:\"en:Merge the page revisions of <kbd>Oldpage</kbd> dating up to <kbd>2015-12-31T04:37:41Z</kbd> into <kbd>Newpage</kbd>.\";'),('en','messages:apihelp-mergehistory-param-from','s:105:\"en:Title of the page from which history will be merged. Cannot be used together with <var>$1fromid</var>.\";'),('en','messages:apihelp-mergehistory-param-fromid','s:105:\"en:Page ID of the page from which history will be merged. Cannot be used together with <var>$1from</var>.\";'),('en','messages:apihelp-mergehistory-param-reason','s:32:\"en:Reason for the history merge.\";'),('en','messages:apihelp-mergehistory-param-starttimestamp','s:339:\"en:Timestamp from which revisions will be moved from the source page\'s history to the destination page\'s history. If omitted, all revisions before the timestamp parameter (or the entire history if neither are specified) will be merged into the destination page. May specify \"timestamp|revid\" to split two revisions with the same timestamp.\";'),('en','messages:apihelp-mergehistory-param-timestamp','s:289:\"en:Timestamp up to which revisions will be moved from the source page\'s history to the destination page\'s history. If omitted, the entire page history of the source page will be merged into the destination page. May specify \"timestamp|revid\" to split two revisions with the same timestamp.\";'),('en','messages:apihelp-mergehistory-param-to','s:101:\"en:Title of the page to which history will be merged. Cannot be used together with <var>$1toid</var>.\";'),('en','messages:apihelp-mergehistory-param-toid','s:101:\"en:Page ID of the page to which history will be merged. Cannot be used together with <var>$1to</var>.\";'),('en','messages:apihelp-mergehistory-summary','s:24:\"en:Merge page histories.\";'),('en','messages:apihelp-move-example-move','s:79:\"en:Move <kbd>Badtitle</kbd> to <kbd>Goodtitle</kbd> without leaving a redirect.\";'),('en','messages:apihelp-move-param-from','s:81:\"en:Title of the page to rename. Cannot be used together with <var>$1fromid</var>.\";'),('en','messages:apihelp-move-param-fromid','s:81:\"en:Page ID of the page to rename. Cannot be used together with <var>$1from</var>.\";'),('en','messages:apihelp-move-param-ignorewarnings','s:23:\"en:Ignore any warnings.\";'),('en','messages:apihelp-move-param-movesubpages','s:34:\"en:Rename subpages, if applicable.\";'),('en','messages:apihelp-move-param-movetalk','s:38:\"en:Rename the talk page, if it exists.\";'),('en','messages:apihelp-move-param-noredirect','s:27:\"en:Don\'t create a redirect.\";'),('en','messages:apihelp-move-param-reason','s:25:\"en:Reason for the rename.\";'),('en','messages:apihelp-move-param-tags','s:102:\"en:Change tags to apply to the entry in the move log and to the null revision on the destination page.\";'),('en','messages:apihelp-move-param-to','s:31:\"en:Title to rename the page to.\";'),('en','messages:apihelp-move-param-unwatch','s:70:\"en:Remove the page and the redirect from the current user\'s watchlist.\";'),('en','messages:apihelp-move-param-watch','s:65:\"en:Add the page and the redirect to the current user\'s watchlist.\";'),('en','messages:apihelp-move-param-watchlist','s:140:\"en:Unconditionally add or remove the page from the current user\'s watchlist, use preferences (ignored for bot users) or do not change watch.\";'),('en','messages:apihelp-move-param-watchlistexpiry','s:98:\"en:Watchlist expiry timestamp. Omit this parameter entirely to leave the current expiry unchanged.\";'),('en','messages:apihelp-move-summary','s:15:\"en:Move a page.\";'),('en','messages:apihelp-no-such-module','s:25:\"en:Module \"$1\" not found.\";'),('en','messages:apihelp-none-summary','s:18:\"en:Output nothing.\";'),('en','messages:apihelp-opensearch-example-te','s:43:\"en:Find pages beginning with <kbd>Te</kbd>.\";'),('en','messages:apihelp-opensearch-param-format','s:28:\"en:The format of the output.\";'),('en','messages:apihelp-opensearch-param-limit','s:39:\"en:Maximum number of results to return.\";'),('en','messages:apihelp-opensearch-param-namespace','s:93:\"en:Namespaces to search. Ignored if <var>$1search</var> begins with a valid namespace prefix.\";'),('en','messages:apihelp-opensearch-param-redirects','s:27:\"en:How to handle redirects:\";'),('en','messages:apihelp-opensearch-param-redirects-append','s:101:\"en:For historical reasons, the default is \"return\" for $1format=json and \"resolve\" for other formats.\";'),('en','messages:apihelp-opensearch-param-search','s:17:\"en:Search string.\";'),('en','messages:apihelp-opensearch-param-suggest','s:18:\"en:No longer used.\";'),('en','messages:apihelp-opensearch-param-warningsaserror','s:100:\"en:If warnings are raised with <kbd>format=json</kbd>, return an API error instead of ignoring them.\";'),('en','messages:apihelp-opensearch-paramvalue-redirects-resolve','s:65:\"en:Return the target page. May return fewer than $1limit results.\";'),('en','messages:apihelp-opensearch-paramvalue-redirects-return','s:30:\"en:Return the redirect itself.\";'),('en','messages:apihelp-opensearch-summary','s:49:\"en:Search the wiki using the OpenSearch protocol.\";'),('en','messages:apihelp-options-example-change','s:63:\"en:Change <kbd>skin</kbd> and <kbd>hideminor</kbd> preferences.\";'),('en','messages:apihelp-options-example-complex','s:75:\"en:Reset all preferences, then set <kbd>skin</kbd> and <kbd>nickname</kbd>.\";'),('en','messages:apihelp-options-example-reset','s:25:\"en:Reset all preferences.\";'),('en','messages:apihelp-options-extended-description','s:186:\"en:Only options which are registered in core or in one of installed extensions, or options with keys prefixed with <code>userjs-</code> (intended to be used by user scripts), can be set.\";'),('en','messages:apihelp-options-param-change','s:361:\"en:List of changes, formatted name=value (e.g. skin=vector). If no value is given (not even an equals sign), e.g., optionname|otheroption|..., the option will be reset to its default value. If any value passed contains the pipe character (<kbd>|</kbd>), use the [[Special:ApiHelp/main#main/datatypes|alternative multiple-value separator]] for correct operation.\";'),('en','messages:apihelp-options-param-global','s:329:\"en:What to do if the option was set globally using the GlobalPreferences extension.\n\n* <kbd>ignore</kbd>: Do nothing. The option remains with its previous value.\n* <kbd>override</kbd>: Add a local override.\n* <kbd>update</kbd>: Update the option globally.\n* <kbd>create</kbd>: Set the option globally, overriding any local value.\";'),('en','messages:apihelp-options-param-optionname','s:92:\"en:The name of the option that should be set to the value given by <var>$1optionvalue</var>.\";'),('en','messages:apihelp-options-param-optionvalue','s:189:\"en:The value for the option specified by <var>$1optionname</var>. When <var>$1optionname</var> is set but <var>$1optionvalue</var> is omitted, the option will be reset to its default value.\";'),('en','messages:apihelp-options-param-reset','s:43:\"en:Resets preferences to the site defaults.\";'),('en','messages:apihelp-options-param-resetkinds','s:79:\"en:List of types of options to reset when the <var>$1reset</var> option is set.\";'),('en','messages:apihelp-options-summary','s:42:\"en:Change preferences of the current user.\";'),('en','messages:apihelp-paraminfo-example-1','s:272:\"en:Show info for <kbd>[[Special:ApiHelp/parse|action=parse]]</kbd>, <kbd>[[Special:ApiHelp/jsonfm|format=jsonfm]]</kbd>, <kbd>[[Special:ApiHelp/query+allpages|action=query&list=allpages]]</kbd>, and <kbd>[[Special:ApiHelp/query+siteinfo|action=query&meta=siteinfo]]</kbd>.\";'),('en','messages:apihelp-paraminfo-example-2','s:85:\"en:Show info for all submodules of <kbd>[[Special:ApiHelp/query|action=query]]</kbd>.\";'),('en','messages:apihelp-paraminfo-param-formatmodules','s:104:\"en:List of format module names (value of <var>format</var> parameter). Use <var>$1modules</var> instead.\";'),('en','messages:apihelp-paraminfo-param-helpformat','s:26:\"en:Format of help strings.\";'),('en','messages:apihelp-paraminfo-param-mainmodule','s:100:\"en:Get information about the main (top-level) module as well. Use <kbd>$1modules=main</kbd> instead.\";'),('en','messages:apihelp-paraminfo-param-modules','s:244:\"en:List of module names (values of the <var>action</var> and <var>format</var> parameters, or <kbd>main</kbd>). Can specify submodules with a <kbd>+</kbd>, or all submodules with <kbd>+*</kbd>, or all submodules recursively with <kbd>+**</kbd>.\";'),('en','messages:apihelp-paraminfo-param-pagesetmodule','s:84:\"en:Get information about the pageset module (providing titles= and friends) as well.\";'),('en','messages:apihelp-paraminfo-param-querymodules','s:180:\"en:List of query module names (value of <var>prop</var>, <var>meta</var> or <var>list</var> parameter). Use <kbd>$1modules=query+foo</kbd> instead of <kbd>$1querymodules=foo</kbd>.\";'),('en','messages:apihelp-paraminfo-summary','s:40:\"en:Obtain information about API modules.\";'),('en','messages:apihelp-parse-example-page','s:16:\"en:Parse a page.\";'),('en','messages:apihelp-parse-example-summary','s:19:\"en:Parse a summary.\";'),('en','messages:apihelp-parse-example-text','s:18:\"en:Parse wikitext.\";'),('en','messages:apihelp-parse-example-texttitle','s:45:\"en:Parse wikitext, specifying the page title.\";'),('en','messages:apihelp-parse-extended-description','s:503:\"en:See the various prop-modules of <kbd>[[Special:ApiHelp/query|action=query]]</kbd> to get information from the current version of a page.\n\nThere are several ways to specify the text to parse:\n# Specify a page or revision, using <var>$1page</var>, <var>$1pageid</var>, or <var>$1oldid</var>.\n# Specify content explicitly, using <var>$1text</var>, <var>$1title</var>, <var>$1revid</var>, and <var>$1contentmodel</var>.\n# Specify only a summary to parse. <var>$1prop</var> should be given an empty value.\";'),('en','messages:apihelp-parse-param-contentformat','s:90:\"en:Content serialization format used for the input text. Only valid when used with $1text.\";'),('en','messages:apihelp-parse-param-contentmodel','s:162:\"en:Content model of the input text. If omitted, $1title must be specified, and default will be the model of the specified title. Only valid when used with $1text.\";'),('en','messages:apihelp-parse-param-disableeditsection','s:50:\"en:Omit edit section links from the parser output.\";'),('en','messages:apihelp-parse-param-disablelimitreport','s:71:\"en:Omit the limit report (\"NewPP limit report\") from the parser output.\";'),('en','messages:apihelp-parse-param-disablepp','s:47:\"en:Use <var>$1disablelimitreport</var> instead.\";'),('en','messages:apihelp-parse-param-disablestylededuplication','s:62:\"en:Do not deduplicate inline stylesheets in the parser output.\";'),('en','messages:apihelp-parse-param-disabletoc','s:36:\"en:Omit table of contents in output.\";'),('en','messages:apihelp-parse-param-effectivelanglinks','s:93:\"en:Includes language links supplied by extensions (for use with <kbd>$1prop=langlinks</kbd>).\";'),('en','messages:apihelp-parse-param-generatexml','s:109:\"en:Generate XML parse tree (requires content model <code>$1</code>; replaced by <kbd>$2prop=parsetree</kbd>).\";'),('en','messages:apihelp-parse-param-oldid','s:91:\"en:Parse the content of this revision. Overrides <var>$1page</var> and <var>$1pageid</var>.\";'),('en','messages:apihelp-parse-param-onlypst','s:168:\"en:Do a pre-save transform (PST) on the input, but don\'t parse it. Returns the same wikitext, after a PST has been applied. Only valid when used with <var>$1text</var>.\";'),('en','messages:apihelp-parse-param-page','s:105:\"en:Parse the content of this page. Cannot be used together with <var>$1text</var> and <var>$1title</var>.\";'),('en','messages:apihelp-parse-param-pageid','s:63:\"en:Parse the content of this page. Overrides <var>$1page</var>.\";'),('en','messages:apihelp-parse-param-parser','s:32:\"en:Which wikitext parser to use:\";'),('en','messages:apihelp-parse-param-parsoid','s:143:\"en:Generate HTML conforming to the [[mw:Specs/HTML|MediaWiki DOM spec]] using [[mw:Parsoid|Parsoid]].  Replaced by <kbd>$1parser=parsoid</kbd>.\";'),('en','messages:apihelp-parse-param-preview','s:25:\"en:Parse in preview mode.\";'),('en','messages:apihelp-parse-param-prop','s:38:\"en:Which pieces of information to get:\";'),('en','messages:apihelp-parse-param-pst','s:90:\"en:Do a pre-save transform on the input before parsing it. Only valid when used with text.\";'),('en','messages:apihelp-parse-param-redirects','s:80:\"en:If <var>$1page</var> or <var>$1pageid</var> is set to a redirect, resolve it.\";'),('en','messages:apihelp-parse-param-revid','s:87:\"en:Revision ID, for <code><nowiki>{{REVISIONID}}</nowiki></code> and similar variables.\";'),('en','messages:apihelp-parse-param-section','s:243:\"en:Only parse the content of the section with this identifier.\n\nWhen <kbd>new</kbd>, parse <var>$1text</var> and <var>$1sectiontitle</var> as if adding a new section to the page.\n\n<kbd>new</kbd> is allowed only when specifying <var>text</var>.\";'),('en','messages:apihelp-parse-param-sectionpreview','s:60:\"en:Parse in section preview mode (enables preview mode too).\";'),('en','messages:apihelp-parse-param-sectiontitle','s:154:\"en:New section title when <var>section</var> is <kbd>new</kbd>.\n\nUnlike page editing, this does not fall back to <var>summary</var> when omitted or empty.\";'),('en','messages:apihelp-parse-param-showstrategykeys','s:74:\"en:Whether to include internal merge strategy information in jsconfigvars.\";'),('en','messages:apihelp-parse-param-summary','s:20:\"en:Summary to parse.\";'),('en','messages:apihelp-parse-param-text','s:99:\"en:Text to parse. Use <var>$1title</var> or <var>$1contentmodel</var> to control the content model.\";'),('en','messages:apihelp-parse-param-title','s:133:\"en:Title of page the text belongs to. If omitted, <var>$1contentmodel</var> must be specified, and [[API]] will be used as the title.\";'),('en','messages:apihelp-parse-param-usearticle','s:103:\"en:Use the ArticleParserOptions hook to ensure the options used match those used for article page views\";'),('en','messages:apihelp-parse-param-useskin','s:214:\"en:Apply the selected skin to the parser output. May affect the following properties: <kbd>text</kbd>, <kbd>langlinks</kbd>, <kbd>headitems</kbd>, <kbd>modules</kbd>, <kbd>jsconfigvars</kbd>, <kbd>indicators</kbd>.\";'),('en','messages:apihelp-parse-param-wrapoutputclass','s:46:\"en:CSS class to use to wrap the parser output.\";'),('en','messages:apihelp-parse-paramvalue-parser-default','s:50:\"en:Generate HTML using this wiki\'s default parser.\";'),('en','messages:apihelp-parse-paramvalue-parser-legacy','s:41:\"en:Generate HTML using the legacy parser.\";'),('en','messages:apihelp-parse-paramvalue-parser-parsoid','s:101:\"en:Generate HTML conforming to the [[mw:Specs/HTML|MediaWiki DOM spec]] using [[mw:Parsoid|Parsoid]].\";'),('en','messages:apihelp-parse-paramvalue-prop-categories','s:47:\"en:Gives the categories in the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-categorieshtml','s:44:\"en:Gives the HTML version of the categories.\";'),('en','messages:apihelp-parse-paramvalue-prop-displaytitle','s:41:\"en:Adds the title of the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-encodedjsconfigvars','s:86:\"en:Gives the JavaScript configuration variables specific to the page as a JSON string.\";'),('en','messages:apihelp-parse-paramvalue-prop-externallinks','s:51:\"en:Gives the external links in the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-headhtml','s:144:\"en:Gives parsed doctype, opening <code>&lt;html&gt;</code>, <code>&lt;head&gt;</code> element and opening <code>&lt;body&gt;</code> of the page.\";'),('en','messages:apihelp-parse-paramvalue-prop-headitems','s:67:\"en:Gives items to put in the <code>&lt;head&gt;</code> of the page.\";'),('en','messages:apihelp-parse-paramvalue-prop-images','s:43:\"en:Gives the images in the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-indicators','s:61:\"en:Gives the HTML of page status indicators used on the page.\";'),('en','messages:apihelp-parse-paramvalue-prop-iwlinks','s:48:\"en:Gives interwiki links in the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-jsconfigvars','s:113:\"en:Gives the JavaScript configuration variables specific to the page. To apply, use <code>mw.config.set()</code>.\";'),('en','messages:apihelp-parse-paramvalue-prop-langlinks','s:51:\"en:Gives the language links in the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-limitreportdata','s:106:\"en:Gives the limit report in a structured way. Gives no data, when <var>$1disablelimitreport</var> is set.\";'),('en','messages:apihelp-parse-paramvalue-prop-limitreporthtml','s:106:\"en:Gives the HTML version of the limit report. Gives no data, when <var>$1disablelimitreport</var> is set.\";'),('en','messages:apihelp-parse-paramvalue-prop-links','s:51:\"en:Gives the internal links in the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-modules','s:214:\"en:Gives the ResourceLoader modules used on the page. To load, use <code>mw.loader.using()</code>. Either <kbd>jsconfigvars</kbd> or <kbd>encodedjsconfigvars</kbd> must be requested jointly with <kbd>modules</kbd>.\";'),('en','messages:apihelp-parse-paramvalue-prop-parsetree','s:82:\"en:The XML parse tree of revision content (requires content model <code>$1</code>)\";'),('en','messages:apihelp-parse-paramvalue-prop-parsewarnings','s:72:\"en:Gives the warnings that occurred while parsing content (as wikitext).\";'),('en','messages:apihelp-parse-paramvalue-prop-parsewarningshtml','s:68:\"en:Gives the warnings that occurred while parsing content (as HTML).\";'),('en','messages:apihelp-parse-paramvalue-prop-properties','s:59:\"en:Gives various properties defined in the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-revid','s:43:\"en:Adds the revision ID of the parsed page.\";'),('en','messages:apihelp-parse-paramvalue-prop-sections','s:45:\"en:Gives the sections in the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-subtitle','s:46:\"en:Adds the page subtitle for the parsed page.\";'),('en','messages:apihelp-parse-paramvalue-prop-templates','s:46:\"en:Gives the templates in the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-text','s:41:\"en:Gives the parsed text of the wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-tocdata','s:66:\"en:Gives the table of contents information in the parsed wikitext.\";'),('en','messages:apihelp-parse-paramvalue-prop-wikitext','s:47:\"en:Gives the original wikitext that was parsed.\";'),('en','messages:apihelp-parse-summary','s:44:\"en:Parses content and returns parser output.\";'),('en','messages:apihelp-patrol-example-rcid','s:26:\"en:Patrol a recent change.\";'),('en','messages:apihelp-patrol-example-revid','s:21:\"en:Patrol a revision.\";'),('en','messages:apihelp-patrol-param-rcid','s:30:\"en:Recentchanges ID to patrol.\";'),('en','messages:apihelp-patrol-param-revid','s:25:\"en:Revision ID to patrol.\";'),('en','messages:apihelp-patrol-param-tags','s:55:\"en:Change tags to apply to the entry in the patrol log.\";'),('en','messages:apihelp-patrol-summary','s:29:\"en:Patrol a page or revision.\";'),('en','messages:apihelp-php-param-formatversion','s:20:\"en:Output formatting\";'),('en','messages:apihelp-php-paramvalue-formatversion-1','s:97:\"en:Backwards-compatible format (XML-style booleans, <samp>*</samp> keys for content nodes, etc.).\";'),('en','messages:apihelp-php-paramvalue-formatversion-2','s:17:\"en:Modern format.\";'),('en','messages:apihelp-php-paramvalue-formatversion-latest','s:78:\"en:Use the latest format (currently <kbd>2</kbd>), may change without warning.\";'),('en','messages:apihelp-php-summary','s:40:\"en:Output data in serialized PHP format.\";'),('en','messages:apihelp-phpfm-summary','s:63:\"en:Output data in serialized PHP format (pretty-print in HTML).\";'),('en','messages:apihelp-protect-example-protect','s:18:\"en:Protect a page.\";'),('en','messages:apihelp-protect-example-unprotect','s:108:\"en:Unprotect a page by setting restrictions to <kbd>all</kbd> (i.e. everyone is allowed to take the action).\";'),('en','messages:apihelp-protect-example-unprotect2','s:47:\"en:Unprotect a page by setting no restrictions.\";'),('en','messages:apihelp-protect-param-cascade','s:163:\"en:Enable cascading protection (i.e. protect transcluded templates and images used in this page). Ignored if none of the given protection levels support cascading.\";'),('en','messages:apihelp-protect-param-expiry','s:209:\"en:Expiry timestamps. If only one timestamp is set, it\'ll be used for all protections. Use <kbd>infinite</kbd>, <kbd>indefinite</kbd>, <kbd>infinity</kbd>, or <kbd>never</kbd>, for a never-expiring protection.\";'),('en','messages:apihelp-protect-param-pageid','s:71:\"en:ID of the page to (un)protect. Cannot be used together with $1title.\";'),('en','messages:apihelp-protect-param-protections','s:265:\"en:List of protection levels, formatted <kbd>action=level</kbd> (e.g. <kbd>edit=sysop</kbd>). A level of <kbd>all</kbd> means everyone is allowed to take the action, i.e. no restriction.\n\n<strong>Note:</strong> Any actions not listed will have restrictions removed.\";'),('en','messages:apihelp-protect-param-reason','s:29:\"en:Reason for (un)protecting.\";'),('en','messages:apihelp-protect-param-tags','s:59:\"en:Change tags to apply to the entry in the protection log.\";'),('en','messages:apihelp-protect-param-title','s:75:\"en:Title of the page to (un)protect. Cannot be used together with $1pageid.\";'),('en','messages:apihelp-protect-param-watch','s:76:\"en:If set, add the page being (un)protected to the current user\'s watchlist.\";'),('en','messages:apihelp-protect-param-watchlist','s:140:\"en:Unconditionally add or remove the page from the current user\'s watchlist, use preferences (ignored for bot users) or do not change watch.\";'),('en','messages:apihelp-protect-param-watchlistexpiry','s:98:\"en:Watchlist expiry timestamp. Omit this parameter entirely to leave the current expiry unchanged.\";'),('en','messages:apihelp-protect-summary','s:41:\"en:Change the protection level of a page.\";'),('en','messages:apihelp-purge-example-generator','s:50:\"en:Purge the first 10 pages in the main namespace.\";'),('en','messages:apihelp-purge-example-simple','s:75:\"en:Purge <kbd>[[{{MediaWiki:Mainpage}}]]</kbd> and the <kbd>API</kbd> page.\";'),('en','messages:apihelp-purge-param-forcelinkupdate','s:63:\"en:Update the links tables and do other secondary data updates.\";'),('en','messages:apihelp-purge-param-forcerecursivelinkupdate','s:114:\"en:Same as <kbd>forcelinkupdate</kbd>, and update the links tables for any page that uses this page as a template.\";'),('en','messages:apihelp-purge-summary','s:40:\"en:Purge the cache for the given titles.\";'),('en','messages:apihelp-query+allcategories-example-generator','s:89:\"en:Retrieve info about the category page itself for categories beginning <kbd>List</kbd>.\";'),('en','messages:apihelp-query+allcategories-example-size','s:67:\"en:List categories with information on the number of pages in each.\";'),('en','messages:apihelp-query+allcategories-param-dir','s:24:\"en:Direction to sort in.\";'),('en','messages:apihelp-query+allcategories-param-from','s:42:\"en:The category to start enumerating from.\";'),('en','messages:apihelp-query+allcategories-param-limit','s:33:\"en:How many categories to return.\";'),('en','messages:apihelp-query+allcategories-param-max','s:57:\"en:Only return categories with at most this many members.\";'),('en','messages:apihelp-query+allcategories-param-min','s:58:\"en:Only return categories with at least this many members.\";'),('en','messages:apihelp-query+allcategories-param-prefix','s:61:\"en:Search for all category titles that begin with this value.\";'),('en','messages:apihelp-query+allcategories-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+allcategories-param-to','s:39:\"en:The category to stop enumerating at.\";'),('en','messages:apihelp-query+allcategories-paramvalue-prop-hidden','s:75:\"en:Tags categories that are hidden with <code>_&#95;HIDDENCAT_&#95;</code>.\";'),('en','messages:apihelp-query+allcategories-paramvalue-prop-size','s:40:\"en:Adds number of pages in the category.\";'),('en','messages:apihelp-query+allcategories-summary','s:28:\"en:Enumerate all categories.\";'),('en','messages:apihelp-query+alldeletedrevisions-example-ns-main','s:61:\"en:List the first 50 deleted revisions in the main namespace.\";'),('en','messages:apihelp-query+alldeletedrevisions-example-user','s:69:\"en:List the last 50 deleted contributions by user <kbd>Example</kbd>.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-end','s:40:\"en:The timestamp to stop enumerating at.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-excludeuser','s:37:\"en:Don\'t list revisions by this user.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-from','s:31:\"en:Start listing at this title.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-generatetitles','s:76:\"en:When being used as a generator, generate titles rather than revision IDs.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-miser-user-namespace','s:278:\"en:<strong>Note:</strong> Due to [[mw:Special:MyLanguage/Manual:$wgMiserMode|miser mode]], using <var>$1user</var> and <var>$1namespace</var> together may result in fewer than <var>$1limit</var> results returned before continuing; in extreme cases, zero results may be returned.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-namespace','s:37:\"en:Only list pages in this namespace.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-prefix','s:57:\"en:Search for all page titles that begin with this value.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-start','s:43:\"en:The timestamp to start enumerating from.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-tag','s:44:\"en:Only list revisions tagged with this tag.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-to','s:30:\"en:Stop listing at this title.\";'),('en','messages:apihelp-query+alldeletedrevisions-param-user','s:36:\"en:Only list revisions by this user.\";'),('en','messages:apihelp-query+alldeletedrevisions-paraminfo-nonuseronly','s:41:\"en:Cannot be used with <var>$3user</var>.\";'),('en','messages:apihelp-query+alldeletedrevisions-paraminfo-useronly','s:43:\"en:May only be used with <var>$3user</var>.\";'),('en','messages:apihelp-query+alldeletedrevisions-summary','s:58:\"en:List all deleted revisions by a user or in a namespace.\";'),('en','messages:apihelp-query+allfileusages-example-b','s:99:\"en:List file titles, including missing ones, with page IDs they are from, starting at <kbd>B</kbd>.\";'),('en','messages:apihelp-query+allfileusages-example-generator','s:35:\"en:Gets pages containing the files.\";'),('en','messages:apihelp-query+allfileusages-example-unique','s:27:\"en:List unique file titles.\";'),('en','messages:apihelp-query+allfileusages-example-unique-generator','s:50:\"en:Gets all file titles, marking the missing ones.\";'),('en','messages:apihelp-query+allfileusages-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+allfileusages-param-from','s:51:\"en:The title of the file to start enumerating from.\";'),('en','messages:apihelp-query+allfileusages-param-limit','s:34:\"en:How many total items to return.\";'),('en','messages:apihelp-query+allfileusages-param-prefix','s:57:\"en:Search for all file titles that begin with this value.\";'),('en','messages:apihelp-query+allfileusages-param-prop','s:42:\"en:Which pieces of information to include:\";'),('en','messages:apihelp-query+allfileusages-param-to','s:48:\"en:The title of the file to stop enumerating at.\";'),('en','messages:apihelp-query+allfileusages-param-unique','s:137:\"en:Only show distinct file titles. Cannot be used with $1prop=ids.\nWhen used as a generator, yields target pages instead of source pages.\";'),('en','messages:apihelp-query+allfileusages-paramvalue-prop-ids','s:71:\"en:Adds the page IDs of the using pages (cannot be used with $1unique).\";'),('en','messages:apihelp-query+allfileusages-paramvalue-prop-title','s:30:\"en:Adds the title of the file.\";'),('en','messages:apihelp-query+allfileusages-summary','s:48:\"en:List all file usages, including non-existing.\";'),('en','messages:apihelp-query+allimages-example-b','s:60:\"en:Show a list of files starting at the letter <kbd>B</kbd>.\";'),('en','messages:apihelp-query+allimages-example-generator','s:63:\"en:Show info about 4 files starting at the letter <kbd>T</kbd>.\";'),('en','messages:apihelp-query+allimages-example-mimetypes','s:83:\"en:Show a list of files with MIME type <kbd>image/png</kbd> or <kbd>image/gif</kbd>\";'),('en','messages:apihelp-query+allimages-example-recent','s:75:\"en:Show a list of recently uploaded files, similar to [[Special:NewFiles]].\";'),('en','messages:apihelp-query+allimages-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+allimages-param-end','s:76:\"en:The timestamp to end enumerating. Can only be used with $1sort=timestamp.\";'),('en','messages:apihelp-query+allimages-param-filterbots','s:117:\"en:How to filter files uploaded by bots. Can only be used with $1sort=timestamp. Cannot be used together with $1user.\";'),('en','messages:apihelp-query+allimages-param-from','s:80:\"en:The image title to start enumerating from. Can only be used with $1sort=name.\";'),('en','messages:apihelp-query+allimages-param-limit','s:38:\"en:How many images in total to return.\";'),('en','messages:apihelp-query+allimages-param-maxsize','s:48:\"en:Limit to images with at most this many bytes.\";'),('en','messages:apihelp-query+allimages-param-mime','s:61:\"en:What MIME types to search for, e.g. <kbd>image/jpeg</kbd>.\";'),('en','messages:apihelp-query+allimages-param-minsize','s:49:\"en:Limit to images with at least this many bytes.\";'),('en','messages:apihelp-query+allimages-param-prefix','s:93:\"en:Search for all image titles that begin with this value. Can only be used with $1sort=name.\";'),('en','messages:apihelp-query+allimages-param-sha1','s:46:\"en:SHA1 hash of image. Overrides $1sha1base36.\";'),('en','messages:apihelp-query+allimages-param-sha1base36','s:53:\"en:SHA1 hash of image in base 36 (used in MediaWiki).\";'),('en','messages:apihelp-query+allimages-param-sort','s:23:\"en:Property to sort by.\";'),('en','messages:apihelp-query+allimages-param-start','s:83:\"en:The timestamp to start enumerating from. Can only be used with $1sort=timestamp.\";'),('en','messages:apihelp-query+allimages-param-to','s:77:\"en:The image title to stop enumerating at. Can only be used with $1sort=name.\";'),('en','messages:apihelp-query+allimages-param-user','s:153:\"en:Only return files where the last version was uploaded by this user. Can only be used with $1sort=timestamp. Cannot be used together with $1filterbots.\";'),('en','messages:apihelp-query+allimages-summary','s:37:\"en:Enumerate all images sequentially.\";'),('en','messages:apihelp-query+alllinks-example-b','s:101:\"en:List linked titles, including missing ones, with page IDs they are from, starting at <kbd>B</kbd>.\";'),('en','messages:apihelp-query+alllinks-example-generator','s:35:\"en:Gets pages containing the links.\";'),('en','messages:apihelp-query+alllinks-example-unique','s:29:\"en:List unique linked titles.\";'),('en','messages:apihelp-query+alllinks-example-unique-generator','s:52:\"en:Gets all linked titles, marking the missing ones.\";'),('en','messages:apihelp-query+alllinks-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+alllinks-param-from','s:51:\"en:The title of the link to start enumerating from.\";'),('en','messages:apihelp-query+alllinks-param-limit','s:34:\"en:How many total items to return.\";'),('en','messages:apihelp-query+alllinks-param-namespace','s:30:\"en:The namespace to enumerate.\";'),('en','messages:apihelp-query+alllinks-param-prefix','s:59:\"en:Search for all linked titles that begin with this value.\";'),('en','messages:apihelp-query+alllinks-param-prop','s:42:\"en:Which pieces of information to include:\";'),('en','messages:apihelp-query+alllinks-param-to','s:48:\"en:The title of the link to stop enumerating at.\";'),('en','messages:apihelp-query+alllinks-param-unique','s:150:\"en:Only show distinct linked titles. Cannot be used with <kbd>$1prop=ids</kbd>.\nWhen used as a generator, yields target pages instead of source pages.\";'),('en','messages:apihelp-query+alllinks-paramvalue-prop-ids','s:82:\"en:Adds the page ID of the linking page (cannot be used with <var>$1unique</var>).\";'),('en','messages:apihelp-query+alllinks-paramvalue-prop-title','s:30:\"en:Adds the title of the link.\";'),('en','messages:apihelp-query+alllinks-summary','s:55:\"en:Enumerate all links that point to a given namespace.\";'),('en','messages:apihelp-query+allmessages-example-de','s:69:\"en:Show messages <kbd>august</kbd> and <kbd>mainpage</kbd> in German.\";'),('en','messages:apihelp-query+allmessages-example-ipb','s:47:\"en:Show messages starting with <kbd>ipb-</kbd>.\";'),('en','messages:apihelp-query+allmessages-param-args','s:44:\"en:Arguments to be substituted into message.\";'),('en','messages:apihelp-query+allmessages-param-customised','s:52:\"en:Return only messages in this customisation state.\";'),('en','messages:apihelp-query+allmessages-param-enableparser','s:114:\"en:Set to enable parser, will preprocess the wikitext of message (substitute magic words, handle templates, etc.).\";'),('en','messages:apihelp-query+allmessages-param-filter','s:60:\"en:Return only messages with names that contain this string.\";'),('en','messages:apihelp-query+allmessages-param-from','s:44:\"en:Return messages starting at this message.\";'),('en','messages:apihelp-query+allmessages-param-includelocal','s:276:\"en:Also include local messages, i.e. messages that don\'t exist in the software but do exist as in the {{ns:MediaWiki}} namespace.\nThis lists all {{ns:MediaWiki}}-namespace pages, so it will also list those that aren\'t really messages such as [[MediaWiki:Common.js|Common.js]].\";'),('en','messages:apihelp-query+allmessages-param-lang','s:36:\"en:Return messages in this language.\";'),('en','messages:apihelp-query+allmessages-param-messages','s:71:\"en:Which messages to output. <kbd>*</kbd> (default) means all messages.\";'),('en','messages:apihelp-query+allmessages-param-nocontent','s:68:\"en:If set, do not include the content of the messages in the output.\";'),('en','messages:apihelp-query+allmessages-param-prefix','s:36:\"en:Return messages with this prefix.\";'),('en','messages:apihelp-query+allmessages-param-prop','s:27:\"en:Which properties to get.\";'),('en','messages:apihelp-query+allmessages-param-title','s:80:\"en:Page name to use as context when parsing message (for $1enableparser option).\";'),('en','messages:apihelp-query+allmessages-param-to','s:42:\"en:Return messages ending at this message.\";'),('en','messages:apihelp-query+allmessages-summary','s:34:\"en:Return messages from this site.\";'),('en','messages:apihelp-query+allpages-example-b','s:60:\"en:Show a list of pages starting at the letter <kbd>B</kbd>.\";'),('en','messages:apihelp-query+allpages-example-generator','s:63:\"en:Show info about 4 pages starting at the letter <kbd>T</kbd>.\";'),('en','messages:apihelp-query+allpages-example-generator-revisions','s:73:\"en:Show content of first 2 non-redirect pages beginning at <kbd>Re</kbd>.\";'),('en','messages:apihelp-query+allpages-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+allpages-param-filterlanglinks','s:111:\"en:Filter based on whether a page has langlinks. Note that this may not consider langlinks added by extensions.\";'),('en','messages:apihelp-query+allpages-param-filterredir','s:23:\"en:Which pages to list.\";'),('en','messages:apihelp-query+allpages-param-from','s:44:\"en:The page title to start enumerating from.\";'),('en','messages:apihelp-query+allpages-param-limit','s:34:\"en:How many total pages to return.\";'),('en','messages:apihelp-query+allpages-param-maxsize','s:47:\"en:Limit to pages with at most this many bytes.\";'),('en','messages:apihelp-query+allpages-param-minsize','s:48:\"en:Limit to pages with at least this many bytes.\";'),('en','messages:apihelp-query+allpages-param-namespace','s:30:\"en:The namespace to enumerate.\";'),('en','messages:apihelp-query+allpages-param-prefix','s:57:\"en:Search for all page titles that begin with this value.\";'),('en','messages:apihelp-query+allpages-param-prexpiry','s:49:\"en:Which protection expiry to filter the page on:\";'),('en','messages:apihelp-query+allpages-param-prfiltercascade','s:79:\"en:Filter protections based on cascadingness (ignored when $1prtype isn\'t set).\";'),('en','messages:apihelp-query+allpages-param-prlevel','s:88:\"en:Filter protections based on protection level (must be used with $1prtype= parameter).\";'),('en','messages:apihelp-query+allpages-param-prtype','s:33:\"en:Limit to protected pages only.\";'),('en','messages:apihelp-query+allpages-param-to','s:41:\"en:The page title to stop enumerating at.\";'),('en','messages:apihelp-query+allpages-paramvalue-prexpiry-all','s:41:\"en:Get pages with any protections expiry.\";'),('en','messages:apihelp-query+allpages-paramvalue-prexpiry-definite','s:63:\"en:Get only pages with a definite (specific) protection expiry.\";'),('en','messages:apihelp-query+allpages-paramvalue-prexpiry-indefinite','s:52:\"en:Get only pages with indefinite protection expiry.\";'),('en','messages:apihelp-query+allpages-summary','s:57:\"en:Enumerate all pages sequentially in a given namespace.\";'),('en','messages:apihelp-query+allredirects-example-b','s:100:\"en:List target pages, including missing ones, with page IDs they are from, starting at <kbd>B</kbd>.\";'),('en','messages:apihelp-query+allredirects-example-generator','s:39:\"en:Gets pages containing the redirects.\";'),('en','messages:apihelp-query+allredirects-example-unique','s:28:\"en:List unique target pages.\";'),('en','messages:apihelp-query+allredirects-example-unique-generator','s:51:\"en:Gets all target pages, marking the missing ones.\";'),('en','messages:apihelp-query+allredirects-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+allredirects-param-from','s:55:\"en:The title of the redirect to start enumerating from.\";'),('en','messages:apihelp-query+allredirects-param-limit','s:34:\"en:How many total items to return.\";'),('en','messages:apihelp-query+allredirects-param-namespace','s:30:\"en:The namespace to enumerate.\";'),('en','messages:apihelp-query+allredirects-param-prefix','s:58:\"en:Search for all target pages that begin with this value.\";'),('en','messages:apihelp-query+allredirects-param-prop','s:42:\"en:Which pieces of information to include:\";'),('en','messages:apihelp-query+allredirects-param-to','s:52:\"en:The title of the redirect to stop enumerating at.\";'),('en','messages:apihelp-query+allredirects-param-unique','s:157:\"en:Only show distinct target pages. Cannot be used with $1prop=ids|fragment|interwiki.\nWhen used as a generator, yields target pages instead of source pages.\";'),('en','messages:apihelp-query+allredirects-paramvalue-prop-fragment','s:89:\"en:Adds the fragment from the redirect, if any (cannot be used with <var>$1unique</var>).\";'),('en','messages:apihelp-query+allredirects-paramvalue-prop-ids','s:86:\"en:Adds the page ID of the redirecting page (cannot be used with <var>$1unique</var>).\";'),('en','messages:apihelp-query+allredirects-paramvalue-prop-interwiki','s:97:\"en:Adds the interwiki prefix from the redirect, if any (cannot be used with <var>$1unique</var>).\";'),('en','messages:apihelp-query+allredirects-paramvalue-prop-title','s:34:\"en:Adds the title of the redirect.\";'),('en','messages:apihelp-query+allredirects-summary','s:37:\"en:List all redirects to a namespace.\";'),('en','messages:apihelp-query+allrevisions-example-ns-any','s:48:\"en:List the first 50 revisions in any namespace.\";'),('en','messages:apihelp-query+allrevisions-example-user','s:61:\"en:List the last 50 contributions by user <kbd>Example</kbd>.\";'),('en','messages:apihelp-query+allrevisions-param-end','s:40:\"en:The timestamp to stop enumerating at.\";'),('en','messages:apihelp-query+allrevisions-param-excludeuser','s:37:\"en:Don\'t list revisions by this user.\";'),('en','messages:apihelp-query+allrevisions-param-generatetitles','s:76:\"en:When being used as a generator, generate titles rather than revision IDs.\";'),('en','messages:apihelp-query+allrevisions-param-namespace','s:37:\"en:Only list pages in this namespace.\";'),('en','messages:apihelp-query+allrevisions-param-start','s:43:\"en:The timestamp to start enumerating from.\";'),('en','messages:apihelp-query+allrevisions-param-user','s:36:\"en:Only list revisions by this user.\";'),('en','messages:apihelp-query+allrevisions-summary','s:22:\"en:List all revisions.\";'),('en','messages:apihelp-query+alltransclusions-example-b','s:106:\"en:List transcluded titles, including missing ones, with page IDs they are from, starting at <kbd>B</kbd>.\";'),('en','messages:apihelp-query+alltransclusions-example-generator','s:43:\"en:Gets pages containing the transclusions.\";'),('en','messages:apihelp-query+alltransclusions-example-unique','s:34:\"en:List unique transcluded titles.\";'),('en','messages:apihelp-query+alltransclusions-example-unique-generator','s:57:\"en:Gets all transcluded titles, marking the missing ones.\";'),('en','messages:apihelp-query+alltransclusions-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+alltransclusions-param-from','s:59:\"en:The title of the transclusion to start enumerating from.\";'),('en','messages:apihelp-query+alltransclusions-param-limit','s:34:\"en:How many total items to return.\";'),('en','messages:apihelp-query+alltransclusions-param-namespace','s:30:\"en:The namespace to enumerate.\";'),('en','messages:apihelp-query+alltransclusions-param-prefix','s:64:\"en:Search for all transcluded titles that begin with this value.\";'),('en','messages:apihelp-query+alltransclusions-param-prop','s:42:\"en:Which pieces of information to include:\";'),('en','messages:apihelp-query+alltransclusions-param-to','s:56:\"en:The title of the transclusion to stop enumerating at.\";'),('en','messages:apihelp-query+alltransclusions-param-unique','s:144:\"en:Only show distinct transcluded titles. Cannot be used with $1prop=ids.\nWhen used as a generator, yields target pages instead of source pages.\";'),('en','messages:apihelp-query+alltransclusions-paramvalue-prop-ids','s:76:\"en:Adds the page ID of the transcluding page (cannot be used with $1unique).\";'),('en','messages:apihelp-query+alltransclusions-paramvalue-prop-title','s:38:\"en:Adds the title of the transclusion.\";'),('en','messages:apihelp-query+alltransclusions-summary','s:99:\"en:List all transclusions (pages embedded using &#123;&#123;x&#125;&#125;), including non-existing.\";'),('en','messages:apihelp-query+allusers-example-y','s:39:\"en:List users starting at <kbd>Y</kbd>.\";'),('en','messages:apihelp-query+allusers-param-activeusers','s:64:\"en:Only list users active in the last $1 {{PLURAL:$1|day|days}}.\";'),('en','messages:apihelp-query+allusers-param-attachedwiki','s:117:\"en:With <kbd>$1prop=centralids</kbd>, also indicate whether the user is attached with the wiki identified by this ID.\";'),('en','messages:apihelp-query+allusers-param-dir','s:24:\"en:Direction to sort in.\";'),('en','messages:apihelp-query+allusers-param-excludegroup','s:37:\"en:Exclude users in the given groups.\";'),('en','messages:apihelp-query+allusers-param-excludenamed','s:35:\"en:Exclude users of named accounts.\";'),('en','messages:apihelp-query+allusers-param-excludetemp','s:39:\"en:Exclude users of temporary accounts.\";'),('en','messages:apihelp-query+allusers-param-from','s:42:\"en:The username to start enumerating from.\";'),('en','messages:apihelp-query+allusers-param-group','s:124:\"en:Only include users in the given groups. Does not include implicit or auto-promoted groups like *, user, or autoconfirmed.\";'),('en','messages:apihelp-query+allusers-param-limit','s:38:\"en:How many total usernames to return.\";'),('en','messages:apihelp-query+allusers-param-prefix','s:51:\"en:Search for all users that begin with this value.\";'),('en','messages:apihelp-query+allusers-param-prop','s:42:\"en:Which pieces of information to include:\";'),('en','messages:apihelp-query+allusers-param-rights','s:144:\"en:Only include users with the given rights. Does not include rights granted by implicit or auto-promoted groups like *, user, or autoconfirmed.\";'),('en','messages:apihelp-query+allusers-param-to','s:39:\"en:The username to stop enumerating at.\";'),('en','messages:apihelp-query+allusers-param-witheditsonly','s:39:\"en:Only list users who have made edits.\";'),('en','messages:apihelp-query+allusers-paramvalue-prop-blockinfo','s:58:\"en:Adds the information about a current block on the user.\";'),('en','messages:apihelp-query+allusers-paramvalue-prop-centralids','s:59:\"en:Adds the central IDs and attachment status for the user.\";'),('en','messages:apihelp-query+allusers-paramvalue-prop-editcount','s:35:\"en:Adds the edit count of the user.\";'),('en','messages:apihelp-query+allusers-paramvalue-prop-groups','s:113:\"en:Lists groups that the user is in. This uses more server resources and may return fewer results than the limit.\";'),('en','messages:apihelp-query+allusers-paramvalue-prop-implicitgroups','s:53:\"en:Lists all the groups the user is automatically in.\";'),('en','messages:apihelp-query+allusers-paramvalue-prop-registration','s:78:\"en:Adds the timestamp of when the user registered if available (may be blank).\";'),('en','messages:apihelp-query+allusers-paramvalue-prop-rights','s:34:\"en:Lists rights that the user has.\";'),('en','messages:apihelp-query+allusers-summary','s:34:\"en:Enumerate all registered users.\";'),('en','messages:apihelp-query+authmanagerinfo-example-login','s:62:\"en:Fetch the requests that may be used when beginning a login.\";'),('en','messages:apihelp-query+authmanagerinfo-example-login-merged','s:87:\"en:Fetch the requests that may be used when beginning a login, with form fields merged.\";'),('en','messages:apihelp-query+authmanagerinfo-example-securitysensitiveoperation','s:71:\"en:Test whether authentication is sufficient for action <kbd>foo</kbd>.\";'),('en','messages:apihelp-query+authmanagerinfo-param-requestsfor','s:102:\"en:Fetch information about the authentication requests needed for the specified authentication action.\";'),('en','messages:apihelp-query+authmanagerinfo-param-securitysensitiveoperation','s:118:\"en:Test whether the user\'s current authentication status is sufficient for the specified security-sensitive operation.\";'),('en','messages:apihelp-query+authmanagerinfo-summary','s:64:\"en:Retrieve information about the current authentication status.\";'),('en','messages:apihelp-query+backlinks-example-generator','s:69:\"en:Get information about pages linking to [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+backlinks-example-simple','s:44:\"en:Show links to [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+backlinks-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+backlinks-param-filterredir','s:146:\"en:How to filter for redirects. If set to <kbd>nonredirects</kbd> when <var>$1redirect</var> is enabled, this is only applied to the second level.\";'),('en','messages:apihelp-query+backlinks-param-limit','s:182:\"en:How many total pages to return. If <var>$1redirect</var> is enabled, the limit applies to each level separately (which means up to 2 * <var>$1limit</var> results may be returned).\";'),('en','messages:apihelp-query+backlinks-param-namespace','s:30:\"en:The namespace to enumerate.\";'),('en','messages:apihelp-query+backlinks-param-pageid','s:70:\"en:Page ID to search. Cannot be used together with <var>$1title</var>.\";'),('en','messages:apihelp-query+backlinks-param-redirect','s:109:\"en:If linking page is a redirect, find all pages that link to that redirect as well. Maximum limit is halved.\";'),('en','messages:apihelp-query+backlinks-param-title','s:69:\"en:Title to search. Cannot be used together with <var>$1pageid</var>.\";'),('en','messages:apihelp-query+backlinks-summary','s:46:\"en:Find all pages that link to the given page.\";'),('en','messages:apihelp-query+blocks-example-simple','s:15:\"en:List blocks.\";'),('en','messages:apihelp-query+blocks-example-users','s:60:\"en:List blocks of users <kbd>Alice</kbd> and <kbd>Bob</kbd>.\";'),('en','messages:apihelp-query+blocks-param-end','s:40:\"en:The timestamp to stop enumerating at.\";'),('en','messages:apihelp-query+blocks-param-ids','s:40:\"en:List of block IDs to list (optional).\";'),('en','messages:apihelp-query+blocks-param-ip','s:195:\"en:Get all blocks applying to this IP address or CIDR range, including range blocks.\nCannot be used together with <var>$3users</var>. CIDR ranges broader than IPv4/$1 or IPv6/$2 are not accepted.\";'),('en','messages:apihelp-query+blocks-param-limit','s:40:\"en:The maximum number of blocks to list.\";'),('en','messages:apihelp-query+blocks-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+blocks-param-show','s:136:\"en:Show only items that meet these criteria.\nFor example, to see only indefinite blocks on IP addresses, set <kbd>$1show=ip|!temp</kbd>.\";'),('en','messages:apihelp-query+blocks-param-start','s:43:\"en:The timestamp to start enumerating from.\";'),('en','messages:apihelp-query+blocks-param-users','s:42:\"en:List of users to search for (optional).\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-by','s:42:\"en:Adds the username of the blocking user.\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-byid','s:41:\"en:Adds the user ID of the blocking user.\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-expiry','s:48:\"en:Adds the timestamp of when the block expires.\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-flags','s:49:\"en:Tags the ban with (autoblock, anononly, etc.).\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-id','s:28:\"en:Adds the ID of the block.\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-parsedreason','s:46:\"en:Adds the parsed reason given for the block.\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-range','s:56:\"en:Adds the range of IP addresses affected by the block.\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-reason','s:39:\"en:Adds the reason given for the block.\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-restrictions','s:68:\"en:Adds the partial block restrictions if the block is not sitewide.\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-timestamp','s:50:\"en:Adds the timestamp of when the block was given.\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-user','s:41:\"en:Adds the username of the blocked user.\";'),('en','messages:apihelp-query+blocks-paramvalue-prop-userid','s:40:\"en:Adds the user ID of the blocked user.\";'),('en','messages:apihelp-query+blocks-summary','s:43:\"en:List all blocked users and IP addresses.\";'),('en','messages:apihelp-query+categories-example-generator','s:84:\"en:Get information about all categories used in the page <kbd>Albert Einstein</kbd>.\";'),('en','messages:apihelp-query+categories-example-simple','s:75:\"en:Get a list of categories the page <kbd>Albert Einstein</kbd> belongs to.\";'),('en','messages:apihelp-query+categories-param-categories','s:99:\"en:Only list these categories. Useful for checking whether a certain page is in a certain category.\";'),('en','messages:apihelp-query+categories-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+categories-param-limit','s:33:\"en:How many categories to return.\";'),('en','messages:apihelp-query+categories-param-prop','s:56:\"en:Which additional properties to get for each category:\";'),('en','messages:apihelp-query+categories-param-show','s:36:\"en:Which kind of categories to show.\";'),('en','messages:apihelp-query+categories-paramvalue-prop-hidden','s:75:\"en:Tags categories that are hidden with <code>_&#95;HIDDENCAT_&#95;</code>.\";'),('en','messages:apihelp-query+categories-paramvalue-prop-sortkey','s:99:\"en:Adds the sortkey (hexadecimal string) and sortkey prefix (human-readable part) for the category.\";'),('en','messages:apihelp-query+categories-paramvalue-prop-timestamp','s:49:\"en:Adds timestamp of when the category was added.\";'),('en','messages:apihelp-query+categories-summary','s:43:\"en:List all categories the pages belong to.\";'),('en','messages:apihelp-query+categoryinfo-example-simple','s:77:\"en:Get information about <kbd>Category:Foo</kbd> and <kbd>Category:Bar</kbd>.\";'),('en','messages:apihelp-query+categoryinfo-summary','s:50:\"en:Returns information about the given categories.\";'),('en','messages:apihelp-query+categorymembers-example-generator','s:69:\"en:Get page info about first 10 pages in <kbd>Category:Physics</kbd>.\";'),('en','messages:apihelp-query+categorymembers-example-simple','s:53:\"en:Get first 10 pages in <kbd>Category:Physics</kbd>.\";'),('en','messages:apihelp-query+categorymembers-param-dir','s:30:\"en:In which direction to sort.\";'),('en','messages:apihelp-query+categorymembers-param-end','s:82:\"en:Timestamp to end listing at. Can only be used with <kbd>$1sort=timestamp</kbd>.\";'),('en','messages:apihelp-query+categorymembers-param-endhexsortkey','s:120:\"en:Sortkey to end listing at, as returned by <kbd>$1prop=sortkey</kbd>. Can only be used with <kbd>$1sort=sortkey</kbd>.\";'),('en','messages:apihelp-query+categorymembers-param-endsortkey','s:31:\"en:Use $1endhexsortkey instead.\";'),('en','messages:apihelp-query+categorymembers-param-endsortkeyprefix','s:195:\"en:Sortkey prefix to end listing <strong>before</strong> (not <strong>at</strong>; if this value occurs it will not be included!). Can only be used with $1sort=sortkey. Overrides $1endhexsortkey.\";'),('en','messages:apihelp-query+categorymembers-param-limit','s:41:\"en:The maximum number of pages to return.\";'),('en','messages:apihelp-query+categorymembers-param-namespace','s:169:\"en:Only include pages in these namespaces. Note that <kbd>$1type=subcat</kbd> or <kbd>$1type=file</kbd> may be used instead of <kbd>$1namespace=14</kbd> or <kbd>6</kbd>.\";'),('en','messages:apihelp-query+categorymembers-param-pageid','s:89:\"en:Page ID of the category to enumerate. Cannot be used together with <var>$1title</var>.\";'),('en','messages:apihelp-query+categorymembers-param-prop','s:42:\"en:Which pieces of information to include:\";'),('en','messages:apihelp-query+categorymembers-param-sort','s:23:\"en:Property to sort by.\";'),('en','messages:apihelp-query+categorymembers-param-start','s:86:\"en:Timestamp to start listing from. Can only be used with <kbd>$1sort=timestamp</kbd>.\";'),('en','messages:apihelp-query+categorymembers-param-starthexsortkey','s:124:\"en:Sortkey to start listing from, as returned by <kbd>$1prop=sortkey</kbd>. Can only be used with <kbd>$1sort=sortkey</kbd>.\";'),('en','messages:apihelp-query+categorymembers-param-startsortkey','s:33:\"en:Use $1starthexsortkey instead.\";'),('en','messages:apihelp-query+categorymembers-param-startsortkeyprefix','s:129:\"en:Sortkey prefix to start listing from. Can only be used with <kbd>$1sort=sortkey</kbd>. Overrides <var>$1starthexsortkey</var>.\";'),('en','messages:apihelp-query+categorymembers-param-title','s:145:\"en:Which category to enumerate (required). Must include the <kbd>{{ns:category}}:</kbd> prefix. Cannot be used together with <var>$1pageid</var>.\";'),('en','messages:apihelp-query+categorymembers-param-type','s:94:\"en:Which type of category members to include. Ignored when <kbd>$1sort=timestamp</kbd> is set.\";'),('en','messages:apihelp-query+categorymembers-paramvalue-prop-ids','s:20:\"en:Adds the page ID.\";'),('en','messages:apihelp-query+categorymembers-paramvalue-prop-sortkey','s:74:\"en:Adds the sortkey used for sorting in the category (hexadecimal string).\";'),('en','messages:apihelp-query+categorymembers-paramvalue-prop-sortkeyprefix','s:97:\"en:Adds the sortkey prefix used for sorting in the category (human-readable part of the sortkey).\";'),('en','messages:apihelp-query+categorymembers-paramvalue-prop-timestamp','s:52:\"en:Adds the timestamp of when the page was included.\";'),('en','messages:apihelp-query+categorymembers-paramvalue-prop-title','s:47:\"en:Adds the title and namespace ID of the page.\";'),('en','messages:apihelp-query+categorymembers-paramvalue-prop-type','s:117:\"en:Adds the type that the page has been categorised as (<samp>page</samp>, <samp>subcat</samp> or <samp>file</samp>).\";'),('en','messages:apihelp-query+categorymembers-summary','s:38:\"en:List all pages in a given category.\";'),('en','messages:apihelp-query+codexicons-example','s:45:\"en:Get icons for cdxIconInfo and cdxIconTrash\";'),('en','messages:apihelp-query+codexicons-param-names','s:17:\"en:Names of icons\";'),('en','messages:apihelp-query+codexicons-summary','s:18:\"en:Get Codex icons\";'),('en','messages:apihelp-query+contributors-example-simple','s:60:\"en:Show contributors to the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+contributors-param-excludegroup','s:119:\"en:Exclude users in the given groups. Does not include implicit or auto-promoted groups like *, user, or autoconfirmed.\";'),('en','messages:apihelp-query+contributors-param-excluderights','s:141:\"en:Exclude users having the given rights. Does not include rights granted by implicit or auto-promoted groups like *, user, or autoconfirmed.\";'),('en','messages:apihelp-query+contributors-param-group','s:124:\"en:Only include users in the given groups. Does not include implicit or auto-promoted groups like *, user, or autoconfirmed.\";'),('en','messages:apihelp-query+contributors-param-limit','s:35:\"en:How many contributors to return.\";'),('en','messages:apihelp-query+contributors-param-rights','s:146:\"en:Only include users having the given rights. Does not include rights granted by implicit or auto-promoted groups like *, user, or autoconfirmed.\";'),('en','messages:apihelp-query+contributors-summary','s:93:\"en:Get the list of logged-in contributors and the count of logged-out contributors to a page.\";'),('en','messages:apihelp-query+contributors-summary-tempusers-enabled','s:121:\"en:Get the list of logged-in contributors (including temporary users) and the count of logged-out contributors to a page.\";'),('en','messages:apihelp-query+deletedrevisions-example-revids','s:63:\"en:List the information for deleted revision <kbd>123456</kbd>.\";'),('en','messages:apihelp-query+deletedrevisions-example-titles','s:101:\"en:List the deleted revisions of the pages [[{{MediaWiki:Mainpage}}]] and its talk page with content.\";'),('en','messages:apihelp-query+deletedrevisions-extended-description','s:239:\"en:May be used in several ways:\n# Get deleted revisions for a set of pages, by setting titles or pageids. Ordered by title and timestamp.\n# Get data about a set of deleted revisions by setting their IDs with revids. Ordered by revision ID.\";'),('en','messages:apihelp-query+deletedrevisions-param-end','s:88:\"en:The timestamp to stop enumerating at. Ignored when processing a list of revision IDs.\";'),('en','messages:apihelp-query+deletedrevisions-param-excludeuser','s:37:\"en:Don\'t list revisions by this user.\";'),('en','messages:apihelp-query+deletedrevisions-param-start','s:91:\"en:The timestamp to start enumerating from. Ignored when processing a list of revision IDs.\";'),('en','messages:apihelp-query+deletedrevisions-param-tag','s:44:\"en:Only list revisions tagged with this tag.\";'),('en','messages:apihelp-query+deletedrevisions-param-user','s:36:\"en:Only list revisions by this user.\";'),('en','messages:apihelp-query+deletedrevisions-summary','s:36:\"en:Get deleted revision information.\";'),('en','messages:apihelp-query+deletedrevs-example-mode1','s:128:\"en:List the last deleted revisions of the pages [[{{MediaWiki:Mainpage}}]] and <kbd>Talk:Main Page</kbd>, with content (mode 1).\";'),('en','messages:apihelp-query+deletedrevs-example-mode2','s:69:\"en:List the last 50 deleted contributions by <kbd>Bob</kbd> (mode 2).\";'),('en','messages:apihelp-query+deletedrevs-example-mode3-main','s:70:\"en:List the first 50 deleted revisions in the main namespace (mode 3).\";'),('en','messages:apihelp-query+deletedrevs-example-mode3-talk','s:73:\"en:List the first 50 deleted pages in the {{ns:talk}} namespace (mode 3).\";'),('en','messages:apihelp-query+deletedrevs-extended-description','s:381:\"en:Operates in three modes:\n# List deleted revisions for the given titles, sorted by timestamp.\n# List deleted contributions for the given user, sorted by timestamp (no titles specified).\n# List all deleted revisions in the given namespace, sorted by title and timestamp (no titles specified, $1user not set).\n\nCertain parameters only apply to some modes and are ignored in others.\";'),('en','messages:apihelp-query+deletedrevs-param-end','s:40:\"en:The timestamp to stop enumerating at.\";'),('en','messages:apihelp-query+deletedrevs-param-excludeuser','s:37:\"en:Don\'t list revisions by this user.\";'),('en','messages:apihelp-query+deletedrevs-param-from','s:31:\"en:Start listing at this title.\";'),('en','messages:apihelp-query+deletedrevs-param-limit','s:98:\"en:The maximum amount of revisions to list. If <var>$2prop=content</var> is used, the limit is $1.\";'),('en','messages:apihelp-query+deletedrevs-param-namespace','s:37:\"en:Only list pages in this namespace.\";'),('en','messages:apihelp-query+deletedrevs-param-prefix','s:57:\"en:Search for all page titles that begin with this value.\";'),('en','messages:apihelp-query+deletedrevs-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+deletedrevs-param-start','s:43:\"en:The timestamp to start enumerating from.\";'),('en','messages:apihelp-query+deletedrevs-param-tag','s:44:\"en:Only list revisions tagged with this tag.\";'),('en','messages:apihelp-query+deletedrevs-param-to','s:30:\"en:Stop listing at this title.\";'),('en','messages:apihelp-query+deletedrevs-param-unique','s:40:\"en:List only one revision for each page.\";'),('en','messages:apihelp-query+deletedrevs-param-user','s:36:\"en:Only list revisions by this user.\";'),('en','messages:apihelp-query+deletedrevs-paraminfo-modes','s:31:\"en:{{PLURAL:$1|Mode|Modes}}: $2\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-comment','s:36:\"en:Adds the comment of the revision.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-content','s:123:\"en:Adds the content of the revision. For performance reasons, if this option is used, <var>$2limit</var> is enforced to $1.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-len','s:43:\"en:Adds the length (bytes) of the revision.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-minor','s:33:\"en:Tags if the revision is minor.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-parentid','s:61:\"en:Adds the revision ID of the previous revision to the page.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-parsedcomment','s:43:\"en:Adds the parsed comment of the revision.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-revid','s:48:\"en:Adds the revision ID of the deleted revision.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-sha1','s:44:\"en:Adds the SHA-1 (base 16) of the revision.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-tags','s:25:\"en:Tags for the revision.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-token','s:24:\"en:Gives the edit token.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-user','s:39:\"en:Adds the user who made the revision.\";'),('en','messages:apihelp-query+deletedrevs-paramvalue-prop-userid','s:49:\"en:Adds the ID of the user who made the revision.\";'),('en','messages:apihelp-query+deletedrevs-summary','s:26:\"en:List deleted revisions.\";'),('en','messages:apihelp-query+disabled-summary','s:39:\"en:This query module has been disabled.\";'),('en','messages:apihelp-query+duplicatefiles-example-generated','s:36:\"en:Look for duplicates of all files.\";'),('en','messages:apihelp-query+duplicatefiles-example-simple','s:61:\"en:Look for duplicates of [[:File:Albert Einstein Head.jpg]].\";'),('en','messages:apihelp-query+duplicatefiles-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+duplicatefiles-param-limit','s:38:\"en:How many duplicate files to return.\";'),('en','messages:apihelp-query+duplicatefiles-param-localonly','s:47:\"en:Look only for files in the local repository.\";'),('en','messages:apihelp-query+duplicatefiles-summary','s:78:\"en:List all files that are duplicates of the given files based on hash values.\";'),('en','messages:apihelp-query+embeddedin-example-generator','s:69:\"en:Get information about pages transcluding <kbd>Template:Stub</kbd>.\";'),('en','messages:apihelp-query+embeddedin-example-simple','s:52:\"en:Show pages transcluding <kbd>Template:Stub</kbd>.\";'),('en','messages:apihelp-query+embeddedin-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+embeddedin-param-filterredir','s:31:\"en:How to filter for redirects.\";'),('en','messages:apihelp-query+embeddedin-param-limit','s:34:\"en:How many total pages to return.\";'),('en','messages:apihelp-query+embeddedin-param-namespace','s:30:\"en:The namespace to enumerate.\";'),('en','messages:apihelp-query+embeddedin-param-pageid','s:59:\"en:Page ID to search. Cannot be used together with $1title.\";'),('en','messages:apihelp-query+embeddedin-param-title','s:58:\"en:Title to search. Cannot be used together with $1pageid.\";'),('en','messages:apihelp-query+embeddedin-summary','s:58:\"en:Find all pages that embed (transclude) the given title.\";'),('en','messages:apihelp-query+extlinks-example-simple','s:71:\"en:Get a list of external links on the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+extlinks-param-expandurl','s:61:\"en:Expand protocol-relative URLs with the canonical protocol.\";'),('en','messages:apihelp-query+extlinks-param-limit','s:28:\"en:How many links to return.\";'),('en','messages:apihelp-query+extlinks-param-protocol','s:190:\"en:Protocol of the URL. If empty and <var>$1query</var> is set, the protocol is <kbd>http</kbd> and <kbd>https</kbd>. Leave both this and <var>$1query</var> empty to list all external links.\";'),('en','messages:apihelp-query+extlinks-param-query','s:110:\"en:Search string without protocol. Useful for checking whether a certain page contains a certain external url.\";'),('en','messages:apihelp-query+extlinks-summary','s:67:\"en:Returns all external URLs (not interwikis) from the given pages.\";'),('en','messages:apihelp-query+exturlusage-example-simple','s:62:\"en:Show pages linking to <kbd>https://www.mediawiki.org</kbd>.\";'),('en','messages:apihelp-query+exturlusage-param-expandurl','s:61:\"en:Expand protocol-relative URLs with the canonical protocol.\";'),('en','messages:apihelp-query+exturlusage-param-limit','s:28:\"en:How many pages to return.\";'),('en','messages:apihelp-query+exturlusage-param-namespace','s:36:\"en:The page namespaces to enumerate.\";'),('en','messages:apihelp-query+exturlusage-param-prop','s:42:\"en:Which pieces of information to include:\";'),('en','messages:apihelp-query+exturlusage-param-protocol','s:190:\"en:Protocol of the URL. If empty and <var>$1query</var> is set, the protocol is <kbd>http</kbd> and <kbd>https</kbd>. Leave both this and <var>$1query</var> empty to list all external links.\";'),('en','messages:apihelp-query+exturlusage-param-query','s:102:\"en:Search string without protocol. See [[Special:LinkSearch]]. Leave empty to list all external links.\";'),('en','messages:apihelp-query+exturlusage-paramvalue-prop-ids','s:23:\"en:Adds the ID of page.\";'),('en','messages:apihelp-query+exturlusage-paramvalue-prop-title','s:47:\"en:Adds the title and namespace ID of the page.\";'),('en','messages:apihelp-query+exturlusage-paramvalue-prop-url','s:33:\"en:Adds the URL used in the page.\";'),('en','messages:apihelp-query+exturlusage-summary','s:44:\"en:Enumerate pages that contain a given URL.\";'),('en','messages:apihelp-query+filearchive-example-simple','s:36:\"en:Show a list of all deleted files.\";'),('en','messages:apihelp-query+filearchive-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+filearchive-param-from','s:45:\"en:The image title to start enumerating from.\";'),('en','messages:apihelp-query+filearchive-param-limit','s:38:\"en:How many images to return in total.\";'),('en','messages:apihelp-query+filearchive-param-prefix','s:58:\"en:Search for all image titles that begin with this value.\";'),('en','messages:apihelp-query+filearchive-param-prop','s:34:\"en:Which image information to get:\";'),('en','messages:apihelp-query+filearchive-param-sha1','s:46:\"en:SHA1 hash of image. Overrides $1sha1base36.\";'),('en','messages:apihelp-query+filearchive-param-sha1base36','s:53:\"en:SHA1 hash of image in base 36 (used in MediaWiki).\";'),('en','messages:apihelp-query+filearchive-param-to','s:42:\"en:The image title to stop enumerating at.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-archivename','s:68:\"en:Adds the filename of the archive version for non-latest versions.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-bitdepth','s:37:\"en:Adds the bit depth of the version.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-description','s:41:\"en:Adds description of the image version.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-dimensions','s:18:\"en:Alias for size.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-mediatype','s:36:\"en:Adds the media type of the image.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-metadata','s:52:\"en:Lists Exif metadata for the version of the image.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-mime','s:26:\"en:Adds MIME of the image.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-parseddescription','s:40:\"en:Parse the description of the version.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-sha1','s:33:\"en:Adds SHA-1 hash for the image.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-size','s:92:\"en:Adds the size of the image in bytes and the height, width and page count (if applicable).\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-timestamp','s:43:\"en:Adds timestamp for the uploaded version.\";'),('en','messages:apihelp-query+filearchive-paramvalue-prop-user','s:44:\"en:Adds user who uploaded the image version.\";'),('en','messages:apihelp-query+filearchive-summary','s:44:\"en:Enumerate all deleted files sequentially.\";'),('en','messages:apihelp-query+filerepoinfo-example-simple','s:43:\"en:Get information about file repositories.\";'),('en','messages:apihelp-query+filerepoinfo-param-prop','s:85:\"en:Which repository properties to get (properties available may vary on other wikis).\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-apiurl','s:76:\"en:URL to the repository API - helpful for getting image info from the host.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-articlepath','s:109:\"en:Repository wiki\'s <var>[[mw:Special:MyLanguage/Manual:$wgArticlePath|$wgArticlePath]]</var> or equivalent.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-canUpload','s:93:\"en:Whether files can be uploaded to this repository, e.g. via CORS and shared authentication.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-displayname','s:50:\"en:The human-readable name of the repository wiki.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-favicon','s:105:\"en:Repository wiki\'s favicon URL, from <var>[[mw:Special:MyLanguage/Manual:$wgFavicon|$wgFavicon]]</var>.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-fetchDescription','s:109:\"en:Whether file description pages are fetched from this repository when viewing local file description pages.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-initialCapital','s:61:\"en:Whether file names implicitly start with a capital letter.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-local','s:51:\"en:Whether that repository is the local one or not.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-name','s:192:\"en:The key of the repository - used in e.g. <var>[[mw:Special:MyLanguage/Manual:$wgForeignFileRepos|$wgForeignFileRepos]]</var> and [[Special:ApiHelp/query+imageinfo|imageinfo]] return values.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-rootUrl','s:33:\"en:Root URL path for image paths.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-scriptDirUrl','s:66:\"en:Root URL path for the repository wiki\'s MediaWiki installation.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-server','s:99:\"en:Repository wiki\'s <var>[[mw:Special:MyLanguage/Manual:$wgServer|$wgServer]]</var> or equivalent.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-thumbUrl','s:37:\"en:Root URL path for thumbnail paths.\";'),('en','messages:apihelp-query+filerepoinfo-paramvalue-prop-url','s:24:\"en:Public zone URL path.\";'),('en','messages:apihelp-query+filerepoinfo-summary','s:75:\"en:Return meta information about image repositories configured on the wiki.\";'),('en','messages:apihelp-query+fileusage-example-generator','s:59:\"en:Get information about pages using [[:File:Example.jpg]].\";'),('en','messages:apihelp-query+fileusage-example-simple','s:51:\"en:Get a list of pages using [[:File:Example.jpg]].\";'),('en','messages:apihelp-query+fileusage-param-limit','s:22:\"en:How many to return.\";'),('en','messages:apihelp-query+fileusage-param-namespace','s:42:\"en:Only include pages in these namespaces.\";'),('en','messages:apihelp-query+fileusage-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+fileusage-param-show','s:44:\"en:Show only items that meet these criteria:\";'),('en','messages:apihelp-query+fileusage-paramvalue-prop-pageid','s:24:\"en:Page ID of each page.\";'),('en','messages:apihelp-query+fileusage-paramvalue-prop-redirect','s:34:\"en:Flag if the page is a redirect.\";'),('en','messages:apihelp-query+fileusage-paramvalue-prop-title','s:22:\"en:Title of each page.\";'),('en','messages:apihelp-query+fileusage-paramvalue-show-!redirect','s:27:\"en:Only show non-redirects.\";'),('en','messages:apihelp-query+fileusage-paramvalue-show-redirect','s:23:\"en:Only show redirects.\";'),('en','messages:apihelp-query+fileusage-summary','s:43:\"en:Find all pages that use the given files.\";'),('en','messages:apihelp-query+imageinfo-example-dated','s:78:\"en:Fetch information about versions of [[:File:Test.jpg]] from 2008 and later.\";'),('en','messages:apihelp-query+imageinfo-example-simple','s:85:\"en:Fetch information about the current version of [[:File:Albert Einstein Head.jpg]].\";'),('en','messages:apihelp-query+imageinfo-param-badfilecontexttitle','s:116:\"en:If <kbd>$2prop=badfile</kbd> is set, this is the page title used when evaluating the [[MediaWiki:Bad image list]]\";'),('en','messages:apihelp-query+imageinfo-param-end','s:32:\"en:Timestamp to stop listing at.\";'),('en','messages:apihelp-query+imageinfo-param-extmetadatafilter','s:87:\"en:If specified and non-empty, only these keys will be returned for $1prop=extmetadata.\";'),('en','messages:apihelp-query+imageinfo-param-extmetadatalanguage','s:183:\"en:What language to fetch extmetadata in. This affects both which translation to fetch, if multiple are available, as well as how things like numbers and various values are formatted.\";'),('en','messages:apihelp-query+imageinfo-param-extmetadatamultilang','s:77:\"en:If translations for extmetadata property are available, fetch all of them.\";'),('en','messages:apihelp-query+imageinfo-param-limit','s:46:\"en:How many file revisions to return per file.\";'),('en','messages:apihelp-query+imageinfo-param-localonly','s:47:\"en:Look only for files in the local repository.\";'),('en','messages:apihelp-query+imageinfo-param-metadataversion','s:139:\"en:Version of metadata to use. If <kbd>latest</kbd> is specified, use latest version. Defaults to <kbd>1</kbd> for backwards compatibility.\";'),('en','messages:apihelp-query+imageinfo-param-prop','s:33:\"en:Which file information to get:\";'),('en','messages:apihelp-query+imageinfo-param-start','s:35:\"en:Timestamp to start listing from.\";'),('en','messages:apihelp-query+imageinfo-param-urlheight','s:25:\"en:Similar to $1urlwidth.\";'),('en','messages:apihelp-query+imageinfo-param-urlparam','s:173:\"en:A handler specific parameter string. For example, PDFs might use <kbd>page15-100px</kbd>. <var>$1urlwidth</var> must be used and be consistent with <var>$1urlparam</var>.\";'),('en','messages:apihelp-query+imageinfo-param-urlwidth','s:177:\"en:If $2prop=url is set, a URL to an image scaled to this width will be returned.\nFor performance reasons if this option is used, no more than $1 scaled images will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-archivename','s:160:\"en:Adds the filename of the archive version for non-latest versions. If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-badfile','s:63:\"en:Adds whether the file is on the [[MediaWiki:Bad image list]]\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-bitdepth','s:129:\"en:Adds the bit depth of the version. If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-canonicaltitle','s:132:\"en:Adds the canonical title of the file. If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-comment','s:124:\"en:Comment on the version. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-commonmetadata','s:158:\"en:Lists file format generic metadata for the version of the file. If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-dimensions','s:18:\"en:Alias for size.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-extmetadata','s:374:\"en:Lists formatted metadata combined from multiple sources. Results are HTML formatted. If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\n\n<strong>Note:</strong> This is an expensive property to request, and should be avoided unless you need it. When using it, you should request only a few results at a time to avoid too much load.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-mediatype','s:127:\"en:Adds the media type of the file. If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-metadata','s:143:\"en:Lists Exif metadata for the version of the file. If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-mime','s:122:\"en:Adds MIME type of the file. If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-parsedcomment','s:134:\"en:Parse the comment on the version. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-sha1','s:124:\"en:Adds SHA-1 hash for the file. If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-size','s:91:\"en:Adds the size of the file in bytes and the height, width and page count (if applicable).\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-thumbmime','s:169:\"en:Adds MIME type of the image thumbnail (requires url and param $1urlwidth). If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-timestamp','s:43:\"en:Adds timestamp for the uploaded version.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-uploadwarning','s:122:\"en:Used by the Special:Upload page to get information about an existing file. Not intended for use outside MediaWiki core.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-url','s:142:\"en:Gives URL to the file and the description page. If the file has been revision deleted, a <samp>filehidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-user','s:140:\"en:Adds the user who uploaded each file version. If the user has been revision deleted, a <samp>userhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-paramvalue-prop-userid','s:150:\"en:Add the ID of the user that uploaded each file version. If the user has been revision deleted, a <samp>userhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+imageinfo-summary','s:47:\"en:Returns file information and upload history.\";'),('en','messages:apihelp-query+images-example-generator','s:79:\"en:Get information about all files used on the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+images-example-simple','s:67:\"en:Get a list of files used on the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+images-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+images-param-images','s:88:\"en:Only list these files. Useful for checking whether a certain page has a certain file.\";'),('en','messages:apihelp-query+images-param-limit','s:28:\"en:How many files to return.\";'),('en','messages:apihelp-query+images-summary','s:50:\"en:Returns all files contained on the given pages.\";'),('en','messages:apihelp-query+imageusage-example-generator','s:72:\"en:Get information about pages using [[:File:Albert Einstein Head.jpg]].\";'),('en','messages:apihelp-query+imageusage-example-simple','s:55:\"en:Show pages using [[:File:Albert Einstein Head.jpg]].\";'),('en','messages:apihelp-query+imageusage-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+imageusage-param-filterredir','s:124:\"en:How to filter for redirects. If set to nonredirects when $1redirect is enabled, this is only applied to the second level.\";'),('en','messages:apihelp-query+imageusage-param-limit','s:182:\"en:How many total pages to return. If <var>$1redirect</var> is enabled, the limit applies to each level separately (which means up to 2 * <var>$1limit</var> results may be returned).\";'),('en','messages:apihelp-query+imageusage-param-namespace','s:30:\"en:The namespace to enumerate.\";'),('en','messages:apihelp-query+imageusage-param-pageid','s:59:\"en:Page ID to search. Cannot be used together with $1title.\";'),('en','messages:apihelp-query+imageusage-param-redirect','s:109:\"en:If linking page is a redirect, find all pages that link to that redirect as well. Maximum limit is halved.\";'),('en','messages:apihelp-query+imageusage-param-title','s:58:\"en:Title to search. Cannot be used together with $1pageid.\";'),('en','messages:apihelp-query+imageusage-summary','s:49:\"en:Find all pages that use the given image title.\";'),('en','messages:apihelp-query+info-example-protection','s:84:\"en:Get general and protection information about the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+info-example-simple','s:61:\"en:Get information about the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+info-param-editintrocustom','s:64:\"en:Title of a custom page to use as an additional intro message.\";'),('en','messages:apihelp-query+info-param-editintroskip','s:169:\"en:List of intro messages to remove from the response. Use this if a specific message is not relevant to your tool, or if the information is conveyed in a different way.\";'),('en','messages:apihelp-query+info-param-editintrostyle','s:138:\"en:Some intro messages come with optional wrapper frames. Use <kbd>moreframes</kbd> to include them or <kbd>lessframes</kbd> to omit them.\";'),('en','messages:apihelp-query+info-param-linkcontext','s:137:\"en:The context title to use when determining extra CSS classes (e.g. link colors) when <var>$1prop</var> contains <var>linkclasses</var>.\";'),('en','messages:apihelp-query+info-param-preloadcustom','s:54:\"en:Title of a custom page to use as preloaded content.\";'),('en','messages:apihelp-query+info-param-preloadnewsection','s:82:\"en:Return preloaded content for a new section on the page, rather than a new page.\";'),('en','messages:apihelp-query+info-param-preloadparams','s:66:\"en:Parameters for the custom page being used as preloaded content.\";'),('en','messages:apihelp-query+info-param-prop','s:38:\"en:Which additional properties to get:\";'),('en','messages:apihelp-query+info-param-testactions','s:73:\"en:Test whether the current user can perform certain actions on the page.\";'),('en','messages:apihelp-query+info-param-testactionsautocreate','s:99:\"en:Test whether performing <var>$1testactions</var> would automatically create a temporary account.\";'),('en','messages:apihelp-query+info-param-testactionsdetail','s:199:\"en:Detail level for <var>$1testactions</var>. Use the [[Special:ApiHelp/main|main module]]\'s <var>errorformat</var> and <var>errorlang</var> parameters to control the format of the messages returned.\";'),('en','messages:apihelp-query+info-paraminfo-editintroonly','s:66:\"en:Only used when <var>$3prop</var> contains <var>editintro</var>.\";'),('en','messages:apihelp-query+info-paraminfo-preloadcontentonly','s:71:\"en:Only used when <var>$3prop</var> contains <var>preloadcontent</var>.\";'),('en','messages:apihelp-query+info-paramvalue-prop-associatedpage','s:110:\"en:The prefixed title of the [[:mw:Special:MyLanguage/Help:Associated_pages|associated subject or talk page]].\";'),('en','messages:apihelp-query+info-paramvalue-prop-displaytitle','s:66:\"en:Gives the manner in which the page title is actually displayed.\";'),('en','messages:apihelp-query+info-paramvalue-prop-editintro','s:106:\"en:Gives the intro messages that should be shown to the user while editing this page or revision, as HTML.\";'),('en','messages:apihelp-query+info-paramvalue-prop-linkclasses','s:152:\"en:Gives the additional CSS classes (e.g. link colors) used for links to this page if they were to appear on the page named by <var>$1linkcontext</var>.\";'),('en','messages:apihelp-query+info-paramvalue-prop-notificationtimestamp','s:53:\"en:The watchlist notification timestamp of each page.\";'),('en','messages:apihelp-query+info-paramvalue-prop-preload','s:139:\"en:Gives the text returned by EditFormPreloadText. Use <kbd>preloadcontent</kbd> instead, which supports other kinds of preloaded text too.\";'),('en','messages:apihelp-query+info-paramvalue-prop-preloadcontent','s:106:\"en:Gives the content to be shown in the editor when the page does not exist or while adding a new section.\";'),('en','messages:apihelp-query+info-paramvalue-prop-protection','s:42:\"en:List the protection level of each page.\";'),('en','messages:apihelp-query+info-paramvalue-prop-readable','s:82:\"en:Whether the user can read this page. Use <kbd>intestactions=read</kbd> instead.\";'),('en','messages:apihelp-query+info-paramvalue-prop-subjectid','s:53:\"en:The page ID of the parent page for each talk page.\";'),('en','messages:apihelp-query+info-paramvalue-prop-talkid','s:55:\"en:The page ID of the talk page for each non-talk page.\";'),('en','messages:apihelp-query+info-paramvalue-prop-url','s:70:\"en:Gives a full URL, an edit URL, and the canonical URL for each page.\";'),('en','messages:apihelp-query+info-paramvalue-prop-varianttitles','s:72:\"en:Gives the display title in all variants of the site content language.\";'),('en','messages:apihelp-query+info-paramvalue-prop-visitingwatchers','s:94:\"en:The number of watchers of each page who have visited recent edits to that page, if allowed.\";'),('en','messages:apihelp-query+info-paramvalue-prop-watched','s:40:\"en:List the watched status of each page.\";'),('en','messages:apihelp-query+info-paramvalue-prop-watchers','s:38:\"en:The number of watchers, if allowed.\";'),('en','messages:apihelp-query+info-paramvalue-testactionsdetail-boolean','s:42:\"en:Return a boolean value for each action.\";'),('en','messages:apihelp-query+info-paramvalue-testactionsdetail-full','s:95:\"en:Return messages describing why the action is disallowed, or an empty array if it is allowed.\";'),('en','messages:apihelp-query+info-paramvalue-testactionsdetail-quick','s:54:\"en:Like <kbd>full</kbd> but skipping expensive checks.\";'),('en','messages:apihelp-query+info-summary','s:30:\"en:Get basic page information.\";'),('en','messages:apihelp-query+iwbacklinks-example-generator','s:61:\"en:Get information about pages linking to [[wikibooks:Test]].\";'),('en','messages:apihelp-query+iwbacklinks-example-simple','s:43:\"en:Get pages linking to [[wikibooks:Test]].\";'),('en','messages:apihelp-query+iwbacklinks-extended-description','s:156:\"en:Can be used to find all links with a prefix, or all links to a title (with a given prefix). Using neither parameter is effectively \"all interwiki links\".\";'),('en','messages:apihelp-query+iwbacklinks-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+iwbacklinks-param-limit','s:34:\"en:How many total pages to return.\";'),('en','messages:apihelp-query+iwbacklinks-param-prefix','s:28:\"en:Prefix for the interwiki.\";'),('en','messages:apihelp-query+iwbacklinks-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+iwbacklinks-param-title','s:73:\"en:Interwiki link to search for. Must be used with <var>$1blprefix</var>.\";'),('en','messages:apihelp-query+iwbacklinks-paramvalue-prop-iwprefix','s:36:\"en:Adds the prefix of the interwiki.\";'),('en','messages:apihelp-query+iwbacklinks-paramvalue-prop-iwtitle','s:35:\"en:Adds the title of the interwiki.\";'),('en','messages:apihelp-query+iwbacklinks-summary','s:56:\"en:Find all pages that link to the given interwiki link.\";'),('en','messages:apihelp-query+iwlinks-example-simple','s:64:\"en:Get interwiki links from the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+iwlinks-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+iwlinks-param-limit','s:38:\"en:How many interwiki links to return.\";'),('en','messages:apihelp-query+iwlinks-param-prefix','s:48:\"en:Only return interwiki links with this prefix.\";'),('en','messages:apihelp-query+iwlinks-param-prop','s:62:\"en:Which additional properties to get for each interwiki link:\";'),('en','messages:apihelp-query+iwlinks-param-title','s:71:\"en:Interwiki link to search for. Must be used with <var>$1prefix</var>.\";'),('en','messages:apihelp-query+iwlinks-param-url','s:60:\"en:Whether to get the full URL (cannot be used with $1prop).\";'),('en','messages:apihelp-query+iwlinks-paramvalue-prop-url','s:21:\"en:Adds the full URL.\";'),('en','messages:apihelp-query+iwlinks-summary','s:52:\"en:Returns all interwiki links from the given pages.\";'),('en','messages:apihelp-query+langbacklinks-example-generator','s:55:\"en:Get information about pages linking to [[:fr:Test]].\";'),('en','messages:apihelp-query+langbacklinks-example-simple','s:37:\"en:Get pages linking to [[:fr:Test]].\";'),('en','messages:apihelp-query+langbacklinks-extended-description','s:233:\"en:Can be used to find all links with a language code, or all links to a title (with a given language). Using neither parameter is effectively \"all language links\".\n\nNote that this may not consider language links added by extensions.\";'),('en','messages:apihelp-query+langbacklinks-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+langbacklinks-param-lang','s:34:\"en:Language for the language link.\";'),('en','messages:apihelp-query+langbacklinks-param-limit','s:34:\"en:How many total pages to return.\";'),('en','messages:apihelp-query+langbacklinks-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+langbacklinks-param-title','s:57:\"en:Language link to search for. Must be used with $1lang.\";'),('en','messages:apihelp-query+langbacklinks-paramvalue-prop-lllang','s:47:\"en:Adds the language code of the language link.\";'),('en','messages:apihelp-query+langbacklinks-paramvalue-prop-lltitle','s:39:\"en:Adds the title of the language link.\";'),('en','messages:apihelp-query+langbacklinks-summary','s:55:\"en:Find all pages that link to the given language link.\";'),('en','messages:apihelp-query+langlinks-example-simple','s:68:\"en:Get interlanguage links from the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+langlinks-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+langlinks-param-inlanguagecode','s:46:\"en:Language code for localised language names.\";'),('en','messages:apihelp-query+langlinks-param-lang','s:54:\"en:Only return language links with this language code.\";'),('en','messages:apihelp-query+langlinks-param-limit','s:32:\"en:How many langlinks to return.\";'),('en','messages:apihelp-query+langlinks-param-prop','s:66:\"en:Which additional properties to get for each interlanguage link:\";'),('en','messages:apihelp-query+langlinks-param-title','s:59:\"en:Link to search for. Must be used with <var>$1lang</var>.\";'),('en','messages:apihelp-query+langlinks-param-url','s:71:\"en:Whether to get the full URL (cannot be used with <var>$1prop</var>).\";'),('en','messages:apihelp-query+langlinks-paramvalue-prop-autonym','s:33:\"en:Adds the native language name.\";'),('en','messages:apihelp-query+langlinks-paramvalue-prop-langname','s:107:\"en:Adds the localised language name (best effort). Use <var>$1inlanguagecode</var> to control the language.\";'),('en','messages:apihelp-query+langlinks-paramvalue-prop-url','s:21:\"en:Adds the full URL.\";'),('en','messages:apihelp-query+langlinks-summary','s:56:\"en:Returns all interlanguage links from the given pages.\";'),('en','messages:apihelp-query+languageinfo-example-autonym-name-de','s:64:\"en:Get the autonyms and German names of all supported languages.\";'),('en','messages:apihelp-query+languageinfo-example-bcp47-dir','s:73:\"en:Get the BCP-47 language code and direction of all supported languages.\";'),('en','messages:apihelp-query+languageinfo-example-fallbacks-variants-oc','s:54:\"en:Get the fallback languages and variants of Occitan.\";'),('en','messages:apihelp-query+languageinfo-example-simple','s:53:\"en:Get the language codes of all supported languages.\";'),('en','messages:apihelp-query+languageinfo-extended-description','s:131:\"en:[[mw:Special:MyLanguage/API:Continue|Continuation]] may be applied if retrieving the information takes too long for one request.\";'),('en','messages:apihelp-query+languageinfo-param-code','s:96:\"en:Language codes of the languages that should be returned, or <code>*</code> for all languages.\";'),('en','messages:apihelp-query+languageinfo-param-prop','s:46:\"en:Which information to get for each language.\";'),('en','messages:apihelp-query+languageinfo-paramvalue-prop-autonym','s:67:\"en:The autonym of the language, that is, the name in that language.\";'),('en','messages:apihelp-query+languageinfo-paramvalue-prop-bcp47','s:28:\"en:The BCP-47 language code.\";'),('en','messages:apihelp-query+languageinfo-paramvalue-prop-code','s:104:\"en:The language code. (This code is MediaWiki-specific, though there are overlaps with other standards.)\";'),('en','messages:apihelp-query+languageinfo-paramvalue-prop-dir','s:87:\"en:The writing direction of the language (either <code>ltr</code> or <code>rtl</code>).\";'),('en','messages:apihelp-query+languageinfo-paramvalue-prop-fallbacks','s:184:\"en:The language codes of the fallback languages configured for this language. The implicit final fallback to \'en\' is not included (but some languages may fall back to \'en\' explicitly).\";'),('en','messages:apihelp-query+languageinfo-paramvalue-prop-name','s:136:\"en:The name of the language in the language specified by the <var>uselang</var> parameter, with language fallbacks applied if necessary.\";'),('en','messages:apihelp-query+languageinfo-paramvalue-prop-variantnames','s:76:\"en:The short names for language variants used for language conversion links.\";'),('en','messages:apihelp-query+languageinfo-paramvalue-prop-variants','s:65:\"en:The language codes of the variants supported by this language.\";'),('en','messages:apihelp-query+languageinfo-summary','s:48:\"en:Return information about available languages.\";'),('en','messages:apihelp-query+links-example-generator','s:79:\"en:Get information about the link pages in the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+links-example-namespaces','s:104:\"en:Get links from the page [[{{MediaWiki:Mainpage}}]] in the {{ns:user}} and {{ns:template}} namespaces.\";'),('en','messages:apihelp-query+links-example-simple','s:53:\"en:Get links from the page [[{{MediaWiki:Mainpage}}]]\";'),('en','messages:apihelp-query+links-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+links-param-limit','s:28:\"en:How many links to return.\";'),('en','messages:apihelp-query+links-param-namespace','s:39:\"en:Show links in these namespaces only.\";'),('en','messages:apihelp-query+links-param-titles','s:104:\"en:Only list links to these titles. Useful for checking whether a certain page links to a certain title.\";'),('en','messages:apihelp-query+links-summary','s:42:\"en:Returns all links from the given pages.\";'),('en','messages:apihelp-query+linkshere-example-generator','s:73:\"en:Get information about pages linking to the [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+linkshere-example-simple','s:65:\"en:Get a list of pages linking to the [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+linkshere-param-limit','s:22:\"en:How many to return.\";'),('en','messages:apihelp-query+linkshere-param-namespace','s:42:\"en:Only include pages in these namespaces.\";'),('en','messages:apihelp-query+linkshere-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+linkshere-param-show','s:44:\"en:Show only items that meet these criteria:\";'),('en','messages:apihelp-query+linkshere-paramvalue-prop-pageid','s:24:\"en:Page ID of each page.\";'),('en','messages:apihelp-query+linkshere-paramvalue-prop-redirect','s:34:\"en:Flag if the page is a redirect.\";'),('en','messages:apihelp-query+linkshere-paramvalue-prop-title','s:22:\"en:Title of each page.\";'),('en','messages:apihelp-query+linkshere-paramvalue-show-!redirect','s:27:\"en:Only show non-redirects.\";'),('en','messages:apihelp-query+linkshere-paramvalue-show-redirect','s:23:\"en:Only show redirects.\";'),('en','messages:apihelp-query+linkshere-summary','s:47:\"en:Find all pages that link to the given pages.\";'),('en','messages:apihelp-query+logevents-example-simple','s:26:\"en:List recent log events.\";'),('en','messages:apihelp-query+logevents-param-action','s:213:\"en:Filter log actions to only this action. Overrides <var>$1type</var>. In the list of possible values, values with the asterisk wildcard such as <kbd>action/*</kbd> can have different strings after the slash (/).\";'),('en','messages:apihelp-query+logevents-param-end','s:36:\"en:The timestamp to end enumerating.\";'),('en','messages:apihelp-query+logevents-param-ids','s:56:\"en:Filter entries to those matching the given log ID(s).\";'),('en','messages:apihelp-query+logevents-param-limit','s:42:\"en:How many total event entries to return.\";'),('en','messages:apihelp-query+logevents-param-namespace','s:50:\"en:Filter entries to those in the given namespace.\";'),('en','messages:apihelp-query+logevents-param-prefix','s:46:\"en:Filter entries that start with this prefix.\";'),('en','messages:apihelp-query+logevents-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+logevents-param-start','s:43:\"en:The timestamp to start enumerating from.\";'),('en','messages:apihelp-query+logevents-param-tag','s:48:\"en:Only list event entries tagged with this tag.\";'),('en','messages:apihelp-query+logevents-param-title','s:45:\"en:Filter entries to those related to a page.\";'),('en','messages:apihelp-query+logevents-param-type','s:40:\"en:Filter log entries to only this type.\";'),('en','messages:apihelp-query+logevents-param-user','s:50:\"en:Filter entries to those made by the given user.\";'),('en','messages:apihelp-query+logevents-paramvalue-prop-comment','s:135:\"en:Adds the comment of the log event. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+logevents-paramvalue-prop-details','s:148:\"en:Lists additional details about the log event. If the log event has been revision deleted, an <samp>actionhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+logevents-paramvalue-prop-ids','s:32:\"en:Adds the ID of the log event.\";'),('en','messages:apihelp-query+logevents-paramvalue-prop-parsedcomment','s:142:\"en:Adds the parsed comment of the log event. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+logevents-paramvalue-prop-tags','s:32:\"en:Lists tags for the log event.\";'),('en','messages:apihelp-query+logevents-paramvalue-prop-timestamp','s:40:\"en:Adds the timestamp for the log event.\";'),('en','messages:apihelp-query+logevents-paramvalue-prop-title','s:48:\"en:Adds the title of the page for the log event.\";'),('en','messages:apihelp-query+logevents-paramvalue-prop-type','s:30:\"en:Adds the type of log event.\";'),('en','messages:apihelp-query+logevents-paramvalue-prop-user','s:139:\"en:Adds the user responsible for the log event. If the user has been revision deleted, a <samp>userhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+logevents-paramvalue-prop-userid','s:150:\"en:Adds the user ID who was responsible for the log event. If the user has been revision deleted, a <samp>userhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+logevents-summary','s:24:\"en:Get events from logs.\";'),('en','messages:apihelp-query+mystashedfiles-example-simple','s:90:\"en:Get the filekey, file size, and pixel size of files in the current user\'s upload stash.\";'),('en','messages:apihelp-query+mystashedfiles-param-limit','s:25:\"en:How many files to get.\";'),('en','messages:apihelp-query+mystashedfiles-param-prop','s:43:\"en:Which properties to fetch for the files.\";'),('en','messages:apihelp-query+mystashedfiles-paramvalue-prop-size','s:44:\"en:Fetch the file size and image dimensions.\";'),('en','messages:apihelp-query+mystashedfiles-paramvalue-prop-type','s:45:\"en:Fetch the file\'s MIME type and media type.\";'),('en','messages:apihelp-query+mystashedfiles-summary','s:58:\"en:Get a list of files in the current user\'s upload stash.\";'),('en','messages:apihelp-query+pagepropnames-example-simple','s:31:\"en:Get first 10 property names.\";'),('en','messages:apihelp-query+pagepropnames-param-limit','s:41:\"en:The maximum number of names to return.\";'),('en','messages:apihelp-query+pagepropnames-summary','s:51:\"en:List all page property names in use on the wiki.\";'),('en','messages:apihelp-query+pageprops-example-simple','s:91:\"en:Get properties for the pages <kbd>{{MediaWiki:Mainpage}}</kbd> and <kbd>MediaWiki</kbd>.\";'),('en','messages:apihelp-query+pageprops-param-prop','s:218:\"en:Only list these page properties (<kbd>[[Special:ApiHelp/query+pagepropnames|action=query&list=pagepropnames]]</kbd> returns page property names in use). Useful for checking whether pages use a certain page property.\";'),('en','messages:apihelp-query+pageprops-summary','s:59:\"en:Get various page properties defined in the page content.\";'),('en','messages:apihelp-query+pageswithprop-example-generator','s:92:\"en:Get additional information about the first 10 pages using <code>_&#95;NOTOC_&#95;</code>.\";'),('en','messages:apihelp-query+pageswithprop-example-simple','s:84:\"en:List the first 10 pages using <code>&#123;&#123;DISPLAYTITLE:&#125;&#125;</code>.\";'),('en','messages:apihelp-query+pageswithprop-param-dir','s:30:\"en:In which direction to sort.\";'),('en','messages:apihelp-query+pageswithprop-param-limit','s:41:\"en:The maximum number of pages to return.\";'),('en','messages:apihelp-query+pageswithprop-param-prop','s:42:\"en:Which pieces of information to include:\";'),('en','messages:apihelp-query+pageswithprop-param-propname','s:166:\"en:Page property for which to enumerate pages (<kbd>[[Special:ApiHelp/query+pagepropnames|action=query&list=pagepropnames]]</kbd> returns page property names in use).\";'),('en','messages:apihelp-query+pageswithprop-paramvalue-prop-ids','s:20:\"en:Adds the page ID.\";'),('en','messages:apihelp-query+pageswithprop-paramvalue-prop-title','s:47:\"en:Adds the title and namespace ID of the page.\";'),('en','messages:apihelp-query+pageswithprop-paramvalue-prop-value','s:39:\"en:Adds the value of the page property.\";'),('en','messages:apihelp-query+pageswithprop-summary','s:46:\"en:List all pages using a given page property.\";'),('en','messages:apihelp-query+prefixsearch-example-simple','s:60:\"en:Search for page titles beginning with <kbd>meaning</kbd>.\";'),('en','messages:apihelp-query+prefixsearch-extended-description','s:511:\"en:Despite the similarity in names, this module is not intended to be equivalent to [[Special:PrefixIndex]]; for that, see <kbd>[[Special:ApiHelp/query+allpages|action=query&list=allpages]]</kbd> with the <kbd>apprefix</kbd> parameter. The purpose of this module is similar to <kbd>[[Special:ApiHelp/opensearch|action=opensearch]]</kbd>: to take user input and provide the best-matching titles. Depending on the search engine backend, this might include typo correction, redirect avoidance, or other heuristics.\";'),('en','messages:apihelp-query+prefixsearch-param-limit','s:39:\"en:Maximum number of results to return.\";'),('en','messages:apihelp-query+prefixsearch-param-namespace','s:93:\"en:Namespaces to search. Ignored if <var>$1search</var> begins with a valid namespace prefix.\";'),('en','messages:apihelp-query+prefixsearch-param-offset','s:29:\"en:Number of results to skip.\";'),('en','messages:apihelp-query+prefixsearch-param-profile','s:25:\"en:Search profile to use.\";'),('en','messages:apihelp-query+prefixsearch-param-search','s:17:\"en:Search string.\";'),('en','messages:apihelp-query+prefixsearch-summary','s:43:\"en:Perform a prefix search for page titles.\";'),('en','messages:apihelp-query+protectedtitles-example-generator','s:56:\"en:Find links to protected titles in the main namespace.\";'),('en','messages:apihelp-query+protectedtitles-example-simple','s:25:\"en:List protected titles.\";'),('en','messages:apihelp-query+protectedtitles-param-end','s:45:\"en:Stop listing at this protection timestamp.\";'),('en','messages:apihelp-query+protectedtitles-param-level','s:49:\"en:Only list titles with these protection levels.\";'),('en','messages:apihelp-query+protectedtitles-param-limit','s:34:\"en:How many total pages to return.\";'),('en','messages:apihelp-query+protectedtitles-param-namespace','s:40:\"en:Only list titles in these namespaces.\";'),('en','messages:apihelp-query+protectedtitles-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+protectedtitles-param-start','s:46:\"en:Start listing at this protection timestamp.\";'),('en','messages:apihelp-query+protectedtitles-paramvalue-prop-comment','s:39:\"en:Adds the comment for the protection.\";'),('en','messages:apihelp-query+protectedtitles-paramvalue-prop-expiry','s:60:\"en:Adds the timestamp of when the protection will be lifted.\";'),('en','messages:apihelp-query+protectedtitles-paramvalue-prop-level','s:29:\"en:Adds the protection level.\";'),('en','messages:apihelp-query+protectedtitles-paramvalue-prop-parsedcomment','s:46:\"en:Adds the parsed comment for the protection.\";'),('en','messages:apihelp-query+protectedtitles-paramvalue-prop-timestamp','s:51:\"en:Adds the timestamp of when protection was added.\";'),('en','messages:apihelp-query+protectedtitles-paramvalue-prop-user','s:43:\"en:Adds the user that added the protection.\";'),('en','messages:apihelp-query+protectedtitles-paramvalue-prop-userid','s:46:\"en:Adds the user ID that added the protection.\";'),('en','messages:apihelp-query+protectedtitles-summary','s:43:\"en:List all titles protected from creation.\";'),('en','messages:apihelp-query+querypage-example-ancientpages','s:48:\"en:Return results from [[Special:Ancientpages]].\";'),('en','messages:apihelp-query+querypage-param-limit','s:31:\"en:Number of results to return.\";'),('en','messages:apihelp-query+querypage-param-page','s:62:\"en:The name of the special page. Note, this is case-sensitive.\";'),('en','messages:apihelp-query+querypage-summary','s:57:\"en:Get a list provided by a QueryPage-based special page.\";'),('en','messages:apihelp-query+random-example-generator','s:67:\"en:Return page info about two random pages from the main namespace.\";'),('en','messages:apihelp-query+random-example-minsize','s:102:\"en:Return page info about one random page from the main namespace that has at least 500 bytes of text.\";'),('en','messages:apihelp-query+random-example-simple','s:51:\"en:Return two random pages from the main namespace.\";'),('en','messages:apihelp-query+random-extended-description','s:301:\"en:Pages are listed in a fixed sequence, only the starting point is random. This means that if, for example, <samp>Main Page</samp> is the first random page in the list, <samp>List of fictional monkeys</samp> will <em>always</em> be second, <samp>List of people on stamps of Vanuatu</samp> third, etc.\";'),('en','messages:apihelp-query+random-param-contentmodel','s:54:\"en:Filter pages that have the specified content model.\";'),('en','messages:apihelp-query+random-param-filterredir','s:31:\"en:How to filter for redirects.\";'),('en','messages:apihelp-query+random-param-limit','s:48:\"en:Limit how many random pages will be returned.\";'),('en','messages:apihelp-query+random-param-maxsize','s:47:\"en:Limit to pages with at most this many bytes.\";'),('en','messages:apihelp-query+random-param-minsize','s:48:\"en:Limit to pages with at least this many bytes.\";'),('en','messages:apihelp-query+random-param-namespace','s:41:\"en:Return pages in these namespaces only.\";'),('en','messages:apihelp-query+random-param-redirect','s:50:\"en:Use <kbd>$1filterredir=redirects</kbd> instead.\";'),('en','messages:apihelp-query+random-summary','s:29:\"en:Get a set of random pages.\";'),('en','messages:apihelp-query+recentchanges-example-generator','s:50:\"en:Get page info about recent unpatrolled changes.\";'),('en','messages:apihelp-query+recentchanges-example-simple','s:23:\"en:List recent changes.\";'),('en','messages:apihelp-query+recentchanges-param-end','s:36:\"en:The timestamp to end enumerating.\";'),('en','messages:apihelp-query+recentchanges-param-excludeuser','s:35:\"en:Don\'t list changes by this user.\";'),('en','messages:apihelp-query+recentchanges-param-generaterevisions','s:177:\"en:When being used as a generator, generate revision IDs rather than titles. Recent change entries without associated revision IDs (e.g. most log entries) will generate nothing.\";'),('en','messages:apihelp-query+recentchanges-param-limit','s:36:\"en:How many total changes to return.\";'),('en','messages:apihelp-query+recentchanges-param-namespace','s:43:\"en:Filter changes to only these namespaces.\";'),('en','messages:apihelp-query+recentchanges-param-prop','s:44:\"en:Include additional pieces of information:\";'),('en','messages:apihelp-query+recentchanges-param-show','s:130:\"en:Show only items that meet these criteria. For example, to see only minor edits done by logged-in users, set $1show=minor|!anon.\";'),('en','messages:apihelp-query+recentchanges-param-slot','s:47:\"en:Only list changes that touch the named slot.\";'),('en','messages:apihelp-query+recentchanges-param-start','s:43:\"en:The timestamp to start enumerating from.\";'),('en','messages:apihelp-query+recentchanges-param-tag','s:42:\"en:Only list changes tagged with this tag.\";'),('en','messages:apihelp-query+recentchanges-param-title','s:45:\"en:Filter entries to those related to a page.\";'),('en','messages:apihelp-query+recentchanges-param-toponly','s:51:\"en:Only list changes which are the latest revision.\";'),('en','messages:apihelp-query+recentchanges-param-type','s:34:\"en:Which types of changes to show.\";'),('en','messages:apihelp-query+recentchanges-param-user','s:34:\"en:Only list changes by this user.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-autopatrolled','s:56:\"en:Tags patrollable edits as being autopatrolled or not.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-comment','s:131:\"en:Adds the comment for the edit. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-flags','s:27:\"en:Adds flags for the edit.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-ids','s:71:\"en:Adds the page ID, recent changes ID and the new and old revision ID.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-loginfo','s:63:\"en:Adds log information (log ID, log type, etc) to log entries.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-parsedcomment','s:138:\"en:Adds the parsed comment for the edit. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-patrolled','s:60:\"en:Tags patrollable edits as being patrolled or unpatrolled.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-redirect','s:35:\"en:Tags edit if page is a redirect.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-sha1','s:163:\"en:Adds the content checksum for entries associated with a revision. If the content has been revision deleted, a <samp>sha1hidden</samp> property will be returned.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-sizes','s:45:\"en:Adds the new and old page length in bytes.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-tags','s:28:\"en:Lists tags for the entry.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-timestamp','s:30:\"en:Adds timestamp of the edit.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-title','s:35:\"en:Adds the page title of the edit.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-user','s:161:\"en:Adds the user responsible for the edit and tags if they are an IP. If the user has been revision deleted, a <samp>userhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+recentchanges-paramvalue-prop-userid','s:137:\"en:Adds the user ID responsible for the edit. If the user has been revision deleted, a <samp>userhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+recentchanges-summary','s:28:\"en:Enumerate recent changes.\";'),('en','messages:apihelp-query+redirects-example-generator','s:73:\"en:Get information about all redirects to the [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+redirects-example-simple','s:61:\"en:Get a list of redirects to the [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+redirects-param-limit','s:32:\"en:How many redirects to return.\";'),('en','messages:apihelp-query+redirects-param-namespace','s:42:\"en:Only include pages in these namespaces.\";'),('en','messages:apihelp-query+redirects-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+redirects-param-show','s:44:\"en:Show only items that meet these criteria:\";'),('en','messages:apihelp-query+redirects-paramvalue-prop-fragment','s:37:\"en:Fragment of each redirect, if any.\";'),('en','messages:apihelp-query+redirects-paramvalue-prop-pageid','s:28:\"en:Page ID of each redirect.\";'),('en','messages:apihelp-query+redirects-paramvalue-prop-title','s:26:\"en:Title of each redirect.\";'),('en','messages:apihelp-query+redirects-paramvalue-show-!fragment','s:42:\"en:Only show redirects without a fragment.\";'),('en','messages:apihelp-query+redirects-paramvalue-show-fragment','s:39:\"en:Only show redirects with a fragment.\";'),('en','messages:apihelp-query+redirects-summary','s:44:\"en:Returns all redirects to the given pages.\";'),('en','messages:apihelp-query+revisions+base-param-contentformat','s:92:\"en:Serialization format used for <var>$1difftotext</var> and expected for output of content.\";'),('en','messages:apihelp-query+revisions+base-param-contentformat-slot','s:59:\"en:Content serialization format used for output of content.\";'),('en','messages:apihelp-query+revisions+base-param-diffto','s:308:\"en:Use <kbd>[[Special:ApiHelp/compare|action=compare]]</kbd> instead. Revision ID to diff each revision to. Use <kbd>prev</kbd>, <kbd>next</kbd> and <kbd>cur</kbd> for the previous, next and current revision respectively. For performance reasons, if this option is used, <var>$2limit</var> is enforced to $1.\";'),('en','messages:apihelp-query+revisions+base-param-difftotext','s:344:\"en:Use <kbd>[[Special:ApiHelp/compare|action=compare]]</kbd> instead. Text to diff each revision to. Only diffs a limited number of revisions. Overrides <var>$2diffto</var>. If <var>$2section</var> is set, only that section will be diffed against this text. For performance reasons, if this option is used, <var>$2limit</var> is enforced to $1.\";'),('en','messages:apihelp-query+revisions+base-param-difftotextpst','s:180:\"en:Use <kbd>[[Special:ApiHelp/compare|action=compare]]</kbd> instead. Perform a pre-save transform on the text before diffing it. Only valid when used with <var>$1difftotext</var>.\";'),('en','messages:apihelp-query+revisions+base-param-expandtemplates','s:149:\"en:Use <kbd>[[Special:ApiHelp/expandtemplates|action=expandtemplates]]</kbd> instead. Expand templates in revision content (requires $1prop=content).\";'),('en','messages:apihelp-query+revisions+base-param-generatexml','s:210:\"en:Use <kbd>[[Special:ApiHelp/expandtemplates|action=expandtemplates]]</kbd> or <kbd>[[Special:ApiHelp/parse|action=parse]]</kbd> instead. Generate XML parse tree for revision content (requires $1prop=content).\";'),('en','messages:apihelp-query+revisions+base-param-limit','s:225:\"en:Limit how many revisions will be returned. If <var>$3prop=content</var>, <var>$3prop=parsetree</var>, <var>$3diffto</var> or <var>$3difftotext</var> is used, the limit is $1. If <var>$3parse</var> is used, the limit is $2.\";'),('en','messages:apihelp-query+revisions+base-param-parse','s:213:\"en:Use <kbd>[[Special:ApiHelp/parse|action=parse]]</kbd> instead. Parse revision content (requires <var>$2prop=content</var>). For performance reasons, if this option is used, <var>$2limit</var> is enforced to $1.\";'),('en','messages:apihelp-query+revisions+base-param-prop','s:45:\"en:Which properties to get for each revision:\";'),('en','messages:apihelp-query+revisions+base-param-section','s:65:\"en:Only retrieve the content of the section with this identifier.\";'),('en','messages:apihelp-query+revisions+base-param-slots','s:206:\"en:Which revision slots to return data for, when slot-related properties are included in <var>$1props</var>. If omitted, data from the <kbd>main</kbd> slot will be returned in a backwards-compatible format.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-comment','s:138:\"en:Comment by the user for the revision. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-content','s:215:\"en:Content of each revision slot. If the content has been revision deleted, a <samp>texthidden</samp> property will be returned. For performance reasons, if this option is used, <var>$2limit</var> is enforced to $1.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-contentmodel','s:42:\"en:Content model ID of each revision slot.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-flags','s:26:\"en:Revision flags (minor).\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-ids','s:26:\"en:The ID of the revision.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-parsedcomment','s:145:\"en:Parsed comment by the user for the revision. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-parsetree','s:306:\"en:Use <kbd>[[Special:ApiHelp/expandtemplates|action=expandtemplates]]</kbd> or <kbd>[[Special:ApiHelp/parse|action=parse]]</kbd> instead. The XML parse tree of revision content (requires content model <code>$1</code>). For performance reasons, if this option is used, <var>$3limit</var> is enforced to $2.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-roles','s:54:\"en:List content slot roles that exist in the revision.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-sha1','s:130:\"en:SHA-1 (base 16) of the revision. If the content has been revision deleted, a <samp>sha1hidden</samp> property will be returned.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-size','s:34:\"en:Length (bytes) of the revision.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-slotsha1','s:136:\"en:SHA-1 (base 16) of each revision slot. If the content has been revision deleted, a <samp>sha1hidden</samp> property will be returned.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-slotsize','s:40:\"en:Length (bytes) of each revision slot.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-tags','s:25:\"en:Tags for the revision.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-timestamp','s:33:\"en:The timestamp of the revision.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-user','s:123:\"en:User that made the revision. If the user has been revision deleted, a <samp>userhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+revisions+base-paramvalue-prop-userid','s:127:\"en:User ID of the revision creator. If the user has been revision deleted, a <samp>userhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+revisions-example-content','s:103:\"en:Get data with content for the last revision of titles <kbd>API</kbd> and [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+revisions-example-first5','s:59:\"en:Get first 5 revisions of the [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+revisions-example-first5-after','s:81:\"en:Get first 5 revisions of the [[{{MediaWiki:Mainpage}}]] made after 2006-05-01.\";'),('en','messages:apihelp-query+revisions-example-first5-not-localhost','s:117:\"en:Get first 5 revisions of the [[{{MediaWiki:Mainpage}}]] that were not made by anonymous user <kbd>127.0.0.1</kbd>.\";'),('en','messages:apihelp-query+revisions-example-first5-user','s:115:\"en:Get first 5 revisions of the [[{{MediaWiki:Mainpage}}]] that were made by the user <kbd>MediaWiki default</kbd>.\";'),('en','messages:apihelp-query+revisions-example-last5','s:58:\"en:Get last 5 revisions of the [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+revisions-extended-description','s:270:\"en:May be used in several ways:\n# Get data about a set of pages (last revision), by setting titles or pageids.\n# Get revisions for one given page, by using titles or pageids with start, end, or limit.\n# Get data about a set of revisions by setting their IDs with revids.\";'),('en','messages:apihelp-query+revisions-param-end','s:34:\"en:Enumerate up to this timestamp.\";'),('en','messages:apihelp-query+revisions-param-endid','s:125:\"en:Stop enumeration at the timestamp of the revision with this ID. The revision must exist, but need not belong to this page.\";'),('en','messages:apihelp-query+revisions-param-excludeuser','s:34:\"en:Exclude revisions made by user.\";'),('en','messages:apihelp-query+revisions-param-start','s:54:\"en:From which revision timestamp to start enumeration.\";'),('en','messages:apihelp-query+revisions-param-startid','s:128:\"en:Start enumeration from the timestamp of the revision with this ID. The revision must exist, but need not belong to this page.\";'),('en','messages:apihelp-query+revisions-param-tag','s:44:\"en:Only list revisions tagged with this tag.\";'),('en','messages:apihelp-query+revisions-param-user','s:39:\"en:Only include revisions made by user.\";'),('en','messages:apihelp-query+revisions-paraminfo-singlepageonly','s:49:\"en:May only be used with a single page (mode #2).\";'),('en','messages:apihelp-query+revisions-summary','s:28:\"en:Get revision information.\";'),('en','messages:apihelp-query+search-example-generator','s:78:\"en:Get page info about the pages returned for a search for <kbd>meaning</kbd>.\";'),('en','messages:apihelp-query+search-example-simple','s:33:\"en:Search for <kbd>meaning</kbd>.\";'),('en','messages:apihelp-query+search-example-text','s:39:\"en:Search texts for <kbd>meaning</kbd>.\";'),('en','messages:apihelp-query+search-param-backend','s:51:\"en:Which search backend to use, if not the default.\";'),('en','messages:apihelp-query+search-param-enablerewrites','s:179:\"en:Enable internal query rewriting. Some search backends can rewrite the query into another which is thought to provide better results, for instance by correcting spelling errors.\";'),('en','messages:apihelp-query+search-param-info','s:28:\"en:Which metadata to return.\";'),('en','messages:apihelp-query+search-param-interwiki','s:57:\"en:Include interwiki results in the search, if available.\";'),('en','messages:apihelp-query+search-param-limit','s:34:\"en:How many total pages to return.\";'),('en','messages:apihelp-query+search-param-namespace','s:39:\"en:Search only within these namespaces.\";'),('en','messages:apihelp-query+search-param-prop','s:30:\"en:Which properties to return:\";'),('en','messages:apihelp-query+search-param-qdprofile','s:62:\"en:Query dependent profile to use (affects ranking algorithm).\";'),('en','messages:apihelp-query+search-param-qiprofile','s:64:\"en:Query independent profile to use (affects ranking algorithm).\";'),('en','messages:apihelp-query+search-param-search','s:178:\"en:Search for page titles or content matching this value. You can use the search string to invoke special search features, depending on what the wiki\'s search backend implements.\";'),('en','messages:apihelp-query+search-param-sort','s:42:\"en:Set the sort order of returned results.\";'),('en','messages:apihelp-query+search-param-what','s:35:\"en:Which type of search to perform.\";'),('en','messages:apihelp-query+search-paramvalue-prop-categorysnippet','s:72:\"en:Adds the matching category name, with query term highlighting markup.\";'),('en','messages:apihelp-query+search-paramvalue-prop-extensiondata','s:43:\"en:Adds extra data generated by extensions.\";'),('en','messages:apihelp-query+search-paramvalue-prop-hasrelated','s:11:\"en:Ignored.\";'),('en','messages:apihelp-query+search-paramvalue-prop-isfilematch','s:64:\"en:Adds a boolean indicating if the search matched file content.\";'),('en','messages:apihelp-query+search-paramvalue-prop-redirectsnippet','s:80:\"en:Adds the title of the matching redirect, with query term highlighting markup.\";'),('en','messages:apihelp-query+search-paramvalue-prop-redirecttitle','s:43:\"en:Adds the title of the matching redirect.\";'),('en','messages:apihelp-query+search-paramvalue-prop-score','s:11:\"en:Ignored.\";'),('en','messages:apihelp-query+search-paramvalue-prop-sectionsnippet','s:79:\"en:Adds the title of the matching section, with query term highlighting markup.\";'),('en','messages:apihelp-query+search-paramvalue-prop-sectiontitle','s:42:\"en:Adds the title of the matching section.\";'),('en','messages:apihelp-query+search-paramvalue-prop-size','s:38:\"en:Adds the size of the page in bytes.\";'),('en','messages:apihelp-query+search-paramvalue-prop-snippet','s:67:\"en:Adds a snippet of the page, with query term highlighting markup.\";'),('en','messages:apihelp-query+search-paramvalue-prop-timestamp','s:55:\"en:Adds the timestamp of when the page was last edited.\";'),('en','messages:apihelp-query+search-paramvalue-prop-titlesnippet','s:60:\"en:Adds the page title, with query term highlighting markup.\";'),('en','messages:apihelp-query+search-paramvalue-prop-wordcount','s:35:\"en:Adds the word count of the page.\";'),('en','messages:apihelp-query+search-summary','s:30:\"en:Perform a full text search.\";'),('en','messages:apihelp-query+siteinfo-example-interwiki','s:44:\"en:Fetch a list of local interwiki prefixes.\";'),('en','messages:apihelp-query+siteinfo-example-replag','s:37:\"en:Check the current replication lag.\";'),('en','messages:apihelp-query+siteinfo-example-simple','s:26:\"en:Fetch site information.\";'),('en','messages:apihelp-query+siteinfo-param-filteriw','s:67:\"en:Return only local or only nonlocal entries of the interwiki map.\";'),('en','messages:apihelp-query+siteinfo-param-inlanguagecode','s:75:\"en:Language code for localised language names (best effort) and skin names.\";'),('en','messages:apihelp-query+siteinfo-param-numberingroup','s:44:\"en:Lists the number of users in user groups.\";'),('en','messages:apihelp-query+siteinfo-param-prop','s:28:\"en:Which information to get:\";'),('en','messages:apihelp-query+siteinfo-param-showalldb','s:64:\"en:List all database servers, not just the one lagging the most.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-autocreatetempuser','s:106:\"en:Returns configuration for the automatic creation of temporary user accounts (also known as IP masking).\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-autopromote','s:49:\"en:Returns the automatic promotion configuration.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-autopromoteonce','s:73:\"en:Returns the automatic promotion configuration that are only done once.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-clientlibraries','s:54:\"en:Returns client-side libraries installed on the wiki\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-copyuploaddomains','s:50:\"en:Returns the list of allowed copy upload domains\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-dbrepllag','s:60:\"en:Returns database server with the highest replication lag.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-defaultoptions','s:51:\"en:Returns the default values for user preferences.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-extensions','s:44:\"en:Returns extensions installed on the wiki.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-extensiontags','s:43:\"en:Returns a list of parser extension tags.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-fileextensions','s:71:\"en:Returns list of file extensions (file types) allowed to be uploaded.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-functionhooks','s:43:\"en:Returns a list of parser function hooks.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-general','s:30:\"en:Overall system information.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-interwikimap','s:106:\"en:Returns interwiki map (optionally filtered, optionally localised by using <var>$1inlanguagecode</var>).\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-languages','s:110:\"en:Returns a list of languages MediaWiki supports (optionally localised by using <var>$1inlanguagecode</var>).\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-languagevariants','s:156:\"en:Returns a list of language codes for which [[mw:Special:MyLanguage/LanguageConverter|LanguageConverter]] is enabled, and the variants supported for each.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-libraries','s:43:\"en:Returns libraries installed on the wiki.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-magicwords','s:41:\"en:List of magic words and their aliases.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-namespacealiases','s:40:\"en:List of registered namespace aliases.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-namespaces','s:59:\"en:List of registered namespaces and their canonical names.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-protocols','s:66:\"en:Returns a list of protocols that are allowed in external links.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-restrictions','s:67:\"en:Returns information on available restriction (protection) types.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-rightsinfo','s:58:\"en:Returns wiki rights (license) information if available.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-showhooks','s:118:\"en:Returns a list of all subscribed hooks (contents of <var>[[mw:Special:MyLanguage/Manual:$wgHooks|$wgHooks]]</var>).\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-skins','s:134:\"en:Returns a list of all enabled skins (optionally localised by using <var>$1inlanguagecode</var>, otherwise in the content language).\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-specialpagealiases','s:32:\"en:List of special page aliases.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-statistics','s:27:\"en:Returns site statistics.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-uploaddialog','s:43:\"en:Returns the upload dialog configuration.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-usergroups','s:54:\"en:Returns user groups and the associated permissions.\";'),('en','messages:apihelp-query+siteinfo-paramvalue-prop-variables','s:34:\"en:Returns a list of variable IDs.\";'),('en','messages:apihelp-query+siteinfo-summary','s:45:\"en:Return general information about the site.\";'),('en','messages:apihelp-query+stashimageinfo-example-params','s:44:\"en:Returns thumbnails for two stashed files.\";'),('en','messages:apihelp-query+stashimageinfo-example-simple','s:42:\"en:Returns information for a stashed file.\";'),('en','messages:apihelp-query+stashimageinfo-param-filekey','s:70:\"en:Key that identifies a previous upload that was stashed temporarily.\";'),('en','messages:apihelp-query+stashimageinfo-param-sessionkey','s:51:\"en:Alias for $1filekey, for backward compatibility.\";'),('en','messages:apihelp-query+stashimageinfo-summary','s:46:\"en:Returns file information for stashed files.\";'),('en','messages:apihelp-query+tags-example-simple','s:23:\"en:List available tags.\";'),('en','messages:apihelp-query+tags-param-limit','s:38:\"en:The maximum number of tags to list.\";'),('en','messages:apihelp-query+tags-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+tags-paramvalue-prop-active','s:42:\"en:Whether the tag is still being applied.\";'),('en','messages:apihelp-query+tags-paramvalue-prop-defined','s:39:\"en:Indicate whether the tag is defined.\";'),('en','messages:apihelp-query+tags-paramvalue-prop-description','s:31:\"en:Adds description of the tag.\";'),('en','messages:apihelp-query+tags-paramvalue-prop-displayname','s:35:\"en:Adds system message for the tag.\";'),('en','messages:apihelp-query+tags-paramvalue-prop-hitcount','s:67:\"en:Adds the number of revisions and log entries that have this tag.\";'),('en','messages:apihelp-query+tags-paramvalue-prop-name','s:20:\"en:Adds name of tag.\";'),('en','messages:apihelp-query+tags-paramvalue-prop-source','s:171:\"en:Gets the sources of the tag, which may include <samp>extension</samp> for extension-defined tags and <samp>manual</samp> for tags that may be applied manually by users.\";'),('en','messages:apihelp-query+tags-summary','s:20:\"en:List change tags.\";'),('en','messages:apihelp-query+templates-example-generator','s:88:\"en:Get information about the template pages used on the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+templates-example-namespaces','s:123:\"en:Get pages in the {{ns:user}} and {{ns:template}} namespaces that are transcluded on the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+templates-example-simple','s:65:\"en:Get the templates used on the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+templates-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+templates-param-limit','s:32:\"en:How many templates to return.\";'),('en','messages:apihelp-query+templates-param-namespace','s:43:\"en:Show templates in these namespaces only.\";'),('en','messages:apihelp-query+templates-param-templates','s:97:\"en:Only list these templates. Useful for checking whether a certain page uses a certain template.\";'),('en','messages:apihelp-query+templates-summary','s:52:\"en:Returns all pages transcluded on the given pages.\";'),('en','messages:apihelp-query+tokens-example-simple','s:39:\"en:Retrieve a csrf token (the default).\";'),('en','messages:apihelp-query+tokens-example-types','s:45:\"en:Retrieve a watch token and a patrol token.\";'),('en','messages:apihelp-query+tokens-param-type','s:29:\"en:Types of token to request.\";'),('en','messages:apihelp-query+tokens-summary','s:42:\"en:Gets tokens for data-modifying actions.\";'),('en','messages:apihelp-query+trackingcategories-example-generator','s:114:\"en:Retrieve info about the tracking category pages representing the broken-file-category themselves, if they exist\";'),('en','messages:apihelp-query+trackingcategories-example-size','s:76:\"en:List tracking categories with information on the number of pages in each.\";'),('en','messages:apihelp-query+trackingcategories-param-limit','s:42:\"en:How many tracking categories to return.\";'),('en','messages:apihelp-query+trackingcategories-param-max','s:75:\"en:Only return existing tracking categories with at most this many members.\";'),('en','messages:apihelp-query+trackingcategories-param-min','s:76:\"en:Only return existing tracking categories with at least this many members.\";'),('en','messages:apihelp-query+trackingcategories-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+trackingcategories-param-trackingcatname','s:164:\"en:Search for all existing tracking category titles that match the provided tracking category name (as defined by \"message name\" on [[Special:TrackingCategories]].)\";'),('en','messages:apihelp-query+trackingcategories-paramvalue-prop-hidden','s:84:\"en:Tags tracking categories that are hidden with <code>_&#95;HIDDENCAT_&#95;</code>.\";'),('en','messages:apihelp-query+trackingcategories-paramvalue-prop-size','s:49:\"en:Adds number of pages in the tracking category.\";'),('en','messages:apihelp-query+trackingcategories-summary','s:168:\"en:Enumerate all existing tracking categories defined in [[Special:TrackingCategories]]. A tracking category exists if it contains pages or if its category page exists.\";'),('en','messages:apihelp-query+transcludedin-example-generator','s:71:\"en:Get information about pages transcluding [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+transcludedin-example-simple','s:63:\"en:Get a list of pages transcluding [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query+transcludedin-param-limit','s:22:\"en:How many to return.\";'),('en','messages:apihelp-query+transcludedin-param-namespace','s:42:\"en:Only include pages in these namespaces.\";'),('en','messages:apihelp-query+transcludedin-param-prop','s:27:\"en:Which properties to get:\";'),('en','messages:apihelp-query+transcludedin-param-show','s:44:\"en:Show only items that meet these criteria:\";'),('en','messages:apihelp-query+transcludedin-paramvalue-prop-pageid','s:24:\"en:Page ID of each page.\";'),('en','messages:apihelp-query+transcludedin-paramvalue-prop-redirect','s:34:\"en:Flag if the page is a redirect.\";'),('en','messages:apihelp-query+transcludedin-paramvalue-prop-title','s:22:\"en:Title of each page.\";'),('en','messages:apihelp-query+transcludedin-paramvalue-show-!redirect','s:27:\"en:Only show non-redirects.\";'),('en','messages:apihelp-query+transcludedin-paramvalue-show-redirect','s:23:\"en:Only show redirects.\";'),('en','messages:apihelp-query+transcludedin-summary','s:50:\"en:Find all pages that transclude the given pages.\";'),('en','messages:apihelp-query+usercontribs-example-ipprefix','s:76:\"en:Show contributions from all IP addresses with prefix <kbd>192.0.2.</kbd>.\";'),('en','messages:apihelp-query+usercontribs-example-user','s:49:\"en:Show contributions of user <kbd>Example</kbd>.\";'),('en','messages:apihelp-query+usercontribs-param-end','s:71:\"en:The end timestamp to return to, i.e. revisions after this timestamp.\";'),('en','messages:apihelp-query+usercontribs-param-iprange','s:137:\"en:The CIDR range to retrieve contributions for. Cannot be used with <var>$1user</var>, <var>$1userprefix</var>, or <var>$1userids</var>.\";'),('en','messages:apihelp-query+usercontribs-param-limit','s:49:\"en:The maximum number of contributions to return.\";'),('en','messages:apihelp-query+usercontribs-param-namespace','s:47:\"en:Only list contributions in these namespaces.\";'),('en','messages:apihelp-query+usercontribs-param-prop','s:44:\"en:Include additional pieces of information:\";'),('en','messages:apihelp-query+usercontribs-param-show','s:308:\"en:Show only items that meet these criteria, e.g. non minor edits only: <kbd>$2show=!minor</kbd>.\n\nIf <kbd>$2show=patrolled</kbd> or <kbd>$2show=!patrolled</kbd> is set, revisions older than <var>[[mw:Special:MyLanguage/Manual:$wgRCMaxAge|$wgRCMaxAge]]</var> ($1 {{PLURAL:$1|second|seconds}}) won\'t be shown.\";'),('en','messages:apihelp-query+usercontribs-param-start','s:76:\"en:The start timestamp to return from, i.e. revisions before this timestamp.\";'),('en','messages:apihelp-query+usercontribs-param-tag','s:44:\"en:Only list revisions tagged with this tag.\";'),('en','messages:apihelp-query+usercontribs-param-toponly','s:51:\"en:Only list changes which are the latest revision.\";'),('en','messages:apihelp-query+usercontribs-param-user','s:135:\"en:The users to retrieve contributions for. Cannot be used with <var>$1userids</var>, <var>$1userprefix</var>, or <var>$1iprange</var>.\";'),('en','messages:apihelp-query+usercontribs-param-userids','s:135:\"en:The user IDs to retrieve contributions for. Cannot be used with <var>$1user</var>, <var>$1userprefix</var>, or <var>$1iprange</var>.\";'),('en','messages:apihelp-query+usercontribs-param-userprefix','s:160:\"en:Retrieve contributions for all users whose names begin with this value. Cannot be used with <var>$1user</var>, <var>$1userids</var>, or <var>$1iprange</var>.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-autopatrolled','s:28:\"en:Tags autopatrolled edits.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-comment','s:130:\"en:Adds the comment of the edit. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-flags','s:26:\"en:Adds flags of the edit.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-ids','s:36:\"en:Adds the page ID and revision ID.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-parsedcomment','s:137:\"en:Adds the parsed comment of the edit. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-patrolled','s:24:\"en:Tags patrolled edits.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-size','s:33:\"en:Adds the new size of the edit.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-sizediff','s:54:\"en:Adds the size delta of the edit against its parent.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-tags','s:27:\"en:Lists tags for the edit.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-timestamp','s:34:\"en:Adds the timestamp of the edit.\";'),('en','messages:apihelp-query+usercontribs-paramvalue-prop-title','s:47:\"en:Adds the title and namespace ID of the page.\";'),('en','messages:apihelp-query+usercontribs-summary','s:27:\"en:Get all edits by a user.\";'),('en','messages:apihelp-query+userinfo-example-data','s:53:\"en:Get additional information about the current user.\";'),('en','messages:apihelp-query+userinfo-example-simple','s:42:\"en:Get information about the current user.\";'),('en','messages:apihelp-query+userinfo-param-attachedwiki','s:112:\"en:With <kbd>$1prop=centralids</kbd>, indicate whether the user is attached with the wiki identified by this ID.\";'),('en','messages:apihelp-query+userinfo-param-prop','s:42:\"en:Which pieces of information to include:\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-acceptlang','s:92:\"en:Echoes the <code>Accept-Language</code> header sent by the client in a structured format.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-blockinfo','s:69:\"en:Tags if the current user is blocked, by whom, and for what reason.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-cancreateaccount','s:204:\"en:Indicates whether the user is allowed to create accounts. To check whether some specific account can be created, use [[Special:ApiHelp/query+users|<kbd>action=query&list=users&usprop=cancreate</kbd>]].\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-centralids','s:59:\"en:Adds the central IDs and attachment status for the user.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-changeablegroups','s:64:\"en:Lists the groups the current user can add to and remove from.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-editcount','s:38:\"en:Adds the current user\'s edit count.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-email','s:63:\"en:Adds the user\'s email address and email authentication date.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-groupmemberships','s:122:\"en:Lists groups that the current user has been explicitly assigned to, including the expiry date of each group membership.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-groups','s:52:\"en:Lists all the groups the current user belongs to.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-hasmsg','s:77:\"en:Adds a tag <samp>messages</samp> if the current user has pending messages.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-implicitgroups','s:70:\"en:Lists all the groups the current user is automatically a member of.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-latestcontrib','s:47:\"en:Adds the date of user\'s latest contribution.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-options','s:50:\"en:Lists all preferences the current user has set.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-ratelimits','s:54:\"en:Lists all rate limits applying to the current user.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-realname','s:29:\"en:Adds the user\'s real name.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-registrationdate','s:37:\"en:Adds the user\'s registration date.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-rights','s:45:\"en:Lists all the rights the current user has.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-theoreticalratelimits','s:133:\"en:Lists all rate limits that would apply to the current user if they were not exempt from all ratelimits based on user rights or ip.\";'),('en','messages:apihelp-query+userinfo-paramvalue-prop-unreadcount','s:104:\"en:Adds the count of unread pages on the user\'s watchlist (maximum $1; returns <samp>$2</samp> if more).\";'),('en','messages:apihelp-query+userinfo-summary','s:42:\"en:Get information about the current user.\";'),('en','messages:apihelp-query+users-example-simple','s:50:\"en:Return information for user <kbd>Example</kbd>.\";'),('en','messages:apihelp-query+users-param-attachedwiki','s:112:\"en:With <kbd>$1prop=centralids</kbd>, indicate whether the user is attached with the wiki identified by this ID.\";'),('en','messages:apihelp-query+users-param-prop','s:42:\"en:Which pieces of information to include:\";'),('en','messages:apihelp-query+users-param-userids','s:48:\"en:A list of user IDs to obtain information for.\";'),('en','messages:apihelp-query+users-param-users','s:45:\"en:A list of users to obtain information for.\";'),('en','messages:apihelp-query+users-paramvalue-prop-blockinfo','s:61:\"en:Tags if the user is blocked, by whom, and for what reason.\";'),('en','messages:apihelp-query+users-paramvalue-prop-cancreate','s:254:\"en:Indicates whether an account for valid but unregistered usernames can be created. To check whether the current user can perform the account creation, use [[Special:ApiHelp/query+userinfo|<kbd>action=query&meta=userinfo&uiprop=cancreateaccount</kbd>]].\";'),('en','messages:apihelp-query+users-paramvalue-prop-centralids','s:59:\"en:Adds the central IDs and attachment status for the user.\";'),('en','messages:apihelp-query+users-paramvalue-prop-editcount','s:30:\"en:Adds the user\'s edit count.\";'),('en','messages:apihelp-query+users-paramvalue-prop-emailable','s:81:\"en:Tags if the user can and wants to receive email through [[Special:Emailuser]].\";'),('en','messages:apihelp-query+users-paramvalue-prop-gender','s:71:\"en:Tags the gender of the user. Returns \"male\", \"female\", or \"unknown\".\";'),('en','messages:apihelp-query+users-paramvalue-prop-groupmemberships','s:115:\"en:Lists groups that each user has been explicitly assigned to, including the expiry date of each group membership.\";'),('en','messages:apihelp-query+users-paramvalue-prop-groups','s:45:\"en:Lists all the groups each user belongs to.\";'),('en','messages:apihelp-query+users-paramvalue-prop-implicitgroups','s:60:\"en:Lists all the groups a user is automatically a member of.\";'),('en','messages:apihelp-query+users-paramvalue-prop-registration','s:42:\"en:Adds the user\'s registration timestamp.\";'),('en','messages:apihelp-query+users-paramvalue-prop-rights','s:38:\"en:Lists all the rights each user has.\";'),('en','messages:apihelp-query+users-summary','s:41:\"en:Get information about a list of users.\";'),('en','messages:apihelp-query+watchlist-example-allrev','s:87:\"en:Fetch information about all recent changes to pages on the current user\'s watchlist.\";'),('en','messages:apihelp-query+watchlist-example-expiry','s:168:\"en:Fetch additional information about the top revision for recently changed pages on the current user\'s watchlist, including when temporarily watched items will expire.\";'),('en','messages:apihelp-query+watchlist-example-generator','s:78:\"en:Fetch page info for recently changed pages on the current user\'s watchlist.\";'),('en','messages:apihelp-query+watchlist-example-generator-rev','s:83:\"en:Fetch revision info for recent changes to pages on the current user\'s watchlist.\";'),('en','messages:apihelp-query+watchlist-example-props','s:114:\"en:Fetch additional information about the top revision for recently changed pages on the current user\'s watchlist.\";'),('en','messages:apihelp-query+watchlist-example-simple','s:84:\"en:List the top revision for recently changed pages on the current user\'s watchlist.\";'),('en','messages:apihelp-query+watchlist-example-wlowner','s:96:\"en:List the top revision for recently changed pages on the watchlist of user <kbd>Example</kbd>.\";'),('en','messages:apihelp-query+watchlist-param-allrev','s:70:\"en:Include multiple revisions of the same page within given timeframe.\";'),('en','messages:apihelp-query+watchlist-param-end','s:36:\"en:The timestamp to end enumerating.\";'),('en','messages:apihelp-query+watchlist-param-excludeuser','s:35:\"en:Don\'t list changes by this user.\";'),('en','messages:apihelp-query+watchlist-param-limit','s:48:\"en:How many total results to return per request.\";'),('en','messages:apihelp-query+watchlist-param-namespace','s:47:\"en:Filter changes to only the given namespaces.\";'),('en','messages:apihelp-query+watchlist-param-owner','s:66:\"en:Used along with $1token to access a different user\'s watchlist.\";'),('en','messages:apihelp-query+watchlist-param-prop','s:38:\"en:Which additional properties to get:\";'),('en','messages:apihelp-query+watchlist-param-show','s:130:\"en:Show only items that meet these criteria. For example, to see only minor edits done by logged-in users, set $1show=minor|!anon.\";'),('en','messages:apihelp-query+watchlist-param-start','s:43:\"en:The timestamp to start enumerating from.\";'),('en','messages:apihelp-query+watchlist-param-token','s:151:\"en:A security token (available in the user\'s [[Special:Preferences#mw-prefsection-watchlist|preferences]]) to allow access to another user\'s watchlist.\";'),('en','messages:apihelp-query+watchlist-param-type','s:34:\"en:Which types of changes to show:\";'),('en','messages:apihelp-query+watchlist-param-user','s:34:\"en:Only list changes by this user.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-autopatrol','s:37:\"en:Tags edits that are autopatrolled.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-comment','s:126:\"en:Adds comment of the edit. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-expiry','s:24:\"en:Adds the expiry time.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-flags','s:27:\"en:Adds flags for the edit.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-ids','s:34:\"en:Adds revision IDs and page IDs.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-loginfo','s:42:\"en:Adds log information where appropriate.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-notificationtimestamp','s:68:\"en:Adds timestamp of when the user was last notified about the edit.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-parsedcomment','s:133:\"en:Adds parsed comment of the edit. If the comment has been revision deleted, a <samp>commenthidden</samp> property will be returned.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-patrol','s:33:\"en:Tags edits that are patrolled.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-sizes','s:44:\"en:Adds the old and new lengths of the page.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-tags','s:28:\"en:Lists tags for the entry.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-timestamp','s:30:\"en:Adds timestamp of the edit.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-title','s:26:\"en:Adds title of the page.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-user','s:127:\"en:Adds the user who made the edit. If the user has been revision deleted, a <samp>userhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+watchlist-paramvalue-prop-userid','s:133:\"en:Adds user ID of whoever made the edit. If the user has been revision deleted, a <samp>userhidden</samp> property will be returned.\";'),('en','messages:apihelp-query+watchlist-paramvalue-type-categorize','s:31:\"en:Category membership changes.\";'),('en','messages:apihelp-query+watchlist-paramvalue-type-edit','s:22:\"en:Regular page edits.\";'),('en','messages:apihelp-query+watchlist-paramvalue-type-external','s:20:\"en:External changes.\";'),('en','messages:apihelp-query+watchlist-paramvalue-type-log','s:15:\"en:Log entries.\";'),('en','messages:apihelp-query+watchlist-paramvalue-type-new','s:18:\"en:Page creations.\";'),('en','messages:apihelp-query+watchlist-summary','s:63:\"en:Get recent changes to pages in the current user\'s watchlist.\";'),('en','messages:apihelp-query+watchlistraw-example-generator','s:61:\"en:Fetch page info for pages on the current user\'s watchlist.\";'),('en','messages:apihelp-query+watchlistraw-example-simple','s:46:\"en:List pages on the current user\'s watchlist.\";'),('en','messages:apihelp-query+watchlistraw-param-dir','s:34:\"en:The direction in which to list.\";'),('en','messages:apihelp-query+watchlistraw-param-fromtitle','s:59:\"en:Title (with namespace prefix) to begin enumerating from.\";'),('en','messages:apihelp-query+watchlistraw-param-limit','s:48:\"en:How many total results to return per request.\";'),('en','messages:apihelp-query+watchlistraw-param-namespace','s:43:\"en:Only list pages in the given namespaces.\";'),('en','messages:apihelp-query+watchlistraw-param-owner','s:66:\"en:Used along with $1token to access a different user\'s watchlist.\";'),('en','messages:apihelp-query+watchlistraw-param-prop','s:38:\"en:Which additional properties to get:\";'),('en','messages:apihelp-query+watchlistraw-param-show','s:44:\"en:Only list items that meet these criteria.\";'),('en','messages:apihelp-query+watchlistraw-param-token','s:151:\"en:A security token (available in the user\'s [[Special:Preferences#mw-prefsection-watchlist|preferences]]) to allow access to another user\'s watchlist.\";'),('en','messages:apihelp-query+watchlistraw-param-totitle','s:56:\"en:Title (with namespace prefix) to stop enumerating at.\";'),('en','messages:apihelp-query+watchlistraw-paramvalue-prop-changed','s:68:\"en:Adds timestamp of when the user was last notified about the edit.\";'),('en','messages:apihelp-query+watchlistraw-summary','s:49:\"en:Get all pages on the current user\'s watchlist.\";'),('en','messages:apihelp-query-example-allpages','s:59:\"en:Fetch revisions of pages beginning with <kbd>API/</kbd>.\";'),('en','messages:apihelp-query-example-revisions','s:134:\"en:Fetch [[Special:ApiHelp/query+siteinfo|site info]] and [[Special:ApiHelp/query+revisions|revisions]] of [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-query-extended-description','s:112:\"en:All data modifications will first have to use query to acquire a token to prevent abuse from malicious sites.\";'),('en','messages:apihelp-query-param-export','s:64:\"en:Export the current revisions of all given or generated pages.\";'),('en','messages:apihelp-query-param-exportnowrap','s:130:\"en:Return the export XML without wrapping it in an XML result (same format as [[Special:Export]]). Can only be used with $1export.\";'),('en','messages:apihelp-query-param-exportschema','s:109:\"en:Target the given version of the XML dump format when exporting. Can only be used with <var>$1export</var>.\";'),('en','messages:apihelp-query-param-indexpageids','s:71:\"en:Include an additional pageids section listing all returned page IDs.\";'),('en','messages:apihelp-query-param-iwurl','s:65:\"en:Whether to get the full URL if the title is an interwiki link.\";'),('en','messages:apihelp-query-param-list','s:22:\"en:Which lists to get.\";'),('en','messages:apihelp-query-param-meta','s:25:\"en:Which metadata to get.\";'),('en','messages:apihelp-query-param-prop','s:49:\"en:Which properties to get for the queried pages.\";'),('en','messages:apihelp-query-param-rawcontinue','s:64:\"en:Return raw <samp>query-continue</samp> data for continuation.\";'),('en','messages:apihelp-query-summary','s:39:\"en:Fetch data from and about MediaWiki.\";'),('en','messages:apihelp-rawfm-summary','s:84:\"en:Output data, including debugging elements, in JSON format (pretty-print in HTML).\";'),('en','messages:apihelp-removeauthenticationdata-example-simple','s:85:\"en:Attempt to remove the current user\'s data for <kbd>FooAuthenticationRequest</kbd>.\";'),('en','messages:apihelp-removeauthenticationdata-summary','s:51:\"en:Remove authentication data for the current user.\";'),('en','messages:apihelp-resetpassword-example-email','s:92:\"en:Send a password reset email for all users with email address <kbd>user@example.com</kbd>.\";'),('en','messages:apihelp-resetpassword-example-user','s:58:\"en:Send a password reset email to user <kbd>Example</kbd>.\";'),('en','messages:apihelp-resetpassword-extended-description-noroutes','s:170:\"en:No password reset routes are available.\n\nEnable routes in <var>[[mw:Special:MyLanguage/Manual:$wgPasswordResetRoutes|$wgPasswordResetRoutes]]</var> to use this module.\";'),('en','messages:apihelp-resetpassword-param-email','s:41:\"en:Email address of the user being reset.\";'),('en','messages:apihelp-resetpassword-param-user','s:20:\"en:User being reset.\";'),('en','messages:apihelp-resetpassword-summary','s:41:\"en:Send a password reset email to a user.\";'),('en','messages:apihelp-revisiondelete-example-log','s:88:\"en:Hide all data on log entry <kbd>67890</kbd> with the reason <kbd>BLP violation</kbd>.\";'),('en','messages:apihelp-revisiondelete-example-revision','s:85:\"en:Hide content for revision <kbd>12345</kbd> on the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-revisiondelete-param-hide','s:34:\"en:What to hide for each revision.\";'),('en','messages:apihelp-revisiondelete-param-ids','s:47:\"en:Identifiers for the revisions to be deleted.\";'),('en','messages:apihelp-revisiondelete-param-reason','s:41:\"en:Reason for the deletion or undeletion.\";'),('en','messages:apihelp-revisiondelete-param-show','s:36:\"en:What to unhide for each revision.\";'),('en','messages:apihelp-revisiondelete-param-suppress','s:66:\"en:Whether to suppress data from administrators as well as others.\";'),('en','messages:apihelp-revisiondelete-param-tags','s:50:\"en:Tags to apply to the entry in the deletion log.\";'),('en','messages:apihelp-revisiondelete-param-target','s:66:\"en:Page title for the revision deletion, if required for the type.\";'),('en','messages:apihelp-revisiondelete-param-type','s:45:\"en:Type of revision deletion being performed.\";'),('en','messages:apihelp-revisiondelete-summary','s:33:\"en:Delete and undelete revisions.\";'),('en','messages:apihelp-rollback-example-simple','s:90:\"en:Roll back the last edits to page [[{{MediaWiki:Mainpage}}]] by user <kbd>Example</kbd>.\";'),('en','messages:apihelp-rollback-example-summary','s:189:\"en:Roll back the last edits to page [[{{MediaWiki:Mainpage}}]] by IP user <kbd>192.0.2.5</kbd> with summary <kbd>Reverting vandalism</kbd>, and mark those edits and the revert as bot edits.\";'),('en','messages:apihelp-rollback-extended-description','s:99:\"en:If the last user who edited the page made multiple edits in a row, they will all be rolled back.\";'),('en','messages:apihelp-rollback-param-markbot','s:55:\"en:Mark the reverted edits and the revert as bot edits.\";'),('en','messages:apihelp-rollback-param-pageid','s:85:\"en:Page ID of the page to roll back. Cannot be used together with <var>$1title</var>.\";'),('en','messages:apihelp-rollback-param-summary','s:63:\"en:Custom edit summary. If empty, default summary will be used.\";'),('en','messages:apihelp-rollback-param-tags','s:33:\"en:Tags to apply to the rollback.\";'),('en','messages:apihelp-rollback-param-title','s:84:\"en:Title of the page to roll back. Cannot be used together with <var>$1pageid</var>.\";'),('en','messages:apihelp-rollback-param-user','s:54:\"en:Name of the user whose edits are to be rolled back.\";'),('en','messages:apihelp-rollback-param-watchlist','s:140:\"en:Unconditionally add or remove the page from the current user\'s watchlist, use preferences (ignored for bot users) or do not change watch.\";'),('en','messages:apihelp-rollback-param-watchlistexpiry','s:98:\"en:Watchlist expiry timestamp. Omit this parameter entirely to leave the current expiry unchanged.\";'),('en','messages:apihelp-rollback-summary','s:34:\"en:Undo the last edit to the page.\";'),('en','messages:apihelp-rsd-example-simple','s:25:\"en:Export the RSD schema.\";'),('en','messages:apihelp-rsd-summary','s:50:\"en:Export an RSD (Really Simple Discovery) schema.\";'),('en','messages:apihelp-setnotificationtimestamp-example-all','s:58:\"en:Reset the notification status for the entire watchlist.\";'),('en','messages:apihelp-setnotificationtimestamp-example-allpages','s:83:\"en:Reset the notification status for pages in the <kbd>{{ns:user}}</kbd> namespace.\";'),('en','messages:apihelp-setnotificationtimestamp-example-page','s:64:\"en:Reset the notification status for [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-setnotificationtimestamp-example-pagetimestamp','s:112:\"en:Set the notification timestamp for [[{{MediaWiki:Mainpage}}]] so all edits since 1 January 2012 are unviewed.\";'),('en','messages:apihelp-setnotificationtimestamp-extended-description','s:171:\"en:This affects the highlighting of changed pages in the watchlist and history, and the sending of email when the \"{{int:tog-enotifwatchlistpages}}\" preference is enabled.\";'),('en','messages:apihelp-setnotificationtimestamp-param-entirewatchlist','s:29:\"en:Work on all watched pages.\";'),('en','messages:apihelp-setnotificationtimestamp-param-newerthanrevid','s:73:\"en:Revision to set the notification timestamp newer than (one page only).\";'),('en','messages:apihelp-setnotificationtimestamp-param-timestamp','s:56:\"en:Timestamp to which to set the notification timestamp.\";'),('en','messages:apihelp-setnotificationtimestamp-param-torevid','s:65:\"en:Revision to set the notification timestamp to (one page only).\";'),('en','messages:apihelp-setnotificationtimestamp-summary','s:55:\"en:Update the notification timestamp for watched pages.\";'),('en','messages:apihelp-setpagelanguage-example-default','s:86:\"en:Change the language of the page with ID 123 to the wiki\'s default content language.\";'),('en','messages:apihelp-setpagelanguage-example-language','s:72:\"en:Change the language of the page [[{{MediaWiki:Mainpage}}]] to Basque.\";'),('en','messages:apihelp-setpagelanguage-extended-description-disabled','s:177:\"en:Changing the language of a page is not allowed on this wiki.\n\nEnable <var>[[mw:Special:MyLanguage/Manual:$wgPageLanguageUseDB|$wgPageLanguageUseDB]]</var> to use this action.\";'),('en','messages:apihelp-setpagelanguage-param-lang','s:136:\"en:Language code of the language to change the page to. Use <kbd>default</kbd> to reset the page to the wiki\'s default content language.\";'),('en','messages:apihelp-setpagelanguage-param-pageid','s:106:\"en:Page ID of the page whose language you wish to change. Cannot be used together with <var>$1title</var>.\";'),('en','messages:apihelp-setpagelanguage-param-reason','s:25:\"en:Reason for the change.\";'),('en','messages:apihelp-setpagelanguage-param-tags','s:68:\"en:Change tags to apply to the log entry resulting from this action.\";'),('en','messages:apihelp-setpagelanguage-param-title','s:105:\"en:Title of the page whose language you wish to change. Cannot be used together with <var>$1pageid</var>.\";'),('en','messages:apihelp-setpagelanguage-summary','s:33:\"en:Change the language of a page.\";'),('en','messages:apihelp-stashedit-extended-description','s:103:\"en:This is intended to be used via AJAX from the edit form to improve the performance of the page save.\";'),('en','messages:apihelp-stashedit-param-baserevid','s:36:\"en:Revision ID of the base revision.\";'),('en','messages:apihelp-stashedit-param-contentformat','s:56:\"en:Content serialization format used for the input text.\";'),('en','messages:apihelp-stashedit-param-contentmodel','s:36:\"en:Content model of the new content.\";'),('en','messages:apihelp-stashedit-param-section','s:90:\"en:Section identifier. <kbd>0</kbd> for the top section, <kbd>new</kbd> for a new section.\";'),('en','messages:apihelp-stashedit-param-sectiontitle','s:31:\"en:The title for a new section.\";'),('en','messages:apihelp-stashedit-param-stashedtexthash','s:55:\"en:Page content hash from a prior stash to use instead.\";'),('en','messages:apihelp-stashedit-param-summary','s:18:\"en:Change summary.\";'),('en','messages:apihelp-stashedit-param-text','s:16:\"en:Page content.\";'),('en','messages:apihelp-stashedit-param-title','s:34:\"en:Title of the page being edited.\";'),('en','messages:apihelp-stashedit-summary','s:35:\"en:Prepare an edit in shared cache.\";'),('en','messages:apihelp-summary','s:3:\"en:\";'),('en','messages:apihelp-tag-example-log','s:98:\"en:Remove the <kbd>spam</kbd> tag from log entry ID 123 with the reason <kbd>Wrongly applied</kbd>\";'),('en','messages:apihelp-tag-example-rev','s:82:\"en:Add the <kbd>vandalism</kbd> tag to revision ID 123 without specifying a reason\";'),('en','messages:apihelp-tag-param-add','s:56:\"en:Tags to add. Only manually defined tags can be added.\";'),('en','messages:apihelp-tag-param-logid','s:65:\"en:One or more log entry IDs from which to add or remove the tag.\";'),('en','messages:apihelp-tag-param-rcid','s:70:\"en:One or more recent changes IDs from which to add or remove the tag.\";'),('en','messages:apihelp-tag-param-reason','s:25:\"en:Reason for the change.\";'),('en','messages:apihelp-tag-param-remove','s:101:\"en:Tags to remove. Only tags that are either manually defined or completely undefined can be removed.\";'),('en','messages:apihelp-tag-param-revid','s:64:\"en:One or more revision IDs from which to add or remove the tag.\";'),('en','messages:apihelp-tag-param-tags','s:82:\"en:Tags to apply to the log entry that will be created as a result of this action.\";'),('en','messages:apihelp-tag-summary','s:70:\"en:Add or remove change tags from individual revisions or log entries.\";'),('en','messages:apihelp-unblock-example-id','s:36:\"en:Unblock block ID #<kbd>105</kbd>.\";'),('en','messages:apihelp-unblock-example-user','s:64:\"en:Unblock user <kbd>Bob</kbd> with reason <kbd>Sorry Bob</kbd>.\";'),('en','messages:apihelp-unblock-param-id','s:120:\"en:ID of the block to unblock (obtained through <kbd>list=blocks</kbd>). Cannot be used together with <var>$1user</var>.\";'),('en','messages:apihelp-unblock-param-reason','s:22:\"en:Reason for unblock.\";'),('en','messages:apihelp-unblock-param-tags','s:54:\"en:Change tags to apply to the entry in the block log.\";'),('en','messages:apihelp-unblock-param-user','s:65:\"en:User to unblock. Cannot be used together with <var>$1id</var>.\";'),('en','messages:apihelp-unblock-param-userid','s:52:\"en:Specify <kbd>$1user=#<var>ID</var></kbd> instead.\";'),('en','messages:apihelp-unblock-param-watchlistexpiry','s:98:\"en:Watchlist expiry timestamp. Omit this parameter entirely to leave the current expiry unchanged.\";'),('en','messages:apihelp-unblock-param-watchuser','s:56:\"en:Watch the user\'s or IP address\'s user and talk pages.\";'),('en','messages:apihelp-unblock-summary','s:18:\"en:Unblock a user.\";'),('en','messages:apihelp-undelete-example-page','s:44:\"en:Undelete page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-undelete-example-revisions','s:61:\"en:Undelete two revisions of page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-undelete-extended-description','s:256:\"en:A list of deleted revisions (including timestamps) can be retrieved through [[Special:ApiHelp/query+deletedrevisions|prop=deletedrevisions]], and a list of deleted file IDs can be retrieved through [[Special:ApiHelp/query+filearchive|list=filearchive]].\";'),('en','messages:apihelp-undelete-param-fileids','s:130:\"en:IDs of the file revisions to restore. If both <var>$1timestamps</var> and <var>$1fileids</var> are empty, all will be restored.\";'),('en','messages:apihelp-undelete-param-reason','s:24:\"en:Reason for restoring.\";'),('en','messages:apihelp-undelete-param-tags','s:57:\"en:Change tags to apply to the entry in the deletion log.\";'),('en','messages:apihelp-undelete-param-timestamps','s:134:\"en:Timestamps of the revisions to undelete. If both <var>$1timestamps</var> and <var>$1fileids</var> are empty, all will be undeleted.\";'),('en','messages:apihelp-undelete-param-title','s:33:\"en:Title of the page to undelete.\";'),('en','messages:apihelp-undelete-param-undeletetalk','s:62:\"en:Undelete all revisions of the associated talk page, if any.\";'),('en','messages:apihelp-undelete-param-watchlist','s:140:\"en:Unconditionally add or remove the page from the current user\'s watchlist, use preferences (ignored for bot users) or do not change watch.\";'),('en','messages:apihelp-undelete-param-watchlistexpiry','s:98:\"en:Watchlist expiry timestamp. Omit this parameter entirely to leave the current expiry unchanged.\";'),('en','messages:apihelp-undelete-summary','s:40:\"en:Undelete revisions of a deleted page.\";'),('en','messages:apihelp-unlinkaccount-example-simple','s:114:\"en:Attempt to remove the current user\'s link for the provider associated with <kbd>FooAuthenticationRequest</kbd>.\";'),('en','messages:apihelp-unlinkaccount-summary','s:61:\"en:Remove a linked third-party account from the current user.\";'),('en','messages:apihelp-upload-example-filekey','s:50:\"en:Complete an upload that failed due to warnings.\";'),('en','messages:apihelp-upload-example-url','s:21:\"en:Upload from a URL.\";'),('en','messages:apihelp-upload-extended-description','s:637:\"en:Several methods are available:\n* Upload file contents directly, using the <var>$1file</var> parameter.\n* Upload the file in pieces, using the <var>$1filesize</var>, <var>$1chunk</var>, and <var>$1offset</var> parameters.\n* Have the MediaWiki server fetch a file from a URL, using the <var>$1url</var> parameter.\n* Complete an earlier upload that failed due to warnings, was uploaded in pieces, or stored otherwise in the upload stash, using the <var>$1filekey</var> parameter.\nNote that the HTTP POST must be done as a file upload (i.e. using <code>multipart/form-data</code>) when sending the <var>$1file</var> or <var>$1chunk</var>.\";'),('en','messages:apihelp-upload-param-async','s:69:\"en:Make potentially large file operations asynchronous when possible.\";'),('en','messages:apihelp-upload-param-checkstatus','s:55:\"en:Only fetch the upload status for the given file key.\";'),('en','messages:apihelp-upload-param-chunk','s:18:\"en:Chunk contents.\";'),('en','messages:apihelp-upload-param-comment','s:106:\"en:Upload comment. Also used as the initial page text for new files if <var>$1text</var> is not specified.\";'),('en','messages:apihelp-upload-param-file','s:17:\"en:File contents.\";'),('en','messages:apihelp-upload-param-filekey','s:70:\"en:Key that identifies a previous upload that was stashed temporarily.\";'),('en','messages:apihelp-upload-param-filename','s:19:\"en:Target filename.\";'),('en','messages:apihelp-upload-param-filesize','s:29:\"en:Filesize of entire upload.\";'),('en','messages:apihelp-upload-param-ignorewarnings','s:23:\"en:Ignore any warnings.\";'),('en','messages:apihelp-upload-param-offset','s:28:\"en:Offset of chunk in bytes.\";'),('en','messages:apihelp-upload-param-sessionkey','s:60:\"en:Same as $1filekey, maintained for backward compatibility.\";'),('en','messages:apihelp-upload-param-stash','s:93:\"en:If set, the server will stash the file temporarily instead of adding it to the repository.\";'),('en','messages:apihelp-upload-param-tags','s:71:\"en:Change tags to apply to the upload log entry and file page revision.\";'),('en','messages:apihelp-upload-param-text','s:35:\"en:Initial page text for new files.\";'),('en','messages:apihelp-upload-param-url','s:30:\"en:URL to fetch the file from.\";'),('en','messages:apihelp-upload-param-watch','s:18:\"en:Watch the page.\";'),('en','messages:apihelp-upload-param-watchlist','s:140:\"en:Unconditionally add or remove the page from the current user\'s watchlist, use preferences (ignored for bot users) or do not change watch.\";'),('en','messages:apihelp-upload-param-watchlistexpiry','s:98:\"en:Watchlist expiry timestamp. Omit this parameter entirely to leave the current expiry unchanged.\";'),('en','messages:apihelp-upload-summary','s:55:\"en:Upload a file, or get the status of pending uploads.\";'),('en','messages:apihelp-userrights-example-expiry','s:75:\"en:Add user <kbd>SometimeSysop</kbd> to group <kbd>sysop</kbd> for 1 month.\";'),('en','messages:apihelp-userrights-example-user','s:121:\"en:Add user <kbd>FooBot</kbd> to group <kbd>bot</kbd>, and remove from groups <kbd>sysop</kbd> and <kbd>bureaucrat</kbd>.\";'),('en','messages:apihelp-userrights-example-userid','s:130:\"en:Add the user with ID <kbd>123</kbd> to group <kbd>bot</kbd>, and remove from groups <kbd>sysop</kbd> and <kbd>bureaucrat</kbd>.\";'),('en','messages:apihelp-userrights-param-add','s:118:\"en:Add the user to these groups, or if they are already a member, update the expiry of their membership in that group.\";'),('en','messages:apihelp-userrights-param-expiry','s:363:\"en:Expiry timestamps. May be relative (e.g. <kbd>5 months</kbd> or <kbd>2 weeks</kbd>) or absolute (e.g. <kbd>2014-09-18T12:34:56Z</kbd>). If only one timestamp is set, it will be used for all groups passed to the <var>$1add</var> parameter. Use <kbd>infinite</kbd>, <kbd>indefinite</kbd>, <kbd>infinity</kbd>, or <kbd>never</kbd> for a never-expiring user group.\";'),('en','messages:apihelp-userrights-param-reason','s:25:\"en:Reason for the change.\";'),('en','messages:apihelp-userrights-param-remove','s:37:\"en:Remove the user from these groups.\";'),('en','messages:apihelp-userrights-param-tags','s:60:\"en:Change tags to apply to the entry in the user rights log.\";'),('en','messages:apihelp-userrights-param-user','s:8:\"en:User.\";'),('en','messages:apihelp-userrights-param-userid','s:52:\"en:Specify <kbd>$1user=#<var>ID</var></kbd> instead.\";'),('en','messages:apihelp-userrights-param-watchlistexpiry','s:98:\"en:Watchlist expiry timestamp. Omit this parameter entirely to leave the current expiry unchanged.\";'),('en','messages:apihelp-userrights-param-watchuser','s:40:\"en:Watch the user\'s user and talk pages.\";'),('en','messages:apihelp-userrights-summary','s:36:\"en:Change a user\'s group membership.\";'),('en','messages:apihelp-validatepassword-example-1','s:64:\"en:Validate the password <kbd>foobar</kbd> for the current user.\";'),('en','messages:apihelp-validatepassword-example-2','s:80:\"en:Validate the password <kbd>qwerty</kbd> for creating user <kbd>Example</kbd>.\";'),('en','messages:apihelp-validatepassword-extended-description','s:209:\"en:Validity is reported as <samp>Good</samp> if the password is acceptable, <samp>Change</samp> if the password may be used for login but must be changed, or <samp>Invalid</samp> if the password is not usable.\";'),('en','messages:apihelp-validatepassword-param-email','s:56:\"en:Email address, for use when testing account creation.\";'),('en','messages:apihelp-validatepassword-param-password','s:24:\"en:Password to validate.\";'),('en','messages:apihelp-validatepassword-param-realname','s:52:\"en:Real name, for use when testing account creation.\";'),('en','messages:apihelp-validatepassword-param-user','s:82:\"en:Username, for use when testing account creation. The named user must not exist.\";'),('en','messages:apihelp-validatepassword-summary','s:60:\"en:Validate a password against the wiki\'s password policies.\";'),('en','messages:apihelp-watch-example-generator','s:51:\"en:Watch the first few pages in the main namespace.\";'),('en','messages:apihelp-watch-example-unwatch','s:47:\"en:Unwatch the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-watch-example-watch','s:45:\"en:Watch the page [[{{MediaWiki:Mainpage}}]].\";'),('en','messages:apihelp-watch-example-watch-expiry','s:96:\"en:Watch the pages [[{{MediaWiki:Mainpage}}]], <kbd>Foo</kbd>, and <kbd>Bar</kbd> for one month.\";'),('en','messages:apihelp-watch-param-expiry','s:123:\"en:Expiry timestamp to be applied to all given pages. Omit this parameter entirely to leave any current expiries unchanged.\";'),('en','messages:apihelp-watch-param-title','s:58:\"en:The page to (un)watch. Use <var>$1titles</var> instead.\";'),('en','messages:apihelp-watch-param-unwatch','s:57:\"en:If set the page will be unwatched rather than watched.\";'),('en','messages:apihelp-watch-summary','s:57:\"en:Add or remove pages from the current user\'s watchlist.\";'),('en','messages:apihelp-xml-param-includexmlnamespace','s:39:\"en:If specified, adds an XML namespace.\";'),('en','messages:apihelp-xml-param-xslt','s:147:\"en:If specified, adds the named page as an XSL stylesheet. The value must be a title in the {{ns:MediaWiki}} namespace ending in <code>.xsl</code>.\";'),('en','messages:apihelp-xml-summary','s:29:\"en:Output data in XML format.\";'),('en','messages:apihelp-xmlfm-summary','s:52:\"en:Output data in XML format (pretty-print in HTML).\";'),('en','messages:apisandbox','s:14:\"en:API sandbox\";'),('en','messages:apisandbox-add-multi','s:6:\"en:Add\";'),('en','messages:apisandbox-alert-field','s:40:\"en:The value of this field is not valid.\";'),('en','messages:apisandbox-alert-page','s:37:\"en:Fields on this page are not valid.\";'),('en','messages:apisandbox-continue','s:11:\"en:Continue\";'),('en','messages:apisandbox-continue-clear','s:8:\"en:Clear\";'),('en','messages:apisandbox-continue-help','s:221:\"en:{{int:apisandbox-continue}} will [https://www.mediawiki.org/wiki/Special:MyLanguage/API:Query#Continuing_queries continue] the last request; {{int:apisandbox-continue-clear}} will clear continuation-related parameters.\";'),('en','messages:apisandbox-deprecated-parameters','s:24:\"en:Deprecated parameters\";'),('en','messages:apisandbox-dynamic-error-exists','s:41:\"en:A parameter named \"$1\" already exists.\";'),('en','messages:apisandbox-dynamic-parameters','s:24:\"en:Additional parameters\";'),('en','messages:apisandbox-dynamic-parameters-add-label','s:17:\"en:Add parameter:\";'),('en','messages:apisandbox-dynamic-parameters-add-placeholder','s:17:\"en:Parameter name\";'),('en','messages:apisandbox-examples','s:11:\"en:Examples\";'),('en','messages:apisandbox-fetch-token','s:22:\"en:Auto-fill the token\";'),('en','messages:apisandbox-helpurls','s:13:\"en:Help links\";'),('en','messages:apisandbox-intro','s:489:\"en:Use this page to experiment with the <strong>MediaWiki web service API</strong>.\nRefer to [https://www.mediawiki.org/wiki/Special:MyLanguage/API:Main_page the API documentation] for further details of API usage. Example: [https://www.mediawiki.org/wiki/Special:MyLanguage/API:Tutorial#A_simple_query search for page titles matching a certain keyword]. Select an action to see more examples.\n\nNote that, although this is a sandbox, actions you carry out on this page may modify the wiki.\";'),('en','messages:apisandbox-jsonly','s:49:\"en:JavaScript is required to use the API sandbox.\";'),('en','messages:apisandbox-load-error','s:70:\"en:An error occurred while loading information for API module \"$1\": $2\";'),('en','messages:apisandbox-loading','s:45:\"en:Loading information for API module \"$1\"...\";'),('en','messages:apisandbox-loading-results','s:27:\"en:Receiving API results...\";'),('en','messages:apisandbox-multivalue-all-namespaces','s:22:\"en:$1 (All namespaces)\";'),('en','messages:apisandbox-multivalue-all-values','s:18:\"en:$1 (All values)\";'),('en','messages:apisandbox-no-parameters','s:37:\"en:This API module has no parameters.\";'),('en','messages:apisandbox-param-limit','s:49:\"en:Enter <kbd>max</kbd> to use the maximum limit.\";'),('en','messages:apisandbox-request-format-json-label','s:7:\"en:JSON\";'),('en','messages:apisandbox-request-format-php-label','s:12:\"en:PHP array\";'),('en','messages:apisandbox-request-format-url-label','s:19:\"en:URL query string\";'),('en','messages:apisandbox-request-formdata','s:92:\"en:This request must be sent as a file upload (i.e. using <code>multipart/form-data</code>).\";'),('en','messages:apisandbox-request-json-label','s:16:\"en:Request JSON:\";'),('en','messages:apisandbox-request-php-label','s:21:\"en:Request PHP array:\";'),('en','messages:apisandbox-request-post','s:56:\"en:This request must be sent using the HTTP POST method.\";'),('en','messages:apisandbox-request-post2','s:89:\"en:Due to the size of the payload, this request has been sent using the HTTP POST method.\";'),('en','messages:apisandbox-request-selectformat-label','s:24:\"en:Show request data as:\";'),('en','messages:apisandbox-request-time','s:36:\"en:Request time: {{PLURAL:$1|$1 ms}}\";'),('en','messages:apisandbox-request-url-label','s:15:\"en:Request URL:\";'),('en','messages:apisandbox-reset','s:8:\"en:Clear\";'),('en','messages:apisandbox-results','s:10:\"en:Results\";'),('en','messages:apisandbox-results-error','s:62:\"en:An error occurred while loading the API query response: $1.\";'),('en','messages:apisandbox-results-fixtoken','s:29:\"en:Correct token and resubmit\";'),('en','messages:apisandbox-results-fixtoken-fail','s:30:\"en:Failed to fetch \"$1\" token.\";'),('en','messages:apisandbox-results-login-suppressed','s:241:\"en:This request has been processed as a logged-out user as it could be used to bypass browser Same-Origin security. Note that the API sandbox\'s automatic token handling does not work properly with such requests, please fill them in manually.\";'),('en','messages:apisandbox-retry','s:8:\"en:Retry\";'),('en','messages:apisandbox-sending-request','s:25:\"en:Sending API request...\";'),('en','messages:apisandbox-submit','s:15:\"en:Make request\";'),('en','messages:apisandbox-submit-invalid-fields-message','s:50:\"en:Please correct the marked fields and try again.\";'),('en','messages:apisandbox-submit-invalid-fields-title','s:26:\"en:Some fields are invalid\";'),('en','messages:apisandbox-summary','s:3:\"en:\";'),('en','messages:apisandbox-templated-parameter-reason','s:131:\"en:This [[Special:ApiHelp/main#main/templatedparams|templated parameter]] is offered based on the {{PLURAL:$1|value|values}} of $2.\";'),('en','messages:apiwarn-alldeletedrevisions-performance','s:77:\"en:For better performance when generating titles, set <kbd>$1dir=newer</kbd>.\";'),('en','messages:apiwarn-badurlparam','s:77:\"en:Could not parse <var>$1urlparam</var> for $2. Using only width and height.\";'),('en','messages:apiwarn-badutf8','s:203:\"en:The value passed for <var>$1</var> contains invalid or non-normalized data. Textual data should be valid, NFC-normalized Unicode without C0 control characters other than HT (\\t), LF (\\n), and CR (\\r).\";'),('en','messages:apiwarn-checktoken-percentencoding','s:87:\"en:Check that symbols such as \"+\" in the token are properly percent-encoded in the URL.\";'),('en','messages:apiwarn-compare-no-next','s:111:\"en:Revision $2 is the latest revision of $1, there is no revision for <kbd>torelative=next</kbd> to compare to.\";'),('en','messages:apiwarn-compare-no-prev','s:113:\"en:Revision $2 is the earliest revision of $1, there is no revision for <kbd>torelative=prev</kbd> to compare to.\";'),('en','messages:apiwarn-compare-nocontentmodel','s:53:\"en:No content model could be determined, assuming $1.\";'),('en','messages:apiwarn-deprecation-deletedrevs','s:143:\"en:<kbd>list=deletedrevs</kbd> has been deprecated. Please use <kbd>prop=deletedrevisions</kbd> or <kbd>list=alldeletedrevisions</kbd> instead.\";'),('en','messages:apiwarn-deprecation-httpsexpected','s:37:\"en:HTTP used when HTTPS was expected.\";'),('en','messages:apiwarn-deprecation-login-botpw','s:259:\"en:Main-account login via <kbd>action=login</kbd> is deprecated and may stop working without warning. To continue login with <kbd>action=login</kbd>, see [[Special:BotPasswords]]. To safely continue using main-account login, see <kbd>action=clientlogin</kbd>.\";'),('en','messages:apiwarn-deprecation-login-nobotpw','s:154:\"en:Main-account login via <kbd>action=login</kbd> is deprecated and may stop working without warning. To safely log in, see <kbd>action=clientlogin</kbd>.\";'),('en','messages:apiwarn-deprecation-login-token','s:122:\"en:Fetching a token via <kbd>action=login</kbd> is deprecated. Use <kbd>action=query&meta=tokens&type=login</kbd> instead.\";'),('en','messages:apiwarn-deprecation-missingparam','s:170:\"en:Because <var>$1</var> was not specified, a legacy format has been used for the output. This format is deprecated, and in the future the new format will always be used.\";'),('en','messages:apiwarn-deprecation-parameter','s:51:\"en:The parameter <var>$1</var> has been deprecated.\";'),('en','messages:apiwarn-deprecation-parse-headitems','s:205:\"en:<kbd>prop=headitems</kbd> is deprecated since MediaWiki 1.28. Use <kbd>prop=headhtml</kbd> when creating new HTML documents, or <kbd>prop=modules|jsconfigvars</kbd> when updating a document client-side.\";'),('en','messages:apiwarn-deprecation-post-without-content-type','s:99:\"en:A POST request was made without a <code>Content-Type</code> header. This does not work reliably.\";'),('en','messages:apiwarn-deprecation-purge-get','s:74:\"en:Use of <kbd>action=purge</kbd> via GET is deprecated. Use POST instead.\";'),('en','messages:apiwarn-deprecation-withreplacement','s:71:\"en:<kbd>$1</kbd> has been deprecated. Please use <kbd>$2</kbd> instead.\";'),('en','messages:apiwarn-difftohidden','s:43:\"en:Couldn\'t diff to r$1: content is hidden.\";'),('en','messages:apiwarn-errorprinterfailed','s:51:\"en:Error printer failed. Will retry without params.\";'),('en','messages:apiwarn-global-option-ignored','s:170:\"en:Option <var>$1</var> is globally overridden. You can use <kbd>global=update</kbd> to change the option globally, or <kbd>global=override</kbd> to set a local override.\";'),('en','messages:apiwarn-ignoring-invalid-templated-value','s:86:\"en:Ignoring value <kbd>$2</kbd> in <var>$1</var> when processing templated parameters.\";'),('en','messages:apiwarn-invalidcategory','s:26:\"en:\"$1\" is not a category.\";'),('en','messages:apiwarn-invalidtitle','s:29:\"en:\"$1\" is not a valid title.\";'),('en','messages:apiwarn-invalidxmlstylesheet','s:48:\"en:Invalid or non-existent stylesheet specified.\";'),('en','messages:apiwarn-invalidxmlstylesheetext','s:54:\"en:Stylesheet should have <code>.xsl</code> extension.\";'),('en','messages:apiwarn-invalidxmlstylesheetns','s:58:\"en:Stylesheet should be in the {{ns:MediaWiki}} namespace.\";'),('en','messages:apiwarn-moduleswithoutvars','s:168:\"en:Property <kbd>modules</kbd> was set but not <kbd>jsconfigvars</kbd> or <kbd>encodedjsconfigvars</kbd>. Configuration variables are necessary for proper module usage.\";'),('en','messages:apiwarn-notfile','s:22:\"en:\"$1\" is not a file.\";'),('en','messages:apiwarn-nothumb-noimagehandler','s:83:\"en:Could not create thumbnail because $1 does not have an associated image handler.\";'),('en','messages:apiwarn-parse-nocontentmodel','s:73:\"en:No <var>title</var> or <var>contentmodel</var> was given, assuming $1.\";'),('en','messages:apiwarn-parse-revidwithouttext','s:158:\"en:<var>revid</var> used without <var>text</var>, and parsed page properties were requested. Did you mean to use <var>oldid</var> instead of <var>revid</var>?\";'),('en','messages:apiwarn-parse-titlewithouttext','s:157:\"en:<var>title</var> used without <var>text</var>, and parsed page properties were requested. Did you mean to use <var>page</var> instead of <var>title</var>?\";'),('en','messages:apiwarn-redirectsandrevids','s:153:\"en:Redirect resolution cannot be used together with the <var>revids</var> parameter. Any redirects the <var>revids</var> point to have not been resolved.\";'),('en','messages:apiwarn-tokens-origin','s:73:\"en:Tokens may not be obtained when the same-origin policy is not applied.\";'),('en','messages:apiwarn-truncatedresult','s:93:\"en:This result was truncated because it would otherwise be larger than the limit of $1 bytes.\";'),('en','messages:apiwarn-unclearnowtimestamp','s:197:\"en:Passing \"$2\" for timestamp parameter <var>$1</var> has been deprecated. If for some reason you need to explicitly specify the current time without calculating it client-side, use <kbd>now</kbd>.\";'),('en','messages:apiwarn-unrecognizedvalues','s:75:\"en:Unrecognized {{PLURAL:$3|value|values}} for parameter <var>$1</var>: $2.\";'),('en','messages:apiwarn-unsupportedarray','s:61:\"en:Parameter <var>$1</var> uses unsupported PHP array syntax.\";'),('en','messages:apiwarn-urlparamwidth','s:145:\"en:Ignoring width value set in <var>$1urlparam</var> ($2) in favor of width value derived from <var>$1urlwidth</var>/<var>$1urlheight</var> ($3).\";'),('en','messages:apiwarn-validationfailed','s:41:\"en:Validation error for <kbd>$1</kbd>: $2\";'),('en','messages:apiwarn-validationfailed-badchars','s:137:\"en:invalid characters in key (only <code>a-z</code>, <code>A-Z</code>, <code>0-9</code>, <code>_</code>, and <code>-</code> are allowed).\";'),('en','messages:apiwarn-validationfailed-badpref','s:26:\"en:not a valid preference.\";'),('en','messages:apiwarn-validationfailed-cannotset','s:32:\"en:cannot be set by this module.\";'),('en','messages:apiwarn-validationfailed-keytoolong','s:67:\"en:key too long (no more than $1 {{PLURAL:$1|byte|bytes}} allowed).\";'),('en','messages:apiwarn-validationfailed-valuetoolong','s:69:\"en:value too long (no more than $1 {{PLURAL:$1|byte|bytes}} allowed).\";'),('en','messages:apiwarn-wgdebugapi','s:72:\"en:<strong>Security Warning:</strong> <var>$wgDebugAPI</var> is enabled.\";'),('en','messages:apiwarn-xslt-disabled','s:44:\"en:The xslt option is disabled on this wiki.\";'),('en','messages:apr','s:6:\"en:Apr\";'),('en','messages:april','s:8:\"en:April\";'),('en','messages:april-gen','s:8:\"en:April\";'),('en','messages:article','s:15:\"en:Content page\";'),('en','messages:articleexists','s:111:\"en:A page already exists at [[:$1]], or the page name you have chosen is not valid.\nPlease choose another name.\";'),('en','messages:aug','s:6:\"en:Aug\";'),('en','messages:august','s:9:\"en:August\";'),('en','messages:august-gen','s:9:\"en:August\";'),('en','messages:authenticationdatachange-ignored','s:84:\"en:The authentication data change was not handled. Maybe no provider was configured?\";'),('en','messages:authform-newtoken','s:20:\"en:Missing token. $1\";'),('en','messages:authform-nosession-login','s:93:\"en:The authentication was successful, but your browser cannot \"remember\" being logged in.\n\n$1\";'),('en','messages:authform-nosession-signup','s:83:\"en:The account was created, but your browser cannot \"remember\" being logged in.\n\n$1\";'),('en','messages:authform-notoken','s:16:\"en:Missing token\";'),('en','messages:authform-wrongtoken','s:14:\"en:Wrong token\";'),('en','messages:authmanager-account-password-domain','s:8:\"en:$1@$2\";'),('en','messages:authmanager-authn-autocreate-failed','s:46:\"en:Auto-creation of a local account failed: $1\";'),('en','messages:authmanager-authn-no-local-user','s:74:\"en:The supplied credentials are not associated with any user on this wiki.\";'),('en','messages:authmanager-authn-no-local-user-link','s:215:\"en:The supplied credentials are valid but are not associated with any user on this wiki. Login in a different way, or create a new user, and you will have an option to link your previous credentials to that account.\";'),('en','messages:authmanager-authn-no-primary','s:55:\"en:The supplied credentials could not be authenticated.\";'),('en','messages:authmanager-authn-not-in-progress','s:106:\"en:Authentication is not in progress or session data has been lost. Please start again from the beginning.\";'),('en','messages:authmanager-autocreate-exception','s:71:\"en:Automatic account creation temporarily disabled due to prior errors.\";'),('en','messages:authman