isions}} by more than $2 {{PLURAL:$2|user|users}} not shown)\";'),('en','messages:diff-multi-otherusers','s:121:\"en:({{PLURAL:$1|One intermediate revision|$1 intermediate revisions}} by {{PLURAL:$2|one other user|$2 users}} not shown)\";'),('en','messages:diff-multi-sameuser','s:111:\"en:({{PLURAL:$1|One intermediate revision|$1 intermediate revisions}} by the same {{GENDER:$3|user}} not shown)\";'),('en','messages:diff-newline','s:14:\"en:âē newline\";'),('en','messages:diff-paragraph-moved-tonew','s:54:\"en:Paragraph was moved. Click to jump to new location.\";'),('en','messages:diff-paragraph-moved-toold','s:54:\"en:Paragraph was moved. Click to jump to old location.\";'),('en','messages:diff-user-edits','s:43:\"en:<span>$1</span> {{PLURAL:$1|edit|edits}}\";'),('en','messages:difference-bad-new-revision','s:59:\"en:The content of the new revision is missing or corrupted.\";'),('en','messages:difference-bad-old-revision','s:59:\"en:The content of the old revision is missing or corrupted.\";'),('en','messages:difference-missing-revision','s:295:\"en:{{PLURAL:$2|One revision|$2 revisions}} of this difference ($1) {{PLURAL:$2|was|were}} not found.\n\nThis is usually caused by following an outdated diff link to a page that has been deleted.\nDetails can be found in the [{{fullurl:{{#Special:Log}}/delete|page={{FULLPAGENAMEE}}}} deletion log].\";'),('en','messages:difference-multipage','s:29:\"en:(Difference between pages)\";'),('en','messages:difference-title','s:35:\"en:$1: Difference between revisions\";'),('en','messages:difference-title-multipage','s:38:\"en:$1 and $2: Difference between pages\";'),('en','messages:directorycreateerror','s:35:\"en:Could not create directory \"$1\".\";'),('en','messages:directoryreadonlyerror','s:31:\"en:Directory \"$1\" is read-only.\";'),('en','messages:disabledspecialpage-disabled','s:57:\"en:This page has been disabled by a system administrator.\";'),('en','messages:disclaimerpage','s:29:\"en:Project:General disclaimer\";'),('