Log}}/delete|page=$3}} deletion log].\";'),('en','messages:missingarticle-diff','s:17:\"en:(Diff: $1, $2)\";'),('en','messages:missingarticle-rev','s:18:\"en:(revision#: $1)\";'),('en','messages:missingcommentheader','s:145:\"en:<strong>Reminder:</strong> You have not provided a subject for this comment.\nIf you click \"$1\" again, your edit will be published without one.\";'),('en','messages:missingcommenttext','s:26:\"en:Please enter a comment.\";'),('en','messages:missingsummary','s:134:\"en:<strong>Reminder:</strong> You have not provided an edit summary.\nIf you click \"$1\" again, your edit will be published without one.\";'),('en','messages:mobile-frontend-cookies-required','s:79:\"en:Cookies are required to switch view modes. Please enable them and try again.\";'),('en','messages:mobile-frontend-editor-edit','s:7:\"en:Edit\";'),('en','messages:mobile-frontend-editor-redlink-create','s:14:\"en:Create page\";'),('en','messages:mobile-frontend-editor-redlink-explain','s:38:\"en:This page has not yet been created.\";'),('en','messages:mobile-frontend-editor-redlink-leave','s:14:\"en:No, thanks.\";'),('en','messages:mobile-frontend-history','s:34:\"en:View edit history of this page.\";'),('en','messages:mobile-frontend-home-button','s:7:\"en:Home\";'),('en','messages:mobile-frontend-language-article-heading','s:11:\"en:Language\";'),('en','messages:mobile-frontend-languages-not-available','s:49:\"en:This page is not available in other languages.\";'),('en','messages:mobile-frontend-main-menu-button-tooltip','s:17:\"en:Open main menu\";'),('en','messages:mobile-frontend-main-menu-contributions','s:16:\"en:Contributions\";'),('en','messages:mobile-frontend-main-menu-login','s:9:\"en:Log in\";'),('en','messages:mobile-frontend-main-menu-logout','s:10:\"en:Log out\";'),('en','messages:mobile-frontend-main-menu-nearby','s:9:\"en:Nearby\";'),('en','messages:mobile-frontend-main-menu-settings','s:11:\"en:Settings\";'),('en','messages:mobile-frontend-main-menu-watchlist'