malpasswordlength','s:71:\"en:Password must be at least $1 {{PLURAL:$1|character|characters}} long\";'),('en','messages:passwordpolicies-policy-minimumpasswordlengthtologin','s:91:\"en:Password must be at least $1 {{PLURAL:$1|character|characters}} long to be able to login\";'),('en','messages:passwordpolicies-policy-passwordcannotbesubstringinusername','s:53:\"en:Password cannot be a substring within the username\";'),('en','messages:passwordpolicies-policy-passwordcannotmatchdefaults','s:61:\"en:Password cannot match a specific list of default passwords\";'),('en','messages:passwordpolicies-policy-passwordnotincommonlist','s:74:\"en:Password cannot be in the list of 100,000 most commonly used passwords.\";'),('en','messages:passwordpolicies-policyflag-forcechange','s:23:\"en:must change on login\";'),('en','messages:passwordpolicies-policyflag-suggestchangeonlogin','s:26:\"en:suggest change on login\";'),('en','messages:passwordpolicies-summary','s:94:\"en:This is a list of the effective password policies for the user groups defined in this wiki.\";'),('en','messages:passwordremindertext','s:482:\"en:Someone (from IP address $1) requested a new\npassword for {{SITENAME}} ($4). A temporary password for user\n\"$2\" has been created and was set to \"$3\". If this was your\nintent, you will need to log in and choose a new password now.\nYour temporary password will expire in {{PLURAL:$5|one day|$5 days}}.\n\nIf someone else made this request, or if you have remembered your password,\nand you no longer wish to change it, you may ignore this message and\ncontinue using your old password.\";'),('en','messages:passwordremindertitle','s:42:\"en:New temporary password for {{SITENAME}}\";'),('en','messages:passwordreset','s:17:\"en:Reset password\";'),('en','messages:passwordreset-disabled','s:51:\"en:Password resets have been disabled on this wiki.\";'),('en','messages:passwordreset-domain','s:10:\"en:Domain:\";'),('en','messages:passwordreset-email','s:17:\"en:Email address:\";'),('en','messages:passwordreset-emaildisabled','s:50:\"en:Email features have been disabled on this wiki.\";'),('en','messages:passwordreset-emailelement','s:39:\"en:Username:\n$1\n\nTemporary password:\n$2\";'),('en','messages:passwordreset-emailtext-ip','s:548:\"en:Someone (probably you, from IP address $1) requested a reset of your\npassword for {{SITENAME}} ($4). The following user {{PLURAL:$3|account is|accounts are}}\nassociated with this email address:\n\n$2\n\n{{PLURAL:$3|This temporary password|These temporary passwords}} will expire in {{PLURAL:$5|one day|$5 days}}.\nYou should log in and choose a new password now. If someone else made this\nrequest, or if you have remembered your original password, and you no longer\nwish to change it, you may ignore this message and continue using your old\npassword.\";'),('en','messages:passwordreset-emailtext-require-email','s:266:\"en:However, if you did not generate this request and want to prevent unsolicited\nemails, you may want to update your email options at\n$1.\nYou can require both username and email address to generate password reset\nemails. This may reduce the number of such incidents.\";'),('en','messages:passwordreset-emailtext-user','s:529:\"en:User $1 on {{SITENAME}} requested a reset of your password for {{SITENAME}}\n($4). The following user {{PLURAL:$3|account is|accounts are}} associated with this email address:\n\n$2\n\n{{PLURAL:$3|This temporary password|These temporary passwords}} will expire in {{PLURAL:$5|one day|$5 days}}.\nYou should log in and choose a new password now. If someone else made this\nrequest, or if you have remembered your original password, and you no longer\nwish to change it, you may ignore this message and continue using your old\npassword.\";'),('en','messages:passwordreset-emailtitle','s:34:\"en:Account details on {{SITENAME}}\";'),('en','messages:passwordreset-ignored','s:72:\"en:The password reset was not handled. Maybe no provider was configured?\";'),('en','mes