INSERT INTO `l10n_cache` VALUES ('es','messages:config-install-subscribe-possiblefail','s:315:\"es:Vuestra peticiÃģn para suscribir a mediawiki-anuncia no podrÃ­a haber pasado por. Si no recibes un email de confirmaciÃģn dentro unos cuantos minutos, va a [https://lists.wikimedia.org/postorius/lists/mediawiki-announce.lists.wikimedia.org/ lists.wikimedia.org] para probar entregando vuestra peticiÃģn otra vez.\";'),('es','messages:config-install-success','s:297:\"es:Se instalÃģ MediaWiki correctamente. Ahora puedes visitar\n<$1$2> para ver la wiki.\nSi tienes dudas, echa un vistazo a la lista de preguntas frecuentes:\n<https://www.mediawiki.org/wiki/Special:MyLanguage/Manual:FAQ>, o bien, utiliza uno de\nlos foros de asistencia que se enumeran en esa pÃĄgina.\";'),('es','messages:config-install-sysop','s:49:\"es:Creando la cuenta de usuario del administrador\";'),('es','messages:config-install-tables','s:15:\"es:Crear tablas\";'),('es','messages:config-install-tables-exist','s:106:\"es:<strong>Advertencia:</strong> al parecer, las tablas de MediaWiki ya existen. SaltÃĄndose su creaciÃģn.\";'),('es','messages:config-install-tables-failed','s:87:\"es:<strong>Error:</strong> la creaciÃģn de las tablas fallÃģ con el siguiente error: $1\";'),('es','messages:config-install-updates','s:47:\"es:Evitar ejecutar actualizaciones innecesarias\";'),('es','messages:config-install-updates-failed','s:116:\"es:<strong>Error:</strong> fallÃģ la inserciÃģn de claves de actualizaciÃģn en las tablas con el siguiente error: $1\";'),('es','messages:config-install-user','s:41:\"es:Creando el usuario de la base de datos\";'),('es','messages:config-install-user-alreadyexists','s:40:\"es:La cuenta de usuario ÂŦ$1Âŧ ya existe\";'),('es','messages:config-install-user-create-failed','s:57:\"es:FallÃģ la creaciÃģn de la cuenta de usuario ÂŦ$1Âŧ: $2\";'),('es','messages:config-install-user-grant-failed','s:69:\"es:FallÃģ la concesiÃģn de permisos a la cuenta de usuario ÂŦ$1Âŧ: $2\";'),('es','message